// Snapshot integration: compare with a snapshot from timeline
function _compareWithSnapshot(snap){
  if(!snap||!snap.textareas) return;
  const data={_format:'azuremap',textareas:snap.textareas,accountLabel:snap.accountLabel||snap.label||'snapshot',_srcName:snap.label||('Snapshot '+new Date(snap.timestamp).toLocaleString())};
  enterDiffMode(data);
}

// #endregion DIFF MODE
// #region DEPENDENCY GRAPH
// === DEPENDENCY GRAPH / BLAST RADIUS ===
let _depGraph=null;
let _blastActive=false;
function buildDependencyGraph(ctx){
  if(!ctx)return {};
  const g={};
  const addEdge=(from,to,rel,strength)=>{if(!g[from])g[from]=[];g[from].push({id:to,rel,strength})};
  // VPC -> subnets (hard)
  (ctx.vpcs||[]).forEach(v=>{
    (ctx.subnets||[]).filter(s=>s.VpcId===v.VpcId).forEach(s=>addEdge(v.VpcId,s.SubnetId,'contains','hard'));
    // VPC -> gateways
    (ctx.igws||[]).forEach(ig=>{if((ig.Attachments||[]).some(a=>a.VpcId===v.VpcId))addEdge(v.VpcId,ig.InternetGatewayId,'attached','hard')});
    (ctx.nats||[]).filter(n=>n.VpcId===v.VpcId).forEach(n=>addEdge(v.VpcId,n.NatGatewayId,'contains','hard'));
    (ctx.vpces||[]).filter(e=>e.VpcId===v.VpcId).forEach(e=>addEdge(v.VpcId,e.VpcEndpointId,'contains','soft'));
    // VPC -> route tables
    (ctx.rts||[]).filter(rt=>rt.VpcId===v.VpcId).forEach(rt=>addEdge(v.VpcId,rt.RouteTableId,'contains','config'));
    // VPC -> NACLs
    (ctx.nacls||[]).filter(n=>n.VpcId===v.VpcId).forEach(n=>addEdge(v.VpcId,n.NetworkAclId,'contains','config'));
    // VPC -> SGs
    (ctx.sgs||[]).filter(sg=>sg.VpcId===v.VpcId).forEach(sg=>addEdge(v.VpcId,sg.GroupId,'contains','config'));
  });
  // Subnet -> resources (hard)
  (ctx.subnets||[]).forEach(sub=>{
    ((ctx.instBySub||{})[sub.SubnetId]||[]).forEach(i=>addEdge(sub.SubnetId,i.InstanceId,'contains','hard'));
    ((ctx.rdsBySub||{})[sub.SubnetId]||[]).forEach(r=>addEdge(sub.SubnetId,r.DBInstanceIdentifier,'contains','hard'));
    ((ctx.ecsBySub||{})[sub.SubnetId]||[]).forEach(e=>addEdge(sub.SubnetId,e.serviceName,'contains','hard'));
    ((ctx.lambdaBySub||{})[sub.SubnetId]||[]).forEach(l=>addEdge(sub.SubnetId,l.FunctionName,'contains','hard'));
    ((ctx.albBySub||{})[sub.SubnetId]||[]).forEach(a=>addEdge(sub.SubnetId,a.LoadBalancerName,'contains','hard'));
    // Subnet -> route table association
    const rt=(ctx.subRT||{})[sub.SubnetId];
    if(rt)addEdge(sub.SubnetId,rt.RouteTableId,'associated','config');
    // Subnet -> NACL
    const nacl=(ctx.subNacl||{})[sub.SubnetId];
    if(nacl)addEdge(sub.SubnetId,nacl.NetworkAclId,'associated','config');
  });
  // EC2 -> SGs (soft)
  (ctx.instances||[]).forEach(inst=>{
    (inst.SecurityGroups||[]).forEach(sg=>addEdge(inst.InstanceId,sg.GroupId,'secured_by','soft'));
    // EC2 -> EBS volumes
    (inst.BlockDeviceMappings||[]).forEach(b=>{if(b.Ebs&&b.Ebs.VolumeId)addEdge(inst.InstanceId,b.Ebs.VolumeId,'attached','hard')});
  });
  // RDS -> SGs
  (ctx.rdsInstances||[]).forEach(db=>{
    (db.VpcSecurityGroups||[]).forEach(sg=>addEdge(db.DBInstanceIdentifier,sg.VpcSecurityGroupId,'secured_by','soft'));
  });
  // ALB -> SGs + target groups
  (ctx.albs||[]).forEach(alb=>{
    (alb.SecurityGroups||[]).forEach(gid=>addEdge(alb.LoadBalancerName,gid,'secured_by','soft'));
    const tgs=(ctx.tgByAlb||{})[alb.LoadBalancerArn]||[];
    tgs.forEach(tg=>{addEdge(alb.LoadBalancerName,tg.TargetGroupName||tg.TargetGroupArn,'targets','soft')});
  });
  // SG -> SG references (config)
  (ctx.sgs||[]).forEach(sg=>{
    [...(sg.IpPermissions||[]),...(sg.IpPermissionsEgress||[])].forEach(p=>{
      (p.UserIdGroupPairs||[]).forEach(pair=>{
        if(pair.GroupId&&pair.GroupId!==sg.GroupId)addEdge(sg.GroupId,pair.GroupId,'references','config');
      });
    });
  });
  // Route table -> gateways (config)
  (ctx.rts||[]).forEach(rt=>{
    (rt.Routes||[]).forEach(r=>{
      if(r.GatewayId&&r.GatewayId!=='local')addEdge(rt.RouteTableId,r.GatewayId,'routes_through','config');
      if(r.NatGatewayId)addEdge(rt.RouteTableId,r.NatGatewayId,'routes_through','config');
      if(r.TransitGatewayId)addEdge(rt.RouteTableId,r.TransitGatewayId,'routes_through','config');
      if(r.VpcPeeringConnectionId)addEdge(rt.RouteTableId,r.VpcPeeringConnectionId,'routes_through','config');
    });
  });
  // Peering -> VPCs (soft)
  (ctx.peerings||[]).forEach(p=>{
    if(p.RequesterVpcInfo)addEdge(p.VpcPeeringConnectionId,p.RequesterVpcInfo.VpcId,'connects','soft');
    if(p.AccepterVpcInfo)addEdge(p.VpcPeeringConnectionId,p.AccepterVpcInfo.VpcId,'connects','soft');
  });
  return g;
}
function getBlastRadius(resourceId,graph,maxDepth){
  maxDepth=maxDepth||5;
  const result={hard:[],soft:[],config:[],all:[]};
  const visited=new Set([resourceId]);
  const queue=[{id:resourceId,depth:0}];
  while(queue.length){
    const{id,depth}=queue.shift();
    if(depth>=maxDepth)continue;
    const edges=graph[id]||[];
    edges.forEach(e=>{
      if(visited.has(e.id))return;
      visited.add(e.id);
      const entry={id:e.id,rel:e.rel,strength:e.strength,depth:depth+1,parent:id};
      result[e.strength]=(result[e.strength]||[]);result[e.strength].push(entry);
      result.all.push(entry);
      queue.push({id:e.id,depth:depth+1});
    });
  }
  return result;
}
function _getResType(id){
  if(!id)return'Unknown';
  if(id.startsWith('vpc-'))return'VNet';if(id.startsWith('subnet-'))return'Subnet';
  if(id.startsWith('i-'))return'VM';if(id.startsWith('igw-'))return'Firewall';
  if(id.startsWith('nat-'))return'NAT';if(id.startsWith('vpce-'))return'VPCE';
  if(id.startsWith('sg-'))return'SG';if(id.startsWith('rtb-'))return'RT';
  if(id.startsWith('acl-'))return'Subnet NSG';if(id.startsWith('vol-'))return'Disk';
  if(id.startsWith('pcx-'))return'Peering';if(id.startsWith('tgw-'))return'TGW';
  if(id.startsWith('arn:'))return'ARN';
  if(_rlCtx){
    if((_rlCtx.sqlServers||[]).some(r=>r.DBInstanceIdentifier===id))return'SQL';
    if((_rlCtx.functionApps||[]).some(f=>f.FunctionName===id))return'FuncApp';
    if((_rlCtx.containerInstances||[]).some(e=>e.serviceName===id))return'Container';
    if((_rlCtx.appGateways||[]).some(a=>a.LoadBalancerName===id))return'ALB';
    if((_rlCtx.redisCaches||[]).some(c=>c.CacheClusterId===id))return'ElastiCache';
    if((_rlCtx.synapseWorkspaces||[]).some(c=>c.ClusterIdentifier===id))return'Redshift';
  }
  return'Resource';
}
function _getResName(id){
  if(!_rlCtx)return id;
  const v=(_rlCtx.vnets||[]).find(x=>x.VpcId===id);if(v){const t=(v.Tags||[]).find(t=>t.Key==='Name');return t?t.Value:id}
  const s=(_rlCtx.subnets||[]).find(x=>x.SubnetId===id);if(s){const t=(s.Tags||[]).find(t=>t.Key==='Name');return t?t.Value:id}
  const i=(_rlCtx.vms||[]).find(x=>x.InstanceId===id);if(i){const t=(i.Tags||[]).find(t=>t.Key==='Name');return t?t.Value:id}
  const sg=_sgById.get(id);if(sg)return sg.GroupName||id;
  return id;
}
function showDependencies(resourceId){
  if(!_rlCtx)return;
  if(!_depGraph)_depGraph=buildDependencyGraph(_rlCtx);
  const blast=getBlastRadius(resourceId,_depGraph);
  const resName=_getResName(resourceId);const resType=_getResType(resourceId);
  document.getElementById('depTitle').textContent='Dependencies: '+resType+' '+resName;
  const body=document.getElementById('depBody');
  let h='<div class="dep-summary">';
  h+='<div class="dep-stat dep-hard"><b>'+blast.hard.length+'</b><span>Hard (destroyed)</span></div>';
  h+='<div class="dep-stat dep-soft"><b>'+blast.soft.length+'</b><span>Soft (degraded)</span></div>';
  h+='<div class="dep-stat dep-config"><b>'+blast.config.length+'</b><span>Config (dangling)</span></div>';
  h+='<div class="dep-stat"><b>'+blast.all.length+'</b><span>Total affected</span></div>';
  h+='</div>';
  // Group by depth
  const byDepth={};blast.all.forEach(e=>{(byDepth[e.depth]=byDepth[e.depth]||[]).push(e)});
  h+='<div class="dep-tree">';
  h+='<div class="dep-node dep-depth-0" style="border-left-color:var(--accent-cyan);font-weight:600"><span class="dep-type">'+resType+'</span>'+_escHtml(resName)+' <span style="color:var(--text-muted);font-size:9px">'+resourceId+'</span></div>';
  Object.keys(byDepth).sort((a,b)=>a-b).forEach(d=>{
    byDepth[d].sort((a,b)=>{const o={hard:0,soft:1,config:2};return(o[a.strength]||3)-(o[b.strength]||3)}).forEach(e=>{
      const depCls=Math.min(parseInt(d),3);
      const name=_getResName(e.id);const type=_getResType(e.id);
      h+='<div class="dep-node dep-'+e.strength+' dep-depth-'+depCls+'" data-id="'+e.id+'" title="'+e.id+'"><span class="dep-type">'+type+'</span>'+_escHtml(name)+' <span class="dep-rel">'+e.rel+'</span></div>';
    });
  });
  if(!blast.all.length)h+='<div style="padding:20px;color:var(--text-muted);font-size:12px;text-align:center">No dependencies found for this resource</div>';
  h+='</div>';
  body.innerHTML=h;
  // Click to zoom
  body.querySelectorAll('.dep-node[data-id]').forEach(el=>{el.addEventListener('click',()=>{
    document.getElementById('depOverlay').classList.remove('open');
    _zoomToElement(el.dataset.id);
  })});
  document.getElementById('depOverlay').classList.add('open');
  // Store for blast highlighting
  document.getElementById('depBlastBtn').onclick=()=>{
    document.getElementById('depOverlay').classList.remove('open');
    _applyBlastRadius(resourceId,blast);
  };
}
function _applyBlastRadius(sourceId,blast){
  if(!_mapG)return;
  _blastActive=true;
  // Dim everything
  _mapG.selectAll('.vpc-group,.subnet-node,.gw-node,.lz-gw-node,.lz-tgw-node').classed('blast-dimmed',true);
  // Un-dim + glow source
  const srcEl=_mapG.node().querySelector('[data-vnet-id="'+sourceId+'"],[data-subnet-id="'+sourceId+'"],[data-gwid="'+sourceId+'"],[data-id="'+sourceId+'"]');
  if(srcEl)d3.select(srcEl).classed('blast-dimmed',false).classed('blast-glow-hard',true);
  // Highlight dependents
  blast.all.forEach(e=>{
    const el=_mapG.node().querySelector('[data-vnet-id="'+e.id+'"],[data-subnet-id="'+e.id+'"],[data-gwid="'+e.id+'"],[data-id="'+e.id+'"]');
    if(el)d3.select(el).classed('blast-dimmed',false).classed('blast-glow-'+e.strength,true);
  });
  _showToast('Blast radius active - click anywhere to clear');
}
function _clearBlastRadius(){
  if(!_blastActive||!_mapG)return;
  _blastActive=false;
  _mapG.selectAll('.blast-dimmed,.blast-glow-hard,.blast-glow-soft,.blast-glow-config').classed('blast-dimmed',false).classed('blast-glow-hard',false).classed('blast-glow-soft',false).classed('blast-glow-config',false);
}
document.getElementById('depCloseBtn').addEventListener('click',()=>document.getElementById('depOverlay').classList.remove('open'));
document.getElementById('depBlastBtn').addEventListener('click',()=>{});// overridden in showDependencies

// === HELP ===
document.getElementById('helpBtn').addEventListener('click',()=>{document.getElementById('helpOverlay').style.display='flex'});
document.getElementById('helpClose').addEventListener('click',()=>{document.getElementById('helpOverlay').style.display='none'});

// #endregion DEPENDENCY GRAPH
// #region UNIFIED DASHBOARD
// === UNIFIED DASHBOARD TAB REGISTRY ===
var _udashTab = null;
var _udashAcctFilter = 'all';

function _udashFilterByAccount(items){
  if(!_udashAcctFilter||_udashAcctFilter==='all') return items;
  var id=_udashAcctFilter;
  var lbl=typeof _rptAccountLabel==='function'?_rptAccountLabel(id):'';
  return items.filter(function(item){
    var a=item._subscriptionId||item.account||'';
    return a===id||a===lbl;
  });
}
const _UDASH_TABS = [
  {id:'classification', label:'Classification', color:'#a78bfa', icon:'', prereq:function(){
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    if(!_classificationData.length) runClassificationEngine(_rlCtx);
    return true;
  }, render:function(){ _renderClassificationTab(); }},
  {id:'appsummary', label:'App Summary', color:'#34d399', icon:'', prereq:function(){
    if(_importedReportData&&_appRegistry.length) return true;
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    if(!_classificationData.length) runClassificationEngine(_rlCtx);
    return true;
  }, render:function(){ _renderAppSummaryTab(); }},
  {id:'iam', label:'IAM Review', color:'#f472b6', icon:'', prereq:function(){
    if(_importedReportData&&_iamReviewData.length) return true;
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    if(!_iamReviewData.length){
      try{var iamRaw=safeParse(gv('in_rbac'));
      if(iamRaw){var p=parseIAMData(iamRaw);if(p)prepareIAMReviewData(p)}}catch(e){console.warn('IAM parse error in prereq:',e)}
    }
    return true;
  }, render:function(){ _renderIAMTab(); }},
  {id:'compliance', label:'Compliance', color:'#22d3ee', icon:'', prereq:function(){
    if(_importedReportData&&_complianceFindings.length) return true;
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    return true;
  }, render:function(){ _renderCompDash(); }},
  {id:'firewall', label:'Firewall', color:'#f59e0b', icon:'', prereq:function(){
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    return true;
  }, render:function(){ _renderFirewallTab(); }},
  {id:'budr', label:'BUDR', color:'#10b981', icon:'', prereq:function(){
    if(_importedReportData&&_budrAssessments.length) return true;
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    if(!_budrAssessments||!_budrAssessments.length) runBUDRChecks(_rlCtx);
    if(!_budrAssessments.length){_showToast('No resources to assess');return false}
    return true;
  }, render:function(){ _renderBUDRDash(); }},
  {id:'inventory', label:'Inventory', color:'#f97316', icon:'', prereq:function(){
    if(_importedReportData&&_inventoryData.length) return true;
    if(!_rlCtx){_showToast('Render map data first','warn');return false}
    if(!_inventoryData.length) _buildInventoryData();
    return _inventoryData.length>0;
  }, render:function(){ _renderInventoryTab(); }},
  {id:'reports', label:'Reports', color:'#6366f1', icon:'', prereq:function(){ return true; }, render:function(){ _renderReportsTab(); }}
];

function openUnifiedDash(tabId){
  var tab=_UDASH_TABS.find(function(t){return t.id===tabId});
  if(!tab) return;
  if(!tab.prereq()) return;
  var el=document.getElementById('udash');
  var wasOpen=el.classList.contains('open');
  if(wasOpen&&tabId===_udashTab) return;
  _udashTab=tabId;
  // Clean shared areas (prevents stale layout classes, hidden toolbars, wrong footers)
  document.getElementById('udashToolbar').textContent='';
  document.getElementById('udashBody').textContent='';
  document.getElementById('udashBody').className='udash-body';
  document.getElementById('udashFooter').textContent='';
  document.getElementById('udashToolbar').style.display='';
  _govToolbarTab=null;
  _compToolbarTab=null;
  _invToolbarRendered=false;
  el.classList.add('open');
  if(!wasOpen) el.offsetHeight; // force reflow only on first open
  _renderUdashTabs();
  tab.render();
}

function _switchUdashTab(tabId){
  if(tabId===_udashTab) return;
  var tab=_UDASH_TABS.find(function(t){return t.id===tabId});
  if(!tab||!tab.prereq()) return;
  _udashTab=tabId;
  _renderUdashTabs();
  invalidateParseCache();
  // Close firewall full panel if open
  document.getElementById('fwFullPanel').classList.remove('open');
  // Clear shared areas
  document.getElementById('udashBody').onclick=null;
  document.getElementById('udashToolbar').textContent='';
  document.getElementById('udashBody').textContent='';
  document.getElementById('udashBody').className='udash-body';
  document.getElementById('udashFooter').textContent='';
  document.getElementById('udashToolbar').style.display='';
  // Reset toolbar tab guards
  _govToolbarTab=null;
  _compToolbarTab=null;
  _invToolbarRendered=false;
  tab.render();
}

function _renderUdashTabs(){
  var c=document.getElementById('udashTabs');
  c.textContent='';
  _UDASH_TABS.forEach(function(t){
    var btn=document.createElement('button');
    btn.className='udash-tab'+(t.id===_udashTab?' active':'');
    btn.style.setProperty('--tab-color',t.color);
    btn.textContent=t.label;
    btn.addEventListener('click',function(){_switchUdashTab(t.id)});
    c.appendChild(btn);
  });
  // Account filter bar
  var bar=document.getElementById('udashAcctBar');
  var accts=typeof _rptUniqueAccounts==='function'?_rptUniqueAccounts():[];
  if(accts.length<2){bar.style.display='none';_udashAcctFilter='all';return}
  bar.style.display='flex';
  bar.textContent='';
  // "All" button
  var allBtn=document.createElement('button');
  allBtn.className='udash-acct-btn'+(_udashAcctFilter==='all'?' active':'');
  allBtn.textContent='All';
  allBtn.addEventListener('click',function(){
    if(_udashAcctFilter==='all') return;
    _udashAcctFilter='all';_renderUdashTabs();_refreshCurrentTab();
  });
  bar.appendChild(allBtn);
  // Per-account buttons
  accts.forEach(function(a){
    var btn=document.createElement('button');
    var color=typeof getAccountColor==='function'?getAccountColor(a.id):'';
    btn.className='udash-acct-btn'+(_udashAcctFilter===a.id?' active':'');
    if(color){
      btn.style.setProperty('--acct-bg',color+'22');
      btn.style.setProperty('--acct-fg',color);
    }
    var dot=document.createElement('span');
    dot.className='acct-dot';
    dot.style.background=color||'var(--text-muted)';
    btn.appendChild(dot);
    btn.appendChild(document.createTextNode(a.label||a.id));
    btn.addEventListener('click',function(){
      _udashAcctFilter=_udashAcctFilter===a.id?'all':a.id;
      _renderUdashTabs();_refreshCurrentTab();
    });
    bar.appendChild(btn);
  });
}

function _refreshCurrentTab(){
  var tab=_UDASH_TABS.find(function(t){return t.id===_udashTab});
  if(!tab) return;
  document.getElementById('udashToolbar').textContent='';
  document.getElementById('udashBody').textContent='';
  document.getElementById('udashBody').className='udash-body';
  document.getElementById('udashFooter').textContent='';
  _govToolbarTab=null;_compToolbarTab=null;_invToolbarRendered=false;if(_compDashState)_compDashState._cachedView=null;
  tab.render();
}

function closeUnifiedDash(){
  document.getElementById('udash').classList.remove('open');
  document.getElementById('fwFullPanel').classList.remove('open');
  _udashTab=null;
  _udashAcctFilter='all';
  invalidateParseCache();
}

document.getElementById('udashClose').addEventListener('click',closeUnifiedDash);

// === COMPLIANCE DASHBOARD CONTROLS ===
// (Toolbar event listeners are now attached dynamically inside _renderCompDash)

// === BUDR DASHBOARD ===
let _budrDashState={tierFilter:'all',search:'',sort:'tier'};
const _BUDR_TIER_META={
  protected:{name:'Protected',color:'#10b981',icon:''},
  partial:{name:'Partially Protected',color:'#f59e0b',icon:''},
  at_risk:{name:'At Risk',color:'#ef4444',icon:''}
};
function openBUDRDash(){
  _budrDashState={tierFilter:'all',search:'',sort:'tier'};
  openUnifiedDash('budr');
}
function _renderBUDRDash(){
  var tb=document.getElementById('udashToolbar');
  var body=document.getElementById('udashBody');
  var footer=document.getElementById('udashFooter');
  var st=_budrDashState;
  var _budrFiltered=_udashFilterByAccount(_budrAssessments);
  var counts={protected:0,partial:0,at_risk:0};
  _budrFiltered.forEach(function(a){if(a.profile)counts[a.profile.tier]=(counts[a.profile.tier]||0)+1});
  var total=_budrFiltered.length;
  // Toolbar: search + sort + tier pills
  var th='<input id="budrSearch" type="text" placeholder="Filter by name, ID, type..." value="'+_escHtml(st.search)+'" style="background:var(--bg-tertiary);border:1px solid var(--border);color:var(--text-primary);padding:4px 10px;border-radius:4px;font-size:11px;font-family:Segoe UI,system-ui,sans-serif;width:200px">';
  th+='<select id="budrSort" style="background:var(--bg-tertiary);border:1px solid var(--border);color:var(--text-secondary);padding:4px 8px;border-radius:4px;font-size:10px;font-family:Segoe UI,system-ui,sans-serif">';
  th+='<option value="tier"'+(st.sort==='tier'?' selected':'')+'>Sort: Tier</option>';
  th+='<option value="compliance"'+(st.sort==='compliance'?' selected':'')+'>Sort: Compliance</option>';
  th+='<option value="name"'+(st.sort==='name'?' selected':'')+'>Sort: Name</option>';
  th+='<option value="type"'+(st.sort==='type'?' selected':'')+'>Sort: Type</option>';
  th+='</select>';
  th+='<div id="budrPills" style="display:flex;gap:4px;margin-left:8px"></div>';
  tb.innerHTML=th;
  // Build tier pills
  var pillBox=document.getElementById('budrPills');
  [{tier:'all',label:'All ('+total+')'},{tier:'protected',label:'Protected ('+counts.protected+')'},{tier:'partial',label:'Partial ('+counts.partial+')'},{tier:'at_risk',label:'At Risk ('+counts.at_risk+')'}].forEach(function(p){
    var btn=document.createElement('span');btn.className='budr-pill'+(st.tierFilter===p.tier?' active':'');
    btn.dataset.tier=p.tier;btn.textContent=p.label;
    btn.addEventListener('click',function(){st.tierFilter=p.tier;_renderBUDRDash()});pillBox.appendChild(btn);
  });
  // Wire toolbar listeners
  document.getElementById('budrSearch').addEventListener('input',function(){st.search=this.value;_renderBUDRDash()});
  document.getElementById('budrSort').addEventListener('change',function(){st.sort=this.value;_renderBUDRDash()});
  // Filter assessments (account filter first)
  var items=_udashFilterByAccount(_budrAssessments).slice();
  if(st.tierFilter!=='all')items=items.filter(function(a){return a.profile&&a.profile.tier===st.tierFilter});
  if(st.search){var q=st.search.toLowerCase();items=items.filter(function(a){return(a.name||'').toLowerCase().includes(q)||(a.id||'').toLowerCase().includes(q)||(a.type||'').toLowerCase().includes(q)})}
  if(st.sort==='name')items.sort(function(a,b){return(a.name||a.id||'').localeCompare(b.name||b.id||'')});
  else if(st.sort==='type')items.sort(function(a,b){return(a.type||'').localeCompare(b.type||'')});
  else if(st.sort==='compliance'){var co={fail:0,warn:1,pass:2,unknown:3};items.sort(function(a,b){var sa=a.compliance?co[a.compliance.status]:3;var sb=b.compliance?co[b.compliance.status]:3;return sa-sb})}
  // Summary cards
  var compCounts={pass:0,warn:0,fail:0,unknown:0};
  _budrFiltered.forEach(function(a){var s=a.compliance?a.compliance.status:'unknown';compCounts[s]=(compCounts[s]||0)+1});
  var h='<div class="budr-summary">';
  ['protected','partial','at_risk'].forEach(function(tier){
    var meta=_BUDR_TIER_META[tier];var c=counts[tier]||0;
    var pct=total>0?Math.round(c/total*100):0;
    h+='<div class="budr-card '+tier+'" data-tier="'+tier+'">';
    h+='<div class="bc-count">'+c+'</div>';
    h+='<div class="bc-label">'+esc(meta.name)+'</div>';
    h+='<div class="bc-rto">'+pct+'% of resources</div>';
    h+='</div>';
  });
  h+='</div>';
  // Tier compliance summary bar
  if(compCounts.fail||compCounts.warn){
    h+='<div style="display:flex;gap:8px;padding:6px 12px;margin:0 0 8px;background:var(--bg-tertiary);border-radius:6px;font-family:Segoe UI,system-ui,sans-serif;font-size:10px;align-items:center">';
    h+='<span style="color:var(--text-muted);font-weight:600">Tier Compliance:</span>';
    if(compCounts.pass)h+='<span style="color:#22c55e">'+compCounts.pass+' meet target</span>';
    if(compCounts.warn)h+='<span style="color:#f59e0b">'+compCounts.warn+' warnings</span>';
    if(compCounts.fail)h+='<span style="color:#ef4444">'+compCounts.fail+' gaps</span>';
    h+='</div>';
  }
  // Strategy legend
  h+=_rptBUDRStrategyLegend();
  // Group by tier
  var groups={protected:[],partial:[],at_risk:[]};
  items.forEach(function(a){if(a.profile)groups[a.profile.tier].push(a)});
  // Render sections
  ['at_risk','partial','protected'].forEach(function(tier){
    var grp=groups[tier];if(!grp.length)return;
    var meta=_BUDR_TIER_META[tier];
    var collapsed=tier==='protected';
    h+='<div class="budr-section" data-tier="'+tier+'">';
    h+='<div class="budr-section-hdr'+(collapsed?' collapsed':'')+'">';
    h+='<span class="bs-chevron">\u25BC</span>';
    h+='<h3 style="color:'+meta.color+'">'+meta.icon+' '+esc(meta.name)+'</h3>';
    h+='<span class="bs-count">'+grp.length+' resource'+(grp.length!==1?'s':'')+'</span>';
    h+='</div>';
    h+='<div class="budr-section-body"'+(collapsed?' style="display:none"':'')+'>';
    grp.forEach(function(a,i){
      var findings=_budrFindings.filter(function(f){return f.resource===a.id});
      var expanded=tier==='at_risk';
      h+='<div class="budr-res'+(expanded?' expanded':'')+'" data-idx="'+tier+'-'+i+'">';
      h+='<div class="budr-res-hdr">';
      h+='<span class="br-dot '+tier+'"></span>';
      h+='<span class="br-type">'+esc(a.type)+'</span>';
      h+='<span class="br-name">'+esc(a.name)+'</span>';
      if(a._subscriptionId)h+=_acctPill(a._subscriptionId);
      // Classification tier badge + compliance indicator
      var ct=a.classTier||'low';var cc=a.compliance||{status:'unknown'};
      var tierColors={critical:'#ef4444',high:'#f59e0b',medium:'#22d3ee',low:'#64748b'};
      var compIcon=cc.status==='pass'?'✓':cc.status==='warn'?'⚠':cc.status==='fail'?'✗':'?';
      var compColor=cc.status==='pass'?'#22c55e':cc.status==='warn'?'#f59e0b':cc.status==='fail'?'#ef4444':'#64748b';
      h+='<span style="font-size:9px;padding:1px 5px;border-radius:3px;background:'+tierColors[ct]+'22;color:'+tierColors[ct]+';border:1px solid '+tierColors[ct]+'44;margin-left:auto">'+ct.toUpperCase()+'</span>';
      h+='<span style="font-size:9px;color:'+compColor+';margin-left:4px" title="'+esc(cc.issues?cc.issues.map(function(i){return i.msg}).join('; '):'')+'">'+compIcon+'</span>';
      h+='<span class="br-rto" style="margin-left:6px">RTO: '+esc(a.profile.rto)+' | RPO: '+esc(a.profile.rpo)+'</span>';
      if(a.overridden)h+='<span style="font-size:8px;padding:1px 4px;border-radius:3px;background:rgba(99,102,241,.15);color:#818cf8;margin-left:4px;font-weight:600">✎ OVERRIDE</span>';
      h+='<button class="budr-cfg-btn" data-rid="'+esc(a.id)+'" title="Configure strategy override" style="margin-left:4px;background:none;border:1px solid var(--border);border-radius:4px;cursor:pointer;padding:2px 7px;font-size:15px;color:var(--text-muted);line-height:1">⚙</button>';
      h+='</div>';
      h+='<div class="budr-res-body">';
      // Override form (hidden by default)
      var ov=_budrOverrides[a.id]||{};
      h+='<div class="budr-override-form" data-rid="'+esc(a.id)+'" style="display:none;margin-bottom:8px;padding:8px 10px;background:rgba(99,102,241,.06);border:1px solid rgba(99,102,241,.2);border-radius:5px;font-size:11px;font-family:Segoe UI,system-ui,sans-serif">';
      h+='<div style="color:#818cf8;font-weight:600;margin-bottom:6px">Strategy Override</div>';
      h+='<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">';
      h+='<label style="color:var(--text-secondary)">DR Strategy</label>';
      h+='<select class="budr-ov-strategy" style="font-size:11px;padding:2px 4px;border-radius:3px;border:1px solid var(--border);background:var(--bg-secondary);color:var(--text-primary)">';
      var _stratToClass={hot:'critical',warm:'high',pilot:'medium',cold:'low'};
      [{k:'critical',label:'Critical (Hot)'},{k:'high',label:'High (Warm)'},{k:'medium',label:'Medium (Pilot Light)'},{k:'low',label:'Low (Cold)'}].forEach(function(s){
        var cur=ov.strategy||_stratToClass[a.profile.strategy]||'low';
        var sel=cur===s.k?' selected':'';
        h+='<option value="'+s.k+'"'+sel+'>'+s.label+'</option>';
      });
      h+='</select>';
      h+='<label style="color:var(--text-secondary);margin-left:8px">RTO</label>';
      h+='<input class="budr-ov-rto" type="text" value="'+esc(ov.rto||a.profile.rto)+'" style="width:70px;font-size:11px;padding:2px 4px;border-radius:3px;border:1px solid var(--border);background:var(--bg-secondary);color:var(--text-primary)" placeholder="'+esc(a.autoProfile?a.autoProfile.rto:a.profile.rto)+'">';
      h+='<label style="color:var(--text-secondary);margin-left:8px">RPO</label>';
      h+='<input class="budr-ov-rpo" type="text" value="'+esc(ov.rpo||a.profile.rpo)+'" style="width:70px;font-size:11px;padding:2px 4px;border-radius:3px;border:1px solid var(--border);background:var(--bg-secondary);color:var(--text-primary)" placeholder="'+esc(a.autoProfile?a.autoProfile.rpo:a.profile.rpo)+'">';
      h+='</div>';
      h+='<div style="margin-top:6px;display:flex;gap:6px">';
      h+='<button class="budr-ov-save" data-rid="'+esc(a.id)+'" style="font-size:10px;padding:3px 10px;border-radius:3px;border:none;background:#6366f1;color:#fff;cursor:pointer;font-weight:600">Save</button>';
      if(a.overridden)h+='<button class="budr-ov-reset" data-rid="'+esc(a.id)+'" style="font-size:10px;padding:3px 10px;border-radius:3px;border:1px solid var(--border);background:var(--bg-secondary);color:var(--text-secondary);cursor:pointer">Reset to Auto</button>';
      h+='</div>';
      h+='</div>';
      // RTO/RPO justification
      var estM=_BUDR_EST_MINUTES[a.profileKey]||{};
      if(estM.rtoWhy||estM.rpoWhy){
        h+='<div style="margin-bottom:6px;padding:4px 8px;background:rgba(99,102,241,.06);border:1px solid rgba(99,102,241,.15);border-radius:4px;font-size:10px;font-family:Segoe UI,system-ui,sans-serif">';
        h+='<div style="color:#818cf8;font-weight:600;margin-bottom:2px">Est. RTO/RPO Justification</div>';
        if(estM.rtoWhy)h+='<div style="color:var(--text-secondary)"><b>RTO '+esc(a.profile.rto)+'</b> — '+esc(estM.rtoWhy)+'</div>';
        if(estM.rpoWhy)h+='<div style="color:var(--text-secondary)"><b>RPO '+esc(a.profile.rpo)+'</b> — '+esc(estM.rpoWhy)+'</div>';
        h+='</div>';
      }
      // Tier compliance details
      if(cc.issues&&cc.issues.length){
        h+='<div style="margin-bottom:6px;padding:4px 8px;background:rgba(239,68,68,.08);border:1px solid rgba(239,68,68,.2);border-radius:4px;font-size:10px;font-family:Segoe UI,system-ui,sans-serif">';
        h+='<div style="color:#ef4444;font-weight:600;margin-bottom:2px">Tier Compliance Gap — '+ct.toUpperCase()+' tier</div>';
        cc.issues.forEach(function(issue){
          h+='<div style="color:var(--text-secondary)">'+esc(issue.msg)+'</div>';
        });
        var target=_TIER_TARGETS[ct];
        if(target)h+='<div style="color:var(--text-muted);margin-top:2px">Target: RTO ≤ '+target.rtoLabel+' | RPO ≤ '+target.rpoLabel+'</div>';
        h+='</div>';
      }
      // Signals
      if(a.signals){
        h+='<div class="budr-signals">';
        Object.entries(a.signals).forEach(function(entry){
          var k=entry[0],v=entry[1];
          var good=v===true||(typeof v==='number'&&v>1);
          var bad=v===false||v===0;
          var cls=good?'good':bad?'bad':'warn';
          var icon=good?'✓':bad?'✗':'!';
          h+='<span class="budr-sig-badge '+cls+'">'+icon+' '+esc(k)+': '+esc(String(v))+'</span>';
        });
        h+='</div>';
      }
      // Findings for this resource
      if(findings.length){
        h+='<div class="budr-findings">';
        findings.forEach(function(f){
          h+='<div class="budr-finding">';
          h+='<span class="bf-sev '+f.severity+'">'+f.severity+'</span>';
          h+='<span class="bf-msg">'+esc(f.message)+'</span>';
          h+='</div>';
          if(f.remediation)h+='<div class="budr-finding"><span class="bf-sev" style="visibility:hidden">.</span><span class="bf-fix">\u21B3 '+esc(f.remediation)+'</span></div>';
        });
        h+='</div>';
      }
      h+='</div></div>';
    });
    h+='</div></div>';
  });
  if(!items.length)h+='<div style="padding:40px;text-align:center;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif">No resources match current filter</div>';
  body.innerHTML=h;
  body.scrollTop=0;
  // Event: section collapse
  body.querySelectorAll('.budr-section-hdr').forEach(function(hdr){
    hdr.addEventListener('click',function(){
      var bd=hdr.nextElementSibling;
      if(hdr.classList.contains('collapsed')){hdr.classList.remove('collapsed');bd.style.display=''}
      else{hdr.classList.add('collapsed');bd.style.display='none'}
    });
  });
  // Event: resource card expand
  body.querySelectorAll('.budr-res-hdr').forEach(function(hdr){
    hdr.addEventListener('click',function(e){
      if(e.target.closest('.budr-cfg-btn'))return; // don't toggle when clicking gear
      hdr.closest('.budr-res').classList.toggle('expanded');
    });
  });
  // Event: gear button toggles override form
  body.querySelectorAll('.budr-cfg-btn').forEach(function(btn){
    btn.addEventListener('click',function(e){
      e.stopPropagation();
      var rid=btn.dataset.rid;
      var form=body.querySelector('.budr-override-form[data-rid="'+rid+'"]');
      if(form)form.style.display=form.style.display==='none'?'':'none';
      // Expand card if not already
      var card=btn.closest('.budr-res');
      if(card&&!card.classList.contains('expanded'))card.classList.add('expanded');
    });
  });
  // Event: save override
  body.querySelectorAll('.budr-ov-save').forEach(function(btn){
    btn.addEventListener('click',function(e){
      e.stopPropagation();
      var rid=btn.dataset.rid;
      var form=btn.closest('.budr-override-form');
      var strategy=form.querySelector('.budr-ov-strategy').value;
      var rto=form.querySelector('.budr-ov-rto').value.trim();
      var rpo=form.querySelector('.budr-ov-rpo').value.trim();
      _budrOverrides[rid]={strategy:strategy,rto:rto||undefined,rpo:rpo||undefined};
      // Re-run enrichment to apply override
      _reapplyBUDROverrides();
      _renderBUDRDash();
      _showToast('Override saved for '+rid);
    });
  });
  // Event: reset override
  body.querySelectorAll('.budr-ov-reset').forEach(function(btn){
    btn.addEventListener('click',function(e){
      e.stopPropagation();
      var rid=btn.dataset.rid;
      delete _budrOverrides[rid];
      _reapplyBUDROverrides();
      _renderBUDRDash();
      _showToast('Override removed for '+rid);
    });
  });
  // Event: summary card click = filter
  body.querySelectorAll('.budr-card').forEach(function(card){
    card.addEventListener('click',function(){
      var t=card.dataset.tier;
      st.tierFilter=st.tierFilter===t?'all':t;
      _renderBUDRDash();
    });
  });
  // Footer: item count + export buttons
  var fh='<button id="budrExportCSV">Export CSV</button>';
  fh+='<button id="budrExportJSON">Export JSON</button>';
  if(_isElectron) fh+='<button id="budrExportXLSX">Export XLSX</button>';
  fh+='<span style="margin-left:auto;font-size:10px;color:var(--text-muted)">'+items.length+' of '+total+' resources</span>';
  footer.innerHTML=fh;
  // Wire export listeners
  document.getElementById('budrExportCSV').addEventListener('click',function(){
    if(!_budrAssessments.length){_showToast('No BUDR data');return}
    var csv='Type,Resource,Name,Tier,Strategy,RTO,RPO,Override,Signals\n';
    _budrAssessments.forEach(function(a){
      var tier=a.profile?a.profile.tier:'unknown';
      var strategy=a.profile?(_BUDR_STRATEGY[a.profile.strategy]||a.profile.strategy):'';
      var rto=a.profile?a.profile.rto:'';
      var rpo=a.profile?a.profile.rpo:'';
      var sigs=a.signals?Object.entries(a.signals).map(function(e){return e[0]+'='+e[1]}).join('; '):'';
      var ce=function(s){return String(s||'').replace(/"/g,'""')};
      csv+='"'+ce(a.type)+'","'+ce(a.id)+'","'+ce(a.name)+'","'+ce(tier)+'","'+ce(strategy)+'","'+ce(rto)+'","'+ce(rpo)+'","'+(a.overridden?'Yes':'No')+'","'+ce(sigs)+'"\n';
    });
    downloadBlob(new Blob([csv],{type:'text/csv'}),'budr-assessment.csv');
  });
  document.getElementById('budrExportJSON').addEventListener('click',function(){
    if(!_budrAssessments.length){_showToast('No BUDR data');return}
    var data={timestamp:new Date().toISOString(),summary:_getBUDRTierCounts(),assessments:_budrAssessments,findings:_budrFindings,overrides:_budrOverrides};
    downloadBlob(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}),'budr-assessment.json');
  });
  var xlsxBtn=document.getElementById('budrExportXLSX');
  if(xlsxBtn) xlsxBtn.addEventListener('click',async function(){
    if(!_budrAssessments.length){_showToast('No BUDR data');return}
    var data={timestamp:new Date().toISOString(),summary:_getBUDRTierCounts(),assessments:_budrAssessments,findings:_budrFindings,overrides:_budrOverrides};
    var jsonStr=JSON.stringify(data,null,2);
    _showToast('Generating XLSX report\u2026');
    try{
      var result=await window.electronAPI.exportBUDRXlsx(jsonStr);
      if(!result){_showToast('Export cancelled');return}
      if(result.error){_showToast('Error: '+result.error,'error');return}
      _showToast('Saved: '+result.path);
    }catch(e){_showToast('XLSX export failed: '+e.message,'error')}
  });
}
// BUDR button
document.getElementById('budrBtn').addEventListener('click',openBUDRDash);
// Inventory button
document.getElementById('inventoryBtn').addEventListener('click',function(){openUnifiedDash('inventory')});

// === GOVERNANCE DASHBOARD ===
function _closeAllDashboardsExcept(keep){_closeAllDashboards(keep)}

function openGovernanceDashboard(tab){
  if(tab==='iam') openUnifiedDash('iam');
  else openUnifiedDash('classification');
}

var _govToolbarTab=null;
var _compToolbarTab=null;

function _renderClassificationTab(){
  var tb=document.getElementById('udashToolbar');
  var body=document.getElementById('udashBody');
  var footer=document.getElementById('udashFooter');
  var st=_govDashState;
  // Toolbar — only rebuild on tab switch
  if(_govToolbarTab!=='classification'){
    _govToolbarTab='classification';
    var th='<label>Search</label>';
    th+='<input id="govSearch" type="text" placeholder="Filter by name, type, VPC..." value="'+_escHtml(st.search)+'">';
    th+='<label>Tier</label>';
    th+='<select id="govFilter">';
    ['all','critical','high','medium','low'].forEach(function(v){th+='<option value="'+v+'"'+(st.filter===v?' selected':'')+'>'+v.charAt(0).toUpperCase()+v.slice(1)+'</option>'});
    th+='</select>';
    th+='<label>Per page</label>';
    th+='<select id="govPerPage">';
    [25,50,100,0].forEach(function(v){th+='<option value="'+v+'"'+(st.perPage===v?' selected':'')+'>'+(v||'All')+'</option>'});
    th+='</select>';
    th+='<button id="govRulesBtn" style="margin-left:auto;background:rgba(139,92,246,.1);border:1px solid #8b5cf6;color:#8b5cf6;padding:4px 12px;border-radius:4px;font-size:10px;font-family:Segoe UI,system-ui,sans-serif;cursor:pointer">Configure Rules</button>';
    tb.innerHTML=th;
    document.getElementById('govSearch').addEventListener('input',function(){st.search=this.value;st.page=1;_renderClassificationTab()});
    document.getElementById('govFilter').addEventListener('change',function(){st.filter=this.value;st.page=1;_renderClassificationTab()});
    document.getElementById('govPerPage').addEventListener('change',function(){st.perPage=parseInt(this.value)||0;st.page=1;_renderClassificationTab()});
    document.getElementById('govRulesBtn').addEventListener('click',_openRulesEditor);
  }
  // Summary cards (account-filtered)
  var _clasFiltered=_udashFilterByAccount(_classificationData);
  var counts={critical:0,high:0,medium:0,low:0};
  _clasFiltered.forEach(function(r){counts[r.tier]=(counts[r.tier]||0)+1});
  var bh='<div class="gov-tier-cards">';
  [{t:'critical',l:'Critical'},{t:'high',l:'High'},{t:'medium',l:'Medium'},{t:'low',l:'Low'}].forEach(function(d){
    var meta=_TIER_RPO_RTO[d.t];
    bh+='<div class="gov-tier-card" data-gov-tier="'+d.t+'" style="border-color:'+meta.color+'">';
    bh+='<h3 style="color:'+meta.color+'">'+d.l+'</h3>';
    bh+='<div class="gov-tier-count" style="color:'+meta.color+'">'+(counts[d.t]||0)+'</div>';
    bh+='<div class="gov-tier-meta">RPO: '+meta.rpo+' · RTO: '+meta.rto+'</div>';
    bh+='</div>';
  });
  bh+='</div>';
  // Build resource→app lookup from registry
  var _resAppMap={};
  _appRegistry.forEach(function(app){
    if(!app.pattern) return;
    var re=_safeRegex(app.pattern);if(!re) return;
    _clasFiltered.forEach(function(r){
      if(_resAppMap[r.id]) return;
      var text=(r.name||'')+' '+(r.type||'')+' '+(r.vpcName||'')+' '+Object.values(r.tags||{}).join(' ');
      if(re.test(text)) _resAppMap[r.id]=app.name;
    });
  });
  // Filter + sort
  var items=_clasFiltered.slice();
  if(st.filter!=='all') items=items.filter(function(r){return r.tier===st.filter});
  if(st.search){var q=st.search.toLowerCase();items=items.filter(function(r){return(r.name||'').toLowerCase().indexOf(q)!==-1||(r.type||'').toLowerCase().indexOf(q)!==-1||(r.id||'').toLowerCase().indexOf(q)!==-1||(r.vpcName||'').toLowerCase().indexOf(q)!==-1||(_resAppMap[r.id]||'').toLowerCase().indexOf(q)!==-1})}
  var sortKey=st.sort;var dir=st.sortDir==='asc'?1:-1;
  items.sort(function(a,b){
    if(sortKey==='tier') return((_TIER_RPO_RTO[a.tier]||{priority:99}).priority-(_TIER_RPO_RTO[b.tier]||{priority:99}).priority)*dir;
    if(sortKey==='app'){var av=(_resAppMap[a.id]||'').toLowerCase();var bv=(_resAppMap[b.id]||'').toLowerCase();return av<bv?-dir:av>bv?dir:0}
    var av=(a[sortKey]||'').toLowerCase();var bv=(b[sortKey]||'').toLowerCase();
    return av<bv?-dir:av>bv?dir:0;
  });
  // Paginate
  var perPage=st.perPage<=0?items.length:st.perPage;
  var totalPages=Math.max(1,Math.ceil(items.length/perPage));
  st.page=Math.min(Math.max(1,st.page),totalPages);
  var start=(st.page-1)*perPage;
  var pageItems=items.slice(start,start+perPage);
  // Table
  var hasMultiAcct=items.some(function(r){return!!r._subscriptionId})&&new Set(items.map(function(r){return r._subscriptionId}).filter(Boolean)).size>1;
  var cols=[{key:'name',label:'Resource'},{key:'type',label:'Type'}];
  if(hasMultiAcct) cols.push({key:'_subscriptionId',label:'Account'});
  cols.push({key:'app',label:'App'},{key:'tier',label:'Tier'},{key:'rpo',label:'RPO',nosort:true},{key:'rto',label:'RTO',nosort:true},{key:'vpcName',label:'VPC'},{key:'auto',label:'Source',nosort:true},{key:'actions',label:'',nosort:true});
  bh+='<table class="gov-table"><thead><tr>';
  cols.forEach(function(c){
    var cls='';if(!c.nosort&&st.sort===c.key) cls=st.sortDir==='asc'?' sort-asc':' sort-desc';
    bh+='<th'+(c.nosort?'':' data-sort-col="'+c.key+'"')+' class="'+cls+'">'+c.label+'</th>';
  });
  bh+='</tr></thead><tbody>';
  if(!pageItems.length) bh+='<tr><td colspan="'+cols.length+'" style="text-align:center;padding:30px;color:var(--text-muted)">No resources match filters</td></tr>';
  pageItems.forEach(function(r){
    bh+='<tr>';
    bh+='<td><span class="gov-res-link" data-rid="'+_escHtml(r.id)+'" style="color:var(--accent-cyan);cursor:pointer">'+_escHtml(r.name)+'</span></td>';
    bh+='<td>'+_escHtml(r.type)+'</td>';
    if(hasMultiAcct) bh+='<td>'+_acctPill(r._subscriptionId)+'</td>';
    var appName=_resAppMap[r.id]||'';
    bh+='<td style="font-size:10px">'+(appName?'<span style="background:rgba(52,211,153,.12);color:#34d399;padding:1px 6px;border-radius:3px;font-size:9px">'+_escHtml(appName)+'</span>':'<span style="color:var(--text-muted)">—</span>')+'</td>';
    bh+='<td><span class="gov-tier-badge '+r.tier+'">'+r.tier+'</span></td>';
    bh+='<td>'+_escHtml(r.rpo)+'</td>';
    bh+='<td>'+_escHtml(r.rto)+'</td>';
    bh+='<td style="font-size:10px;color:var(--text-muted)">'+_escHtml(r.vpcName||'—')+'</td>';
    bh+='<td style="font-size:9px;color:var(--text-muted)">'+(r.auto?'Auto':'<span style="color:#8b5cf6">Manual</span>')+'</td>';
    bh+='<td><select class="gov-override-select" data-res-id="'+_escHtml(r.id)+'">';
    ['critical','high','medium','low'].forEach(function(t){bh+='<option value="'+t+'"'+(r.tier===t?' selected':'')+'>'+t+'</option>'});
    bh+='</select></td>';
    bh+='</tr>';
  });
  bh+='</tbody></table>';
  body.innerHTML=bh;
  body.scrollTop=0;
  // Footer
  var fh='<button id="govExportCSV">Export CSV</button>';
  fh+='<button id="govExportJSON">Export JSON</button>';
  fh+='<span style="margin-left:auto;font-size:10px;color:var(--text-muted)">'+items.length+' of '+_classificationData.length+'</span>';
  if(totalPages>1){
    fh+='<button id="govPrev"'+(st.page<=1?' disabled':'')+'>← Prev</button>';
    fh+='<span style="font-size:10px;color:var(--text-muted)">Page '+st.page+' of '+totalPages+'</span>';
    fh+='<button id="govNext"'+(st.page>=totalPages?' disabled':'')+'>Next →</button>';
  }
  footer.innerHTML=fh;
  // Wire body/footer events (these get recreated each render)
  if(document.getElementById('govPrev')) document.getElementById('govPrev').addEventListener('click',function(){st.page--;_renderClassificationTab()});
  if(document.getElementById('govNext')) document.getElementById('govNext').addEventListener('click',function(){st.page++;_renderClassificationTab()});
  // Sort headers
  body.querySelectorAll('th[data-sort-col]').forEach(function(th){
    th.addEventListener('click',function(){
      var col=this.dataset.sortCol;
      if(st.sort===col) st.sortDir=st.sortDir==='asc'?'desc':'asc';
      else{st.sort=col;st.sortDir='asc'}
      st.page=1;_renderClassificationTab();
    });
  });
  // Tier card clicks
  body.querySelectorAll('.gov-tier-card[data-gov-tier]').forEach(function(card){
    card.addEventListener('click',function(){
      var tier=this.dataset.govTier;
      st.filter=st.filter===tier?'all':tier;
      document.getElementById('govFilter').value=st.filter;
      st.page=1;_renderClassificationTab();
    });
  });
  // Override selects
  body.querySelectorAll('.gov-override-select').forEach(function(sel){
    sel.addEventListener('change',function(){
      var resId=this.dataset.resId;var newTier=this.value;
      _classificationOverrides[resId]=newTier;
      var item=_classificationData.find(function(r){return r.id===resId});
      if(item){item.tier=newTier;item.rpo=_TIER_RPO_RTO[newTier].rpo;item.rto=_TIER_RPO_RTO[newTier].rto;item.auto=false}
      _renderClassificationTab();
    });
  });
  // Resource name clicks → jump to resource on map and open detail panel
  body.querySelectorAll('.gov-res-link').forEach(function(el){el.addEventListener('click',function(e){
    e.stopPropagation();var rid=this.dataset.rid;if(!rid)return;
    closeUnifiedDash();
    setTimeout(function(){_zoomAndShowDetail(rid)},250);
  })});
  // Export
  document.getElementById('govExportCSV').addEventListener('click',function(){
    var rows=[['Resource','Type','App','Tier','RPO','RTO','Classification','VPC']];
    items.forEach(function(r){rows.push([r.name,r.type,_resAppMap[r.id]||'',r.tier,r.rpo,r.rto,r.auto?'Auto':'Manual',r.vpcName||''])});
    var csv=rows.map(function(r){return r.map(function(c){return '"'+String(c).replace(/"/g,'""')+'"'}).join(',')}).join('\n');
    downloadBlob(new Blob([csv],{type:'text/csv'}),'asset-classification.csv');
  });
  document.getElementById('govExportJSON').addEventListener('click',function(){
    downloadBlob(new Blob([JSON.stringify(items,null,2)],{type:'application/json'}),'asset-classification.json');
  });
}

// === APP SUMMARY TAB ===
function _autoDiscoverApps(){
  if(_appAutoDiscovered) return;
  if(!_classificationData.length) return;
  _appAutoDiscovered=true;
  var seen={};
  var candidates=['Application','app','App','Service','service','Product','product','Component','component','Project','project'];
  _classificationData.forEach(function(r){
    if(!r.tags) return;
    candidates.forEach(function(tk){
      var val=r.tags[tk];
      if(!val) return;
      var key=val.toLowerCase();
      if(seen[key]) return;
      seen[key]=true;
      _appRegistry.push({name:val,pattern:val.replace(/[.*+?^${}()|[\]\\]/g,'\\$&').replace(/[\s_-]+/g,'[\\s_-]+'),type:'',tier:'',auto:true});
    });
  });
}

function _matchAppResources(app){
  if(!app.pattern) return[];
  var matched=[];
  var re=_safeRegex(app.pattern);if(!re) return[];
  _classificationData.forEach(function(r){
    var text=(r.name||'')+' '+(r.type||'')+' '+(r.vpcName||'')+' '+Object.values(r.tags||{}).join(' ');
    if(re.test(text)) matched.push(r);
  });
  return matched;
}

function _buildAppRows(){
  var tierPri={critical:1,high:2,medium:3,low:4};
  return _appRegistry.map(function(app,idx){
    var matched=_udashFilterByAccount(_matchAppResources(app));
    var bestTier='low';
    var types={};var vpcs={};var accts={};
    matched.forEach(function(r){
      if((tierPri[r.tier]||99)<(tierPri[bestTier]||99)) bestTier=r.tier;
      types[r.type]=true;
      if(r.vpcName) vpcs[r.vpcName]=true;
      if(r._subscriptionId){var _al=typeof _rptAccountLabel==='function'?(_rptAccountLabel(r._subscriptionId)||r._subscriptionId):r._subscriptionId;accts[_al]=true}
    });
    var tier=app.tier||bestTier;
    var meta=_TIER_RPO_RTO[tier]||_TIER_RPO_RTO.low;
    return{idx:idx,name:app.name,pattern:app.pattern,type:app.type||'',tier:tier,autoTier:!app.tier,rpo:meta.rpo,rto:meta.rto,count:matched.length,types:Object.keys(types).join(', '),vpcs:Object.keys(vpcs).join(', '),accounts:Object.keys(accts),auto:app.auto};
  });
}

function _renderAppSummaryTab(){
  var tb=document.getElementById('udashToolbar');
  var body=document.getElementById('udashBody');
  var footer=document.getElementById('udashFooter');
  var st=_appSummaryState;
  _autoDiscoverApps();
  // Toolbar
  var th='<label>Search</label>';
  th+='<input id="appSearch" type="text" placeholder="Filter apps..." value="'+_escHtml(st.search)+'">';
  th+='<span style="margin-left:auto;display:flex;gap:6px">';
  th+='<button id="appDelSelBtn" style="background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);color:#ef4444;padding:4px 12px;border-radius:4px;font-size:11px;font-family:Segoe UI,system-ui,sans-serif;cursor:pointer;display:none">Delete Selected</button>';
  th+='<button id="appClearAutoBtn" style="background:none;border:1px solid var(--border);color:var(--text-muted);padding:4px 12px;border-radius:4px;font-size:11px;font-family:Segoe UI,system-ui,sans-serif;cursor:pointer">Clear Auto</button>';
  th+='<button id="appAddBtn" style="background:rgba(52,211,153,.15);border:1px solid #34d399;color:#34d399;padding:4px 14px;border-radius:4px;font-size:11px;font-family:Segoe UI,system-ui,sans-serif;cursor:pointer">+ Add App</button>';
  th+='</span>';
  tb.innerHTML=th;
  document.getElementById('appSearch').addEventListener('input',function(){st.search=this.value;_renderAppSummaryTab()});
  document.getElementById('appAddBtn').addEventListener('click',function(){st.adding=true;st.editing=-1;_renderAppSummaryTab()});
  document.getElementById('appClearAutoBtn').addEventListener('click',function(){_appRegistry=_appRegistry.filter(function(a){return!a.auto});_renderAppSummaryTab()});
  // Build rows
  var apps=_buildAppRows();
  if(st.search){var q=st.search.toLowerCase();apps=apps.filter(function(a){return a.name.toLowerCase().indexOf(q)!==-1||(a.type||'').toLowerCase().indexOf(q)!==-1||a.types.toLowerCase().indexOf(q)!==-1})}
  // Sort
  var tierPri={critical:1,high:2,medium:3,low:4};
  var dir=st.sortDir==='asc'?1:-1;
  apps.sort(function(a,b){
    if(st.sort==='tier') return((tierPri[a.tier]||99)-(tierPri[b.tier]||99))*dir;
    if(st.sort==='count') return(a.count-b.count)*dir;
    var av=(a[st.sort]||'').toLowerCase();var bv=(b[st.sort]||'').toLowerCase();
    return av<bv?-dir:av>bv?dir:0;
  });
  // Tier summary cards
  var tierCounts={critical:0,high:0,medium:0,low:0};
  apps.forEach(function(a){tierCounts[a.tier]=(tierCounts[a.tier]||0)+1});
  var bh='<div class="gov-tier-cards">';
  [{t:'critical',l:'Critical'},{t:'high',l:'High'},{t:'medium',l:'Medium'},{t:'low',l:'Low'}].forEach(function(d){
    var meta=_TIER_RPO_RTO[d.t];
    bh+='<div class="gov-tier-card" style="border-color:'+meta.color+'">';
    bh+='<h3 style="color:'+meta.color+'">'+d.l+'</h3>';
    bh+='<div class="gov-tier-count" style="color:'+meta.color+'">'+(tierCounts[d.t]||0)+'</div>';
    bh+='</div>';
  });
  bh+='</div>';
  // Add/Edit form
  if(st.adding||st.editing>=0){
    var ed=st.editing>=0?_appRegistry[st.editing]:null;
    bh+='<div style="background:rgba(52,211,153,.06);border:1px solid rgba(52,211,153,.25);border-radius:8px;padding:12px 16px;margin-bottom:12px;display:flex;gap:10px;align-items:flex-end;flex-wrap:wrap">';
    bh+='<div style="display:flex;flex-direction:column;gap:2px"><label style="font-size:9px;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif">App Name</label>';
    bh+='<input id="appFormName" type="text" placeholder="e.g. Quark" value="'+_escHtml(ed?ed.name:'')+'" style="width:140px;padding:4px 8px;font-size:11px;background:var(--bg-secondary);border:1px solid var(--border);border-radius:4px;color:var(--text-primary);font-family:Segoe UI,system-ui,sans-serif"></div>';
    bh+='<div style="display:flex;flex-direction:column;gap:2px"><label style="font-size:9px;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif">Match Pattern <span style="opacity:.5">(regex)</span></label>';
    bh+='<input id="appFormPattern" type="text" placeholder="auto from name" value="'+_escHtml(ed?ed.pattern:'')+'" style="width:140px;padding:4px 8px;font-size:11px;background:var(--bg-secondary);border:1px solid var(--border);border-radius:4px;color:var(--text-primary);font-family:monospace"></div>';
    bh+='<div style="display:flex;flex-direction:column;gap:2px"><label style="font-size:9px;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif">Type</label>';
    bh+='<input id="appFormType" list="appTypeSuggestions" type="text" placeholder="e.g. Web App" value="'+_escHtml(ed?ed.type:'')+'" style="width:120px;padding:4px 8px;font-size:11px;background:var(--bg-secondary);border:1px solid var(--border);border-radius:4px;color:var(--text-primary);font-family:Segoe UI,system-ui,sans-serif">';
    bh+='<datalist id="appTypeSuggestions">';
    _APP_TYPE_SUGGESTIONS.forEach(function(t){bh+='<option value="'+t+'">'});
    bh+='</datalist></div>';
    bh+='<div style="display:flex;flex-direction:column;gap:2px"><label style="font-size:9px;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif">Criticality</label>';
    bh+='<select id="appFormTier" style="width:110px;padding:4px 8px;font-size:11px;background:var(--bg-secondary);border:1px solid var(--border);border-radius:4px;color:var(--text-primary);font-family:Segoe UI,system-ui,sans-serif">';
    bh+='<option value=""'+((!ed||!ed.tier)?' selected':'')+'>(auto)</option>';
    ['critical','high','medium','low'].forEach(function(t){bh+='<option value="'+t+'"'+((ed&&ed.tier===t)?' selected':'')+'>'+t.charAt(0).toUpperCase()+t.slice(1)+'</option>'});
    bh+='</select></div>';
    bh+='<button id="appFormSave" style="padding:4px 16px;font-size:11px;background:#34d399;border:none;border-radius:4px;color:#000;cursor:pointer;font-weight:600;font-family:Segoe UI,system-ui,sans-serif">'+(ed?'Update':'Add')+'</button>';
    bh+='<button id="appFormCancel" style="padding:4px 12px;font-size:11px;background:none;border:1px solid var(--border);border-radius:4px;color:var(--text-muted);cursor:pointer;font-family:Segoe UI,system-ui,sans-serif">Cancel</button>';
    bh+='</div>';
  }
  // Table
  var appHasMultiAcct=apps.some(function(a){return a.accounts&&a.accounts.length>0})&&new Set(apps.reduce(function(s,a){return s.concat(a.accounts||[])},[]).filter(Boolean)).size>1;
  var cols=[{key:'name',label:'Application'},{key:'type',label:'Type'}];
  if(appHasMultiAcct) cols.push({key:'accounts',label:'Accounts',nosort:true});
  cols.push({key:'tier',label:'Criticality'},{key:'count',label:'Resources'},{key:'rpo',label:'RPO',nosort:true},{key:'rto',label:'RTO',nosort:true},{key:'actions',label:'',nosort:true});
  bh+='<table class="gov-table"><thead><tr>';
  bh+='<th style="width:28px"><input type="checkbox" id="appSelAll" style="cursor:pointer"></th>';
  cols.forEach(function(c){
    var cls='';if(!c.nosort&&st.sort===c.key) cls=st.sortDir==='asc'?' sort-asc':' sort-desc';
    bh+='<th'+(c.nosort?'':' data-sort-col="'+c.key+'"')+' class="'+cls+'">'+c.label+'</th>';
  });
  bh+='</tr></thead><tbody>';
  if(!apps.length) bh+='<tr><td colspan="'+(cols.length+1)+'" style="text-align:center;padding:30px;color:var(--text-muted)">No apps defined — click <b>+ Add App</b> to get started</td></tr>';
  apps.forEach(function(a){
    bh+='<tr data-app-idx="'+a.idx+'">';
    bh+='<td><input type="checkbox" class="app-sel-cb" data-idx="'+a.idx+'" style="cursor:pointer"></td>';
    bh+='<td><span style="font-weight:500">'+_escHtml(a.name)+'</span>'+(a.auto?' <span style="font-size:8px;color:var(--text-muted);opacity:.6">auto</span>':'')+'<br><span style="font-size:9px;color:var(--text-muted);font-family:monospace">'+_escHtml(a.pattern)+'</span></td>';
    bh+='<td style="font-size:10px">'+_escHtml(a.type||'—')+'</td>';
    if(appHasMultiAcct) bh+='<td>'+(a.accounts||[]).map(function(id){return _acctPill(id)}).join(' ')+'</td>';
    bh+='<td><span class="gov-tier-badge '+a.tier+'">'+a.tier+'</span>'+(a.autoTier&&a.auto?' <span style="font-size:8px;color:var(--text-muted)">auto</span>':'')+'</td>';
    bh+='<td style="text-align:center">'+a.count+'</td>';
    bh+='<td style="font-size:10px;color:var(--text-muted)">'+a.rpo+'</td>';
    bh+='<td style="font-size:10px;color:var(--text-muted)">'+a.rto+'</td>';
    bh+='<td><button class="app-edit-btn" data-idx="'+a.idx+'" style="font-size:9px;padding:2px 8px;cursor:pointer;background:none;border:1px solid var(--border);border-radius:3px;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif;margin-right:4px">Edit</button>';
    bh+='<button class="app-del-btn" data-idx="'+a.idx+'" style="font-size:9px;padding:2px 8px;cursor:pointer;background:none;border:1px solid rgba(239,68,68,.3);border-radius:3px;color:#ef4444;font-family:Segoe UI,system-ui,sans-serif">Del</button></td>';
    bh+='</tr>';
  });
  bh+='</tbody></table>';
  body.innerHTML=bh;
  body.scrollTop=0;
  // Footer
  var fh='<button id="appExportCSV">Export CSV</button>';
  fh+='<button id="appExportJSON">Export JSON</button>';
  fh+='<span style="margin-left:auto;font-size:10px;color:var(--text-muted)">'+_appRegistry.length+' apps · '+_classificationData.length+' total resources</span>';
  footer.innerHTML=fh;
  // Wire form events
  if(st.adding||st.editing>=0){
    document.getElementById('appFormCancel').addEventListener('click',function(){st.adding=false;st.editing=-1;_renderAppSummaryTab()});
    document.getElementById('appFormSave').addEventListener('click',function(){
      var name=document.getElementById('appFormName').value.trim();
      if(!name){_showToast('App name is required','warn');return}
      var pattern=document.getElementById('appFormPattern').value.trim()||name.replace(/[.*+?^${}()|[\]\\]/g,'\\$&').replace(/[\s_-]+/g,'[\\s_-]+');
      var type=document.getElementById('appFormType').value.trim();
      var tier=document.getElementById('appFormTier').value;
      if(st.editing>=0){
        _appRegistry[st.editing].name=name;
        _appRegistry[st.editing].pattern=pattern;
        _appRegistry[st.editing].type=type;
        _appRegistry[st.editing].tier=tier;
        _appRegistry[st.editing].auto=false;
      }else{
        _appRegistry.push({name:name,pattern:pattern,type:type,tier:tier,auto:false});
      }
      st.adding=false;st.editing=-1;
      _renderAppSummaryTab();
    });
  }
  // Wire table events
  body.querySelectorAll('th[data-sort-col]').forEach(function(hdr){
    hdr.addEventListener('click',function(){
      var col=this.dataset.sortCol;
      if(st.sort===col) st.sortDir=st.sortDir==='asc'?'desc':'asc';
      else{st.sort=col;st.sortDir='asc'}
      _renderAppSummaryTab();
    });
  });
  body.querySelectorAll('.app-edit-btn').forEach(function(btn){
    btn.addEventListener('click',function(){st.editing=parseInt(this.dataset.idx);st.adding=false;_renderAppSummaryTab()});
  });
  body.querySelectorAll('.app-del-btn').forEach(function(btn){
    btn.addEventListener('click',function(){
      var idx=parseInt(this.dataset.idx);
      _appRegistry.splice(idx,1);
      st.editing=-1;
      _renderAppSummaryTab();
    });
  });
  // Checkbox select-all + delete selected
  var delSelBtn=document.getElementById('appDelSelBtn');
  function _updateDelBtn(){
    var checked=body.querySelectorAll('.app-sel-cb:checked').length;
    delSelBtn.style.display=checked?'':'none';
    delSelBtn.textContent='Delete Selected ('+checked+')';
  }
  var selAll=document.getElementById('appSelAll');
  if(selAll) selAll.addEventListener('change',function(){
    var checked=this.checked;
    body.querySelectorAll('.app-sel-cb').forEach(function(cb){cb.checked=checked});
    _updateDelBtn();
  });
  body.querySelectorAll('.app-sel-cb').forEach(function(cb){cb.addEventListener('change',_updateDelBtn)});
  delSelBtn.addEventListener('click',function(){
    var toDelete={};
    body.querySelectorAll('.app-sel-cb:checked').forEach(function(cb){toDelete[cb.dataset.idx]=true});
    _appRegistry=_appRegistry.filter(function(_,i){return!toDelete[i]});
    st.editing=-1;
    _renderAppSummaryTab();
  });
  document.getElementById('appExportCSV').addEventListener('click',function(){
    var rows=[['Application','Type','Criticality','RPO','RTO','Resources','Resource Types','VPCs']];
    apps.forEach(function(a){rows.push([a.name,a.type,a.tier,a.rpo,a.rto,a.count,a.types,a.vpcs])});
    var csv=rows.map(function(r){return r.map(function(c){return '"'+String(c).replace(/"/g,'""')+'"'}).join(',')}).join('\n');
    downloadBlob(new Blob([csv],{type:'text/csv'}),'app-summary.csv');
  });
  document.getElementById('appExportJSON').addEventListener('click',function(){
    downloadBlob(new Blob([JSON.stringify(apps,null,2)],{type:'application/json'}),'app-summary.json');
  });
}

function _renderIAMTab(){
  var tb=document.getElementById('udashToolbar');
  var body=document.getElementById('udashBody');
  var footer=document.getElementById('udashFooter');
  var st=_iamDashState;
  // Toolbar — only rebuild on tab switch
  if(_govToolbarTab!=='iam'){
    _govToolbarTab='iam';
    var th='<label>Search</label>';
    th+='<input id="govSearch" type="text" placeholder="Filter by name, ARN, type..." value="'+_escHtml(st.search)+'">';
    th+='<label>Filter</label>';
    th+='<select id="govFilter">';
    [{v:'all',l:'All'},{v:'roles',l:'Roles Only'},{v:'users',l:'Users Only'},{v:'admin',l:'Admin Access'},{v:'findings',l:'With Findings'}].forEach(function(o){
      th+='<option value="'+o.v+'"'+(st.filter===o.v?' selected':'')+'>'+o.l+'</option>';
    });
    th+='</select>';
    th+='<label>Per page</label>';
    th+='<select id="govPerPage">';
    [25,50,100,0].forEach(function(v){th+='<option value="'+v+'"'+(st.perPage===v?' selected':'')+'>'+(v||'All')+'</option>'});
    th+='</select>';
    tb.innerHTML=th;
    document.getElementById('govSearch').addEventListener('input',function(){st.search=this.value;st.page=1;_renderIAMTab()});
    document.getElementById('govFilter').addEventListener('change',function(){st.filter=this.value;st.page=1;_renderIAMTab()});
    document.getElementById('govPerPage').addEventListener('change',function(){st.perPage=parseInt(this.value)||0;st.page=1;_renderIAMTab()});
  }
  if(!_iamReviewData.length){
    body.innerHTML='<div style="text-align:center;padding:60px;color:var(--text-muted);font-family:Segoe UI,system-ui,sans-serif"><p style="font-size:14px">No IAM data loaded</p><p style="font-size:11px">Paste RBAC role assignment details (from <code>az role assignment list</code>) in the IAM section of the left panel, then re-render.</p></div>';
    footer.textContent='';
    return;
  }
  // Filter + sort (account filter applied first)
  var items=_udashFilterByAccount(_iamReviewData).slice();
  if(st.filter==='roles') items=items.filter(function(r){return r.type==='Role'});
  else if(st.filter==='users') items=items.filter(function(r){return r.type==='User'});
  else if(st.filter==='admin') items=items.filter(function(r){return r.isAdmin});
  else if(st.filter==='findings') items=items.filter(function(r){return r.findings.length>0});
  if(st.search){var q=st.search.toLowerCase();items=items.filter(function(r){return(r.name||'').toLowerCase().indexOf(q)!==-1||(r.arn||'').toLowerCase().indexOf(q)!==-1||(r.type||'').toLowerCase().indexOf(q)!==-1})}
  var sortKey=st.sort;var dir=st.sortDir==='asc'?1:-1;
  items.sort(function(a,b){
    if(sortKey==='lastUsed'||sortKey==='created'){return((a[sortKey]||0)-(b[sortKey]||0))*dir}
    var av=(a[sortKey]||'').toString().toLowerCase();var bv=(b[sortKey]||'').toString().toLowerCase();
    return av<bv?-dir:av>bv?dir:0;
  });
  // Paginate
  var perPage=st.perPage<=0?items.length:st.perPage;
  var totalPages=Math.max(1,Math.ceil(items.length/perPage));
  st.page=Math.min(Math.max(1,st.page),totalPages);
  var start=(st.page-1)*perPage;
  var pageItems=items.slice(start,start+perPage);
  // Summary (from account-filtered set)
  var _iamAll=_udashFilterByAccount(_iamReviewData);
  var roleCt=_iamAll.filter(function(r){return r.type==='Role'}).length;
  var userCt=_iamAll.filter(function(r){return r.type==='User'}).length;
  var adminCt=_iamAll.filter(function(r){return r.isAdmin}).length;
  var findCt=_iamAll.filter(function(r){return r.findings.length>0}).length;
  var bh='<div class="gov-tier-cards" style="margin-bottom:16px">';
  [{l:'Roles',c:roleCt,color:'#8b5cf6'},{l:'Users',c:userCt,color:'#22d3ee'},{l:'Admin',c:adminCt,color:'#ef4444'},{l:'With Findings',c:findCt,color:'#f59e0b'}].forEach(function(d){
    bh+='<div class="gov-tier-card" style="border-color:'+d.color+'"><h3 style="color:'+d.color+'">'+d.l+'</h3><div class="gov-tier-count" style="color:'+d.color+'">'+d.c+'</div></div>';
  });
  bh+='</div>';
  // Table
  var iamHasMultiAcct=new Set(items.map(function(r){return r._subscriptionId}).filter(Boolean)).size>1;
  var cols=[{key:'name',label:'Name'},{key:'type',label:'Type'}];
  if(iamHasMultiAcct) cols.push({key:'_subscriptionId',label:'Account'});
  cols.push({key:'created',label:'Created'},{key:'lastUsed',label:'Last Used'},{key:'policies',label:'Policies',nosort:true},{key:'admin',label:'Admin',nosort:true},{key:'findings',label:'Findings',nosort:true},{key:'cross',label:'Cross-Acct',nosort:true});
  bh+='<table class="gov-table"><thead><tr>';
  cols.forEach(function(c){
    var cls='';if(!c.nosort&&st.sort===c.key) cls=st.sortDir==='asc'?' sort-asc':' sort-desc';
    bh+='<th'+(c.nosort?'':' data-sort-col="'+c.key+'"')+' class="'+cls+'">'+c.label+'</th>';
  });
  bh+='</tr></thead><tbody>';
  if(!pageItems.length) bh+='<tr><td colspan="'+cols.length+'" style="text-align:center;padding:30px;color:var(--text-muted)">No IAM entities match filters</td></tr>';
  pageItems.forEach(function(r,idx){
    var rowId='iam-r-'+idx;
    bh+='<tr data-iam-row="'+rowId+'" style="cursor:pointer">';
    bh+='<td style="color:var(--accent-cyan)">'+_escHtml(r.name)+'</td>';
    bh+='<td>'+_escHtml(r.type)+'</td>';
    if(iamHasMultiAcct) bh+='<td>'+_acctPill(r._subscriptionId)+'</td>';
    bh+='<td style="font-size:10px">'+(r.created?r.created.toISOString().split('T')[0]:'—')+'</td>';
    bh+='<td style="font-size:10px">'+(r.lastUsed?r.lastUsed.toISOString().split('T')[0]:'Never')+'</td>';
    bh+='<td style="text-align:center">'+r.policies+'</td>';
    bh+='<td>'+(r.isAdmin?'<span class="gov-admin-badge">Admin</span>':'—')+'</td>';
    bh+='<td>'+(r.findings.length>0?'<span class="gov-finding-badge">'+r.findings.length+'</span>':'—')+'</td>';
    bh+='<td>'+(r.crossAccounts.length>0?'<span style="color:#f59e0b">'+r.crossAccounts.length+'</span>':'—')+'</td>';
    bh+='</tr>';
    // Expandable detail row
    bh+='<tr><td colspan="'+cols.length+'" class="gov-iam-expand" id="'+rowId+'-exp">';
    bh+='<div style="margin-bottom:6px"><b>ARN:</b> <code style="font-size:10px;background:var(--bg-input);padding:2px 6px;border-radius:3px">'+_escHtml(r.arn)+'</code></div>';
    if(r.policyNames&&r.policyNames.length) bh+='<div style="margin-bottom:6px"><b>Policies:</b> '+r.policyNames.map(function(p){return '<code style="font-size:9px;background:var(--bg-input);padding:1px 4px;border-radius:2px;margin-right:3px">'+_escHtml(p)+'</code>'}).join('')+'</div>';
    if(r.permBoundary) bh+='<div style="margin-bottom:6px"><b>Permission Boundary:</b> <code style="font-size:9px">'+_escHtml(r.permBoundary)+'</code></div>';
    if(r.crossAccounts.length) bh+='<div style="margin-bottom:6px"><b>Cross-Account Trusts:</b> '+r.crossAccounts.map(function(a){return '<code style="font-size:10px;background:rgba(245,158,11,.1);padding:1px 4px;border-radius:2px;margin-right:3px">'+_escHtml(a)+'</code>'}).join('')+'</div>';
    if(r.type==='User'){
      bh+='<div style="margin-bottom:6px"><b>MFA:</b> '+(r.hasMFA?'<span style="color:#10b981">✓ Enabled</span>':'<span style="color:#ef4444">✗ Disabled</span>')+'</div>';
      if(r.hasConsole) bh+='<div style="margin-bottom:6px"><b>Console Access:</b> <span style="color:#f59e0b">Enabled</span></div>';
      if(r.activeKeys) bh+='<div style="margin-bottom:6px"><b>Active Access Keys:</b> '+r.activeKeys+'</div>';
    }
    if(r.findings.length){
      bh+='<div><b>Findings ('+r.findings.length+'):</b><ul style="margin:4px 0 0;padding-left:20px;list-style:none">';
      r.findings.forEach(function(f){
        var sColor=f.severity==='CRITICAL'?'#ef4444':f.severity==='HIGH'?'#f97316':f.severity==='MEDIUM'?'#eab308':'#3b82f6';
        bh+='<li style="font-size:10px;color:var(--text-secondary);margin:3px 0"><span style="font-size:8px;font-weight:700;padding:1px 4px;border-radius:2px;background:rgba(0,0,0,.2);color:'+sColor+';margin-right:4px">'+f.severity+'</span>'+_escHtml(f.message)+'</li>';
      });
      bh+='</ul></div>';
    }
    bh+='</td></tr>';
  });
  bh+='</tbody></table>';
  body.innerHTML=bh;
  body.scrollTop=0;
  // Footer
  var fh='<button id="govExportCSV">Export CSV</button>';
  fh+='<button id="govExportJSON">Export JSON</button>';
  fh+='<span style="margin-left:auto;font-size:10px;color:var(--text-muted)">'+items.length+' of '+_iamReviewData.length+'</span>';
  if(totalPages>1){
    fh+='<button id="govPrev"'+(st.page<=1?' disabled':'')+'>← Prev</button>';
    fh+='<span style="font-size:10px;color:var(--text-muted)">Page '+st.page+' of '+totalPages+'</span>';
    fh+='<button id="govNext"'+(st.page>=totalPages?' disabled':'')+'>Next →</button>';
  }
  footer.innerHTML=fh;
  // Wire body/footer events (these get recreated each render)
  if(document.getElementById('govPrev')) document.getElementById('govPrev').addEventListener('click',function(){st.page--;_renderIAMTab()});
  if(document.getElementById('govNext')) document.getElementById('govNext').addEventListener('click',function(){st.page++;_renderIAMTab()});
  // Sort headers
  body.querySelectorAll('th[data-sort-col]').forEach(function(th){
    th.addEventListener('click',function(){
      var col=this.dataset.sortCol;
      if(st.sort===col) st.sortDir=st.sortDir==='asc'?'desc':'asc';
      else{st.sort=col;st.sortDir='asc'}
      st.page=1;_renderIAMTab();
    });
  });
  // Row expand/collapse
  body.querySelectorAll('tr[data-iam-row]').forEach(function(tr){
    tr.addEventListener('click',function(){
      var rowId=this.dataset.iamRow;
      var exp=document.getElementById(rowId+'-exp');
      if(!exp)return;
      var isOpen=exp.classList.contains('open');
      body.querySelectorAll('.gov-iam-expand').forEach(function(e){e.classList.remove('open')});
      body.querySelectorAll('tr[data-iam-row]').forEach(function(r){r.classList.remove('expanded')});
      if(!isOpen){exp.classList.add('open');this.classList.add('expanded')}
    });
  });
  // Export
  document.getElementById('govExportCSV').addEventListener('click',function(){
    var rows=[['Name','Type','ARN','Created','Last Used','Policies','Admin','Findings','Cross-Account']];
    items.forEach(function(r){rows.push([r.name,r.type,r.arn,r.created?r.created.toISOString():'',r.lastUsed?r.lastUsed.toISOString():'',r.policies,r.isAdmin?'Yes':'No',r.findings.length,r.crossAccounts.join(';')])});
    var csv=rows.map(function(r){return r.map(function(c){return '"'+String(c).replace(/"/g,'""')+'"'}).join(',')}).join('\n');
    downloadBlob(new Blob([csv],{type:'text/csv'}),'iam-review.csv');
  });
  document.getElementById('govExportJSON').addEventListener('click',function(){
    downloadBlob(new Blob([JSON.stringify(items.map(function(r){return{name:r.name,type:r.type,arn:r.arn,created:r.created,lastUsed:r.lastUsed,isAdmin:r.isAdmin,policies:r.policies,policyNames:r.policyNames,crossAccounts:r.crossAccounts,findingCount:r.findings.length}}),null,2)],{type:'application/json'}),'iam-review.json');
  });
}

// Collect unique tag values for a given tag key from classification data
function _collectTagValues(tagKey){
  var vals={};
  (_classificationData||[]).forEach(function(res){
    var v=(res.tags||{})[tagKey];
    if(v) vals[v]=(vals[v]||0)+1;
  });
  return Object.keys(vals).map(function(v){return{val:v,ct:vals[v]}}).sort(function(a,b){return b.ct-a.ct});
}

// Rules editor overlay
function _openRulesEditor(){
  var existing=document.getElementById('govRulesOverlay');
  if(existing) existing.remove();
  // Working copy of rules
  var workRules=structuredClone(_classificationRules);
  workRules.forEach(function(r){if(r.enabled===undefined) r.enabled=true});
  var groupCollapsed={any:false,vpc:false,type:false,name:false};
  var scopeLabels={any:'Any (Name + Tags + VPC)',vpc:'VPC Name Rules',type:'Resource Type Rules',name:'Resource Name Rules'};
  var scopeOrder=['any','vpc','type','name'];
  // Discover tag scopes from rules + data
  var disc=_discoveredTags||{};
  var tagScopes={};
  workRules.forEach(function(r){if(r.scope&&r.scope.indexOf('tag:')===0) tagScopes[r.scope]=true});
  Object.keys(disc).forEach(function(k){tagScopes['tag:'+k]=true});
  var sortedTagScopes=Object.keys(tagScopes).sort(function(a,b){
    var ac=(disc[a.substring(4)]||{}).count||0,bc=(disc[b.substring(4)]||{}).count||0;return bc-ac;
  });
  sortedTagScopes.forEach(function(ts){
    var tk=ts.substring(4);var info=disc[tk];
    scopeOrder.push(ts);
    scopeLabels[ts]='Tag: '+tk+(info?' ('+info.count+' resources)':'');
    groupCollapsed[ts]=true;
  });
  var overlay=document.createElement('div');
  overlay.id='govRulesOverlay';
  overlay.className='gov-rules-overlay';

  function readRulesFromDom(){
    var rules=[];
    overlay.querySelectorAll('.gov-rule-row[data-rule-idx]').forEach(function(row){
      var idx=parseInt(row.dataset.ruleIdx);
      var r=workRules[idx];if(!r) return;
      r.pattern=row.querySelector('[data-field="pattern"]').value;
      r.scope=row.querySelector('[data-field="scope"]').value;
      r.tier=row.querySelector('[data-field="tier"]').value;
      r.weight=parseInt(row.querySelector('[data-field="weight"]').value)||0;
    });
    return workRules;
  }
  function countMatches(rule){
    if(!rule.pattern||rule.enabled===false) return 0;
    var re=_safeRegex(rule.pattern);if(!re) return -1;
    var ct=0;
    (_classificationData||[]).forEach(function(res){
      var text='';
      if(rule.scope==='any') text=(res.name||'')+' '+(res.type||'')+' '+(res.vpcName||'')+' '+Object.values(res.tags||{}).join(' ');
      else if(rule.scope==='vpc') text=res.vpcName||'';
      else if(rule.scope==='type') text=res.type||'';
      else if(rule.scope==='name') text=res.name||'';
      else if(rule.scope.indexOf('tag:')===0) text=(res.tags||{})[rule.scope.substring(4)]||'';
      if(re.test(text)) ct++;
    });
    return ct;
  }
  function buildPreview(rules){
    if(!_rlCtx) return {critical:0,high:0,medium:0,low:0,samples:[]};
    var counts={critical:0,high:0,medium:0,low:0};
    var samples=[];
    var vpcNameMap={};
    (_rlCtx.vnets||[]).forEach(function(v){vpcNameMap[v.VpcId]=gn(v,v.VpcId)});
    function classify(name,type,vpcName,id,obj){
      var tm=_getTagMap(obj||{});
      var tier=(_classificationOverrides[id]||_scoreClassification(name,type,vpcName,rules,tm).tier);
      counts[tier]=(counts[tier]||0)+1;
      if(samples.length<12) samples.push({name:name,type:type,tier:tier});
    }
    (_rlCtx.vms||[]).forEach(function(inst){
      var name=inst.Tags?((inst.Tags.find(function(t){return t.Key==='Name'})||{}).Value||inst.InstanceId):inst.InstanceId;
      classify(name,'instance',vpcNameMap[inst.VpcId]||'',inst.InstanceId,inst);
    });
    (_rlCtx.sqlServers||[]).forEach(function(db){classify(db.DBInstanceIdentifier,'rds',vpcNameMap[(db.DBSubnetGroup||{}).VpcId]||'',db.DBInstanceIdentifier,db)});
    (_rlCtx.redisCaches||[]).forEach(function(ec){classify(ec.CacheClusterId,'elasticache','',ec.CacheClusterId,ec)});
    (_rlCtx.appGateways||[]).forEach(function(alb){classify(alb.LoadBalancerName||'','alb',vpcNameMap[alb.VpcId]||'',alb.LoadBalancerName||'',alb)});
    (_rlCtx.functionApps||[]).forEach(function(fn){classify(fn.FunctionName,'lambda',vpcNameMap[(fn.VpcConfig||{}).VpcId]||'',fn.FunctionName,fn)});
    (_rlCtx.containerInstances||[]).forEach(function(svc){classify(svc.serviceName||'','ecs','',svc.serviceName||'',svc)});
    (_rlCtx.synapseWorkspaces||[]).forEach(function(rs){classify(rs.ClusterIdentifier,'redshift',vpcNameMap[rs.VpcId]||'',rs.ClusterIdentifier,rs)});
    (_rlCtx.nsgs||[]).forEach(function(sg){classify(gn(sg,sg.GroupId),'security-group',vpcNameMap[sg.VpcId]||'',sg.GroupId,sg)});
    (_rlCtx.vnets||[]).forEach(function(v){var n=gn(v,v.VpcId);classify(n,'vpc',n,v.VpcId,v)});
    (_rlCtx.subnets||[]).forEach(function(s){classify(gn(s,s.SubnetId),'subnet',vpcNameMap[s.VpcId]||'',s.SubnetId,s)});
    (_rlCtx.firewalls||[]).forEach(function(gw){var vid=(gw.Attachments&&gw.Attachments[0])?gw.Attachments[0].VpcId:'';classify(gn(gw,gw.InternetGatewayId),'igw',vpcNameMap[vid]||'',gw.InternetGatewayId,gw)});
    (_rlCtx.natGateways||[]).forEach(function(ng){classify(gn(ng,ng.NatGatewayId),'nat-gateway',vpcNameMap[ng.VpcId]||'',ng.NatGatewayId,ng)});
    (_rlCtx.privateEndpoints||[]).forEach(function(ve){classify(ve.ServiceName||ve.VpcEndpointId,'vpc-endpoint',vpcNameMap[ve.VpcId]||'',ve.VpcEndpointId,ve)});
    (_rlCtx.s3bk||[]).forEach(function(b){classify(b.Name||'','s3','',b.Name||'',b)});
    return {critical:counts.critical,high:counts.high,medium:counts.medium,low:counts.low,total:counts.critical+counts.high+counts.medium+counts.low,samples:samples};
  }
  function renderPreview(){
    var el=document.getElementById('govRulesPreview');if(!el) return;
    var rules=readRulesFromDom();
    var p=buildPreview(rules);
    var total=p.total||1;
    var cur={critical:0,high:0,medium:0,low:0};
    _classificationData.forEach(function(r){cur[r.tier]=(cur[r.tier]||0)+1});
    var ph='<div class="gov-preview-card"><h5>Classification Distribution</h5><div class="gov-preview-bars">';
    [{k:'critical',l:'Critical',c:'#ef4444'},{k:'high',l:'High',c:'#f59e0b'},{k:'medium',l:'Medium',c:'#22d3ee'},{k:'low',l:'Low',c:'#64748b'}].forEach(function(d){
      var pct=Math.round((p[d.k]/total)*100);
      ph+='<div class="gov-preview-bar"><span class="gov-preview-bar-label" style="color:'+d.c+'">'+d.l+'</span>';
      ph+='<div class="gov-preview-bar-track"><div class="gov-preview-bar-fill" style="width:'+pct+'%;background:'+d.c+'"></div></div>';
      ph+='<span class="gov-preview-bar-ct">'+p[d.k]+'</span></div>';
    });
    ph+='</div></div>';
    // Delta from current
    var deltas=[];
    [{k:'critical',l:'Critical',c:'#ef4444'},{k:'high',l:'High',c:'#f59e0b'},{k:'medium',l:'Medium',c:'#22d3ee'},{k:'low',l:'Low',c:'#64748b'}].forEach(function(d){
      var diff=p[d.k]-(cur[d.k]||0);
      if(diff!==0) deltas.push('<span style="color:'+d.c+'">'+d.l+': <span class="'+(diff>0?'up':'down')+'">'+(diff>0?'+':'')+diff+'</span></span>');
    });
    if(deltas.length) ph+='<div class="gov-preview-delta">'+deltas.join(' &nbsp; ')+'</div>';
    else ph+='<div class="gov-preview-delta"><span class="same">No changes from current</span></div>';
    // Sample
    ph+='<div class="gov-preview-card" style="margin-top:10px"><h5>Sample Resources</h5><div class="gov-preview-sample">';
    p.samples.forEach(function(s){
      var tc=_TIER_RPO_RTO[s.tier]||{color:'#64748b'};
      ph+='<div class="gov-preview-sample-row"><span class="name">'+_escHtml(s.name)+'</span><span class="type">'+_escHtml(s.type)+'</span><span class="gov-tier-badge '+s.tier+'" style="font-size:8px;padding:1px 5px">'+s.tier+'</span></div>';
    });
    ph+='</div></div>';
    el.innerHTML=ph;
  }
  function renderRules(){
    var list=document.getElementById('govRulesList');if(!list) return;
    var h='';
    scopeOrder.forEach(function(scope){
      var rules=[];workRules.forEach(function(r,i){if(r.scope===scope) rules.push({rule:r,idx:i})});
      if(!rules.length&&scope!=='vpc') return;
      var collapsed=groupCollapsed[scope];
      h+='<div class="gov-rule-group" data-scope="'+scope+'">';
      h+='<div class="gov-rule-group-hdr" data-toggle-scope="'+scope+'"><span class="gov-rule-group-arrow'+(collapsed?' collapsed':'')+'">▼</span>';
      h+='<span class="gov-rule-group-label">'+(scopeLabels[scope]||scope)+'</span>';
      h+='<span class="gov-rule-group-count">'+rules.length+' rule'+(rules.length!==1?'s':'')+'</span></div>';
      h+='<div class="gov-rule-group-body'+(collapsed?' collapsed':'')+'" style="'+(collapsed?'max-height:0':'max-height:9999px')+'">';
      // Show tag value chips once at group level for tag-scoped rules
      if(scope.indexOf('tag:')===0){
        var tagKey=scope.substring(4);var tagVals=_collectTagValues(tagKey);
        if(tagVals.length){
          h+='<div class="gov-tag-vals" style="display:flex;flex-wrap:wrap;gap:3px;padding:6px 10px 8px 34px;border-bottom:1px solid var(--border)">';
          h+='<span style="font-size:10px;color:var(--text-muted);margin-right:4px">Values:</span>';
          tagVals.slice(0,16).forEach(function(tv){
            h+='<span class="gov-tag-val-chip" data-val="'+_escHtml(tv.val)+'" style="font-size:10px;background:rgba(139,92,246,.1);border:1px solid rgba(139,92,246,.25);padding:2px 6px;border-radius:3px;color:#a78bfa;cursor:pointer" title="Click to add: '+_escHtml(tv.val)+' ('+tv.ct+' resources)">'+_escHtml(tv.val.length>25?tv.val.substring(0,23)+'..':tv.val)+' <span style="color:var(--text-muted)">'+tv.ct+'</span></span>';
          });
          if(tagVals.length>16) h+='<span style="font-size:10px;color:var(--text-muted)">+'+(tagVals.length-16)+' more</span>';
          h+='</div>';
        }
      }
      rules.forEach(function(d){
        var r=d.rule;var i=d.idx;
        var isValid=true;try{if(r.pattern) new RegExp(r.pattern,'i')}catch(e){isValid=false}
        var mc=countMatches(r);
        h+='<div class="gov-rule-row'+(r.enabled===false?' disabled':'')+((!isValid)?' invalid':'')+'" data-rule-idx="'+i+'">';
        h+='<span class="gov-rule-drag" title="Drag to reorder">⠿</span>';
        h+='<div class="gov-rule-toggle'+(r.enabled!==false?' on':'')+'" data-toggle-idx="'+i+'" title="'+(r.enabled!==false?'Enabled — click to disable':'Disabled — click to enable')+'"></div>';
        h+='<input class="pattern'+((!isValid)?' invalid-pattern':'')+'" type="text" value="'+_escHtml(r.pattern)+'" data-field="pattern" placeholder="regex pattern…" title="'+((!isValid)?'Invalid regex!':'Regex pattern')+'">';
        h+='<select data-field="scope" class="gov-scope-sel" title="Match scope — what this pattern is tested against"><option value="any"'+(r.scope==='any'?' selected':'')+'>Any</option><option value="vpc"'+(r.scope==='vpc'?' selected':'')+'>VPC</option><option value="type"'+(r.scope==='type'?' selected':'')+'>Type</option><option value="name"'+(r.scope==='name'?' selected':'')+'>Name</option>';
        sortedTagScopes.forEach(function(ts){h+='<option value="'+ts+'"'+(r.scope===ts?' selected':'')+'>tag:'+ts.substring(4)+'</option>'});
        h+='</select>';
        h+='<select data-field="tier"><option value="critical"'+(r.tier==='critical'?' selected':'')+'>Critical</option><option value="high"'+(r.tier==='high'?' selected':'')+'>High</option><option value="medium"'+(r.tier==='medium'?' selected':'')+'>Medium</option><option value="low"'+(r.tier==='low'?' selected':'')+'>Low</option></select>';
        h+='<input class="weight" type="number" value="'+r.weight+'" data-field="weight" title="Weight (higher wins)">';
        h+='<span class="gov-rule-match-ct'+(mc>0?' has-matches':'')+'" title="'+(mc<0?'Invalid regex':mc+' resources match')+'">'+((mc<0)?'!':mc)+'</span>';
        h+='<button class="gov-rule-del" data-del-idx="'+i+'" title="Delete rule">✕</button>';
        h+='</div>';
      });
      h+='<div style="padding:4px 0 8px 34px"><button class="gov-rule-add-scope" data-add-scope="'+scope+'" style="background:none;border:1px dashed var(--border);border-radius:3px;padding:3px 10px;font-size:9px;font-family:Segoe UI,system-ui,sans-serif;color:var(--text-muted);cursor:pointer;transition:all .15s">+ Add '+((scopeLabels[scope]||scope).replace(' Rules',''))+' Rule</button></div>';
      h+='</div></div>';
    });
    list.innerHTML=h;
    wireRuleEvents();
  }
  function wireRuleEvents(){
    // Toggle enable/disable
    overlay.querySelectorAll('[data-toggle-idx]').forEach(function(el){
      el.addEventListener('click',function(){
        var idx=parseInt(this.dataset.toggleIdx);
        workRules[idx].enabled=workRules[idx].enabled===false?true:false;
        renderRules();renderPreview();
      });
    });
    // Delete
    overlay.querySelectorAll('[data-del-idx]').forEach(function(btn){
      btn.addEventListener('click',function(){
        var idx=parseInt(this.dataset.delIdx);
        workRules.splice(idx,1);
        renderRules();renderPreview();
      });
    });
    // Group toggle
    overlay.querySelectorAll('[data-toggle-scope]').forEach(function(hdr){
      hdr.addEventListener('click',function(){
        var scope=this.dataset.toggleScope;
        groupCollapsed[scope]=!groupCollapsed[scope];
        renderRules();
      });
    });
    // Add rule per scope
    overlay.querySelectorAll('[data-add-scope]').forEach(function(btn){
      btn.addEventListener('click',function(){
        var sc=this.dataset.addScope;
        var dw=sc==='any'?130:sc.indexOf('tag:')===0?120:sc==='name'?100:sc==='type'?80:60;
        workRules.push({pattern:'',scope:sc,tier:'medium',weight:dw,enabled:true});
        renderRules();renderPreview();
      });
    });
    // Live preview on input change (debounced)
    var previewTimer;
    overlay.querySelectorAll('.gov-rule-row input,.gov-rule-row select').forEach(function(el){
      el.addEventListener('input',function(){
        var row=this.closest('.gov-rule-row');
        var idx=parseInt(row.dataset.ruleIdx);
        var field=this.dataset.field;
        if(field==='pattern'){
          workRules[idx].pattern=this.value;
          var valid=true;try{if(this.value) new RegExp(this.value,'i')}catch(e){valid=false}
          this.classList.toggle('invalid-pattern',!valid);
          row.classList.toggle('invalid',!valid);
          // Update match count inline
          var mc=countMatches(workRules[idx]);
          var mcEl=row.querySelector('.gov-rule-match-ct');
          if(mcEl){mcEl.textContent=mc<0?'!':mc;mcEl.classList.toggle('has-matches',mc>0)}
        } else if(field==='tier'){
          workRules[idx].tier=this.value;
        } else if(field==='weight'){
          workRules[idx].weight=parseInt(this.value)||0;
        }
        clearTimeout(previewTimer);
        previewTimer=setTimeout(renderPreview,300);
      });
      el.addEventListener('change',function(){
        var row=this.closest('.gov-rule-row');
        var idx=parseInt(row.dataset.ruleIdx);
        var field=this.dataset.field;
        if(field==='scope'){
          workRules[idx].scope=this.value;
          groupCollapsed[this.value]=false;
          renderRules();renderPreview();return;
        }
        if(field==='tier') workRules[idx].tier=this.value;
        else if(field==='weight') workRules[idx].weight=parseInt(this.value)||0;
        clearTimeout(previewTimer);
        previewTimer=setTimeout(renderPreview,150);
      });
    });
    // Tag value chip click → populate pattern field
    overlay.querySelectorAll('.gov-tag-val-chip').forEach(function(chip){
      chip.addEventListener('click',function(e){
        e.stopPropagation();
        var val=this.dataset.val;
        var row=this.closest('.gov-rule-row');
        if(row){
          var inp=row.querySelector('input.pattern');
          if(inp){
            var cur=inp.value;
            inp.value=cur?(cur+'|'+val):val;
            inp.dispatchEvent(new Event('input',{bubbles:true}));
          }
        }
      });
    });
  }

  // Build shell
  var h='<div class="gov-rules-panel">';
  h+='<div class="gov-rules-hdr"><h3>Classification Rules</h3>';
  h+='<div class="gov-rules-hdr-actions">';
  h+='<button id="govRulesImport" title="Import rules from JSON">Import</button>';
  h+='<button id="govRulesExport" title="Export rules as JSON">Export</button>';
  h+='<button id="govRulesClose">Close</button>';
  h+='</div></div>';
  h+='<div class="gov-rules-content">';
  h+='<div class="gov-rules-left"><p style="font-size:10px;color:var(--text-muted);margin:0 0 12px;line-height:1.5">Regex patterns matched against scope. Higher weight wins when multiple rules match. Toggle rules on/off to test without deleting.</p>';
  // Tag discovery chips
  var dKeys=Object.keys(disc).sort(function(a,b){return (disc[b].count||0)-(disc[a].count||0)});
  if(dKeys.length){
    h+='<div class="gov-tag-discovery"><div style="font-size:9px;color:var(--text-muted);margin:0 0 6px;text-transform:uppercase;letter-spacing:.5px;font-weight:600">Discovered Tags</div><div class="gov-tag-chips">';
    dKeys.forEach(function(k){
      var d=disc[k];var hasRules=workRules.some(function(r){return r.scope==='tag:'+k});
      h+='<button class="gov-tag-chip'+(hasRules?' active':'')+'" data-tag-key="'+_escHtml(k)+'" title="'+d.count+' resources across '+d.types.join(', ')+'\nSamples: '+d.samples.join(', ')+'">';
      h+=_escHtml(k)+' <span class="ct">'+d.count+'</span></button>';
    });
    h+='</div></div>';
  }
  h+='<div id="govRulesList"></div></div>';
  h+='<div class="gov-rules-right"><h4>Live Preview</h4><div id="govRulesPreview"></div></div>';
  h+='</div>';
  h+='<div class="gov-rules-foot">';
  h+='<button id="govRuleReset">Reset to Defaults</button>';
  h+='<button class="gov-rules-apply" id="govRuleApply">Apply & Re-classify</button>';
  h+='</div></div>';
  overlay.innerHTML=h;
  document.body.appendChild(overlay);
  // Render initial state
  renderRules();
  renderPreview();
  // Shell events
  document.getElementById('govRulesClose').addEventListener('click',function(){overlay.remove()});
  overlay.addEventListener('click',function(e){if(e.target===overlay) overlay.remove()});
  // Tag chip clicks — create starter rule for tag scope
  overlay.querySelectorAll('.gov-tag-chip').forEach(function(chip){
    chip.addEventListener('click',function(){
      var chip=this;var tk=chip.dataset.tagKey;var scope='tag:'+tk;
      var hasRules=workRules.some(function(r){return r.scope===scope});
      if(!hasRules){
        workRules.push({pattern:'',scope:scope,tier:'critical',weight:120,enabled:true});
        groupCollapsed[scope]=false;
        chip.classList.add('active');
      } else {
        groupCollapsed[scope]=!groupCollapsed[scope];
        chip.classList.toggle('active',!groupCollapsed[scope]);
      }
      renderRules();renderPreview();
      if(!groupCollapsed[scope]){
        var grp=overlay.querySelector('[data-scope="'+scope+'"]');
        if(grp) grp.scrollIntoView({behavior:'smooth',block:'start'});
      }
    });
  });
  document.getElementById('govRuleReset').addEventListener('click',function(){
    workRules=structuredClone(_DEFAULT_CLASS_RULES);
    workRules.forEach(function(r){r.enabled=true});
    renderRules();renderPreview();
  });
  document.getElementById('govRulesExport').addEventListener('click',function(){
    readRulesFromDom();
    var json=JSON.stringify(workRules,null,2);
    downloadBlob(new Blob([json],{type:'application/json'}),'classification-rules.json');
    _showToast('Rules exported');
  });
  document.getElementById('govRulesImport').addEventListener('click',function(){
    var inp=document.createElement('input');inp.type='file';inp.accept='.json';
    inp.addEventListener('change',function(){
      if(!this.files[0]) return;
      var reader=new FileReader();
      reader.onload=function(e){
        try{
          var imported=JSON.parse(e.target.result);
          if(!Array.isArray(imported)){_showToast('Invalid rules file','warn');return}
          workRules=imported;
          workRules.forEach(function(r){if(r.enabled===undefined) r.enabled=true});
          renderRules();renderPreview();
          _showToast(imported.length+' rules imported');
        }catch(err){_showToast('Failed to parse JSON','warn')}
      };
      reader.readAsText(this.files[0]);
    });
    inp.click();
  });
  document.getElementById('govRuleApply').addEventListener('click',function(){
    readRulesFromDom();
    _classificationRules=workRules.filter(function(r){return r.pattern});
    _classificationOverrides={};
    runClassificationEngine(_rlCtx);
    _govToolbarTab=null;
    overlay.remove();
    _renderClassificationTab();
    _showToast('Rules applied — '+_classificationData.length+' resources re-classified');
  });
}

// Governance event listeners
document.getElementById('govBtn').addEventListener('click',function(){openUnifiedDash('classification')});

// #endregion UNIFIED DASHBOARD
// #region REPORTS & XLSX
// === REPORT BUILDER ===
function _renderReportsTab(){
  document.getElementById('udashToolbar').style.display='none';
  var body=document.getElementById('udashBody');
  body.classList.add('rpt-layout');
  // Build split-pane layout
  body.innerHTML=
    '<div class="rpt-picker">'+
      '<div class="rpt-meta">'+
        '<label>Report Date</label>'+
        '<input type="date" id="rptDate">'+
        '<label>Report Title</label>'+
        '<input type="text" id="rptTitle" placeholder="Azure Infrastructure Assessment">'+
        '<label>Author</label>'+
        '<input type="text" id="rptAuthor" placeholder="Author name">'+
        '<label>Logo</label>'+
        '<div class="rpt-logo-upload">'+
          '<button class="rpt-logo-btn" id="rptLogoBtn">Upload Logo</button>'+
          '<input type="file" id="rptLogoInput" accept="image/*" style="display:none">'+
          '<button class="rpt-logo-clear" id="rptLogoClear" style="display:none">\u2715</button>'+
          '<div class="rpt-logo-preview" id="rptLogoPreview" style="display:none"></div>'+
        '</div>'+
      '</div>'+
      '<div class="rpt-presets" id="rptPresets"></div>'+
      '<div class="rpt-modules" id="rptModules"></div>'+
    '</div>'+
    '<div class="rpt-preview" id="rptPreview">'+
      '<div class="rpt-preview-frame">'+
        '<div class="rpt-preview-content" id="rptPreviewContent"></div>'+
      '</div>'+
    '</div>';
  // Build footer
  var footer=document.getElementById('udashFooter');
  // Build account dropdown options
  var acctOpts='<option value="all">All Accounts</option>';
  _loadedContexts.forEach(function(c){
    var lbl=c.accountLabel||c.accountId;
    // Only show abbreviated ID if label differs from subscriptionId
    if(lbl!==c.accountId&&/^\d{12}$/.test(c.accountId)){
      acctOpts+='<option value="'+esc(c.accountId)+'">'+esc(lbl)+' ('+c.accountId.slice(-4)+')</option>';
    } else {
      acctOpts+='<option value="'+esc(c.accountId)+'">'+esc(lbl)+'</option>';
    }
  });
  var acctSelect=_loadedContexts.length>1?
    '<select id="rptAccountFilter" style="background:var(--bg-secondary);color:var(--text-primary);border:1px solid var(--border);border-radius:4px;padding:4px 8px;font-size:11px;margin-right:8px">'+acctOpts+'</select>':'';
  footer.innerHTML=
    '<span id="rptFooterStats" style="font-size:11px;color:var(--text-muted);margin-right:auto"></span>'+
    '<button class="udash-btn" id="rptImportReport" style="margin-right:8px;opacity:.8">Load Report</button>'+
    acctSelect+
    '<button class="udash-btn rpt-generate" id="rptExportHTML">Generate HTML Report</button>'+
    '<button class="udash-btn" id="rptExportXLSX">Export XLSX</button>'+
    '<select id="rptDocxTone" style="background:var(--bg-secondary);color:var(--text-primary);border:1px solid var(--border);border-radius:4px;padding:4px 8px;font-size:11px;margin-left:4px">'+
      '<option value="executive">Executive</option><option value="technical">Technical</option>'+
    '</select>'+
    '<button class="udash-btn" id="rptExportDOCX">Export DOCX</button>';
  // Set default values
  document.getElementById('rptDate').value=_rptState.date;
  if(_rptState.title) document.getElementById('rptTitle').value=_rptState.title;
  if(_rptState.author) document.getElementById('rptAuthor').value=_rptState.author;
  if(typeof _updateLogoPreview==='function') _updateLogoPreview();
  // Sync account dropdown with dashboard toggle
  var _syncAcct=document.getElementById('rptAccountFilter');
  if(_syncAcct&&_udashAcctFilter&&_udashAcctFilter!=='all'){
    for(let i=0;i<_syncAcct.options.length;i++){
      if(_syncAcct.options[i].value===_udashAcctFilter){_syncAcct.value=_udashAcctFilter;break}
    }
  }
  // Render dynamic content
  _renderRptPicker();
  _renderRptPreview();
  // Wire input listeners
  document.getElementById('rptTitle').addEventListener('input',function(){_rptState.title=this.value;_rptDebouncedPreview()});
  document.getElementById('rptAuthor').addEventListener('input',function(){_rptState.author=this.value;_rptDebouncedPreview()});
  document.getElementById('rptDate').addEventListener('change',function(){_rptState.date=this.value;_renderRptPreview()});
  var acctEl=document.getElementById('rptAccountFilter');
  if(acctEl) acctEl.addEventListener('change',function(){_renderRptPicker();_renderRptPreview()});
  // Logo handlers
  document.getElementById('rptLogoBtn').addEventListener('click',function(){document.getElementById('rptLogoInput').click()});
  document.getElementById('rptLogoInput').addEventListener('change',function(e){
    var file=e.target.files[0];
    if(!file) return;
    if(file.size>500000){_showToast('Logo too large (max 500 KB)');this.value='';return;}
    var reader=new FileReader();
    reader.onload=function(ev){
      var img=new Image();
      img.onload=function(){
        var ext=file.type.split('/')[1]||'png';
        _rptState.logo={dataUri:ev.target.result,ext:ext,width:img.width,height:img.height};
        _updateLogoPreview();
        _rptDebouncedPreview();
      };
      img.src=ev.target.result;
    };
    reader.readAsDataURL(file);
  });
  document.getElementById('rptLogoClear').addEventListener('click',function(){
    _rptState.logo=null;
    document.getElementById('rptLogoInput').value='';
    _updateLogoPreview();
    _rptDebouncedPreview();
  });
  // Import handler
  document.getElementById('rptImportReport').addEventListener('click',function(){document.getElementById('importReportInput').click()});
  // Export handlers
  document.getElementById('rptExportHTML').addEventListener('click',function(){_generateReport()});
  document.getElementById('rptExportXLSX').addEventListener('click',function(){_generateXlsx()});
  document.getElementById('rptExportDOCX').addEventListener('click',function(){
    var tone=document.getElementById('rptDocxTone').value;
    _generateDocx(tone);
  });
}
function openReportBuilder(){
  openUnifiedDash('reports');
}
function _renderRptPicker(){
  var presetsEl=document.getElementById('rptPresets');
  var presets=[
    {id:'full',label:'Full Assessment',modules:_RPT_MODULES.map(function(m){return m.id})},
    {id:'compliance',label:'Compliance Only',modules:['exec-summary','compliance','iam-review','action-plan']},
    {id:'budr',label:'BUDR Only',modules:['exec-summary','budr','action-plan']},
    {id:'diagram',label:'Diagram + Inventory',modules:['architecture','inventory']}
  ];
  presetsEl.textContent='';
  presets.forEach(function(p){
    var btn=document.createElement('button');
    btn.className='rpt-preset';
    btn.dataset.preset=p.id;
    btn.textContent=p.label;
    btn.addEventListener('click',function(){
      _RPT_MODULES.forEach(function(m){m.enabled=p.modules.indexOf(m.id)>=0});
      _rptState.order=p.modules.slice();
      _renderRptPicker();
      _renderRptPreview();
    });
    presetsEl.appendChild(btn);
  });
  var container=document.getElementById('rptModules');
  var order=_rptState.order||_RPT_MODULES.map(function(m){return m.id});
  var sorted=order.map(function(id){return _RPT_MODULES.find(function(m){return m.id===id})}).filter(Boolean);
  _RPT_MODULES.forEach(function(m){if(order.indexOf(m.id)<0)sorted.push(m)});
  container.textContent='';
  var dragId=null;
  sorted.forEach(function(m){
    var avail=m.available();
    var card=document.createElement('div');
    card.className='rpt-mod-card'+(avail?'':' disabled');
    card.draggable=avail;
    card.dataset.mod=m.id;
    var grip=document.createElement('span');
    grip.className='rm-grip';grip.textContent='\u2630';
    var cb=document.createElement('input');
    cb.className='rm-check';cb.type='checkbox';
    cb.checked=m.enabled&&avail;cb.disabled=!avail;
    var info=document.createElement('div');
    info.className='rm-info';
    var nm=document.createElement('div');nm.className='rm-name';nm.textContent=m.name;
    var ds=document.createElement('div');ds.className='rm-desc';ds.textContent=m.desc();
    info.appendChild(nm);info.appendChild(ds);
    card.appendChild(grip);card.appendChild(cb);card.appendChild(info);
    cb.addEventListener('change',function(){m.enabled=this.checked;_renderRptPreview()});
    if(avail){
      card.addEventListener('dragstart',function(e){
        dragId=this.dataset.mod;this.classList.add('dragging');e.dataTransfer.effectAllowed='move';
      });
      card.addEventListener('dragend',function(){
        this.classList.remove('dragging');
        container.querySelectorAll('.drag-over').forEach(function(el){el.classList.remove('drag-over')});
      });
      card.addEventListener('dragover',function(e){
        e.preventDefault();e.dataTransfer.dropEffect='move';
        container.querySelectorAll('.drag-over').forEach(function(el){el.classList.remove('drag-over')});
        this.classList.add('drag-over');
      });
      card.addEventListener('drop',function(e){
        e.preventDefault();this.classList.remove('drag-over');
        var targetId=this.dataset.mod;
        if(!dragId||dragId===targetId)return;
        var cards=Array.from(container.querySelectorAll('.rpt-mod-card'));
        var newOrder=cards.map(function(c){return c.dataset.mod});
        var fromIdx=newOrder.indexOf(dragId);
        var toIdx=newOrder.indexOf(targetId);
        newOrder.splice(fromIdx,1);
        newOrder.splice(toIdx,0,dragId);
        _rptState.order=newOrder;
        _renderRptPicker();
        _renderRptPreview();
      });
    }
    container.appendChild(card);
  });
}
function _renderRptPreview(){
  var container=document.getElementById('rptPreviewContent');
  var enabled=_rptEnabledModules();
  if(!enabled.length){
    container.textContent='';
    var p=document.createElement('p');
    p.style.cssText='color:var(--text-muted);text-align:center;padding:60px 20px;font-family:Segoe UI,system-ui,sans-serif';
    p.textContent='Toggle sections on the left to build your report';
    container.appendChild(p);
    return;
  }
  var html='<style>'+_rptCSS()+_rptInteractiveCSS()+'</style>';
  html+=_rptBuildHeader();
  html+=_rptBuildTOC(enabled);
  html+=_rptBuildSections(enabled);
  html+=_rptBuildFooter();
  var wrapper=document.createElement('div');
  wrapper.innerHTML=html;
  container.textContent='';
  container.appendChild(wrapper);
  if(typeof _rptUpdateFooterStats==='function') _rptUpdateFooterStats();
  /* Wire up anchor jump links to scroll within preview panel */
  var scrollBox=document.getElementById('rptPreview');
  wrapper.addEventListener('click',function(e){
    var link=e.target.closest('a[href^="#"]');
    if(!link) return;
    var hash=link.getAttribute('href');
    if(!hash||hash.length<2) return;
    e.preventDefault();
    var target=wrapper.querySelector(hash)||wrapper.querySelector('[id="'+hash.slice(1)+'"]');
    if(!target||!scrollBox) return;
    var boxTop=scrollBox.getBoundingClientRect().top;
    var elTop=target.getBoundingClientRect().top;
    scrollBox.scrollTop+=elTop-boxTop-12;
  });
  /* ── Wire up interactive JS for preview (innerHTML doesn't execute <script>) ── */
  _rptInitInteractive(wrapper);
}

function _rptInitInteractive(root){
  var SEV_ORD={CRITICAL:0,HIGH:1,MEDIUM:2,LOW:3};
  var TIER_ORD={at_risk:0,partial:1,protected:2};
  var STRAT_ORD={hot:0,warm:1,pilot:2,cold:3};

  function rptPaginate(tableId){
    var wrap=root.querySelector('#'+CSS.escape(tableId))||document.getElementById(tableId);
    if(!wrap)return;
    var table=wrap.querySelector('table');
    if(!table)return;
    var tbody=table.querySelector(':scope > tbody');
    if(!tbody)return;
    var allRows=[].slice.call(tbody.querySelectorAll(':scope > tr:not(.rpt-ctrl-detail)'));
    var visible=allRows.filter(function(r){return r.dataset.filtered!=='0'});
    var perPage=parseInt(wrap.dataset.perPage)||50;
    if(perPage<=0)perPage=visible.length||1;
    var totalPages=Math.max(1,Math.ceil(visible.length/perPage));
    var page=Math.min(parseInt(wrap.dataset.page)||1,totalPages);
    wrap.dataset.page=page;
    var start=(page-1)*perPage,end=start+perPage;
    allRows.forEach(function(r){r.style.display='none'});
    visible.forEach(function(r,i){r.style.display=(i>=start&&i<end)?'':'none'});
    /* detail rows follow their control row visibility */
    table.querySelectorAll('.rpt-ctrl-detail').forEach(function(d){
      var p=d.previousElementSibling;
      d.style.display=(p&&p.style.display!=='none'&&p.classList.contains('expanded'))?'table-row':'none';
    });
    var bar=wrap.querySelector('.rpt-pagination');
    if(!bar)return;
    var info=bar.querySelector('.rpt-page-info');
    if(info)info.textContent='Page '+page+' of '+totalPages+' ('+visible.length+' rows)';
    var prev=bar.querySelector('.rpt-page-prev');
    var next=bar.querySelector('.rpt-page-next');
    if(prev)prev.disabled=(page<=1);
    if(next)next.disabled=(page>=totalPages);
  }

  function rptFilter(tableId){
    var wrap=root.querySelector('#'+CSS.escape(tableId))||document.getElementById(tableId);
    if(!wrap)return;
    var pills=wrap.querySelectorAll('.rpt-pill');
    var active={};
    pills.forEach(function(p){
      if(!p.classList.contains('active'))return;
      var attr=p.dataset.attr;
      if(!active[attr])active[attr]=[];
      active[attr].push(p.dataset.val.toUpperCase());
    });
    var si=wrap.querySelector('.rpt-search');
    var query=si?si.value.toLowerCase():'';
    var table=wrap.querySelector('table');
    if(!table)return;
    var tbody=table.querySelector(':scope > tbody');
    if(!tbody)return;
    var rows=tbody.querySelectorAll(':scope > tr:not(.rpt-ctrl-detail)');
    var shown=0,attrCounts={},total=rows.length;
    rows.forEach(function(tr){
      var vis=true;
      Object.keys(active).forEach(function(attr){
        var raw=(tr.dataset[attr]||'').toUpperCase();
        if(attr==='account'&&raw.indexOf('|')!==-1){
          var parts=raw.split('|');
          var match=parts.some(function(p){return active[attr].indexOf(p)!==-1});
          if(!match)vis=false;
        }else{
          if(active[attr].indexOf(raw)===-1)vis=false;
        }
      });
      if(vis&&query){if(tr.textContent.toLowerCase().indexOf(query)===-1)vis=false}
      tr.dataset.filtered=vis?'1':'0';
      if(vis)shown++;
      ['sev','tier','fw','strategy','account'].forEach(function(attr){
        var v=(tr.dataset[attr]||'').toUpperCase();
        if(attr==='account'&&v.indexOf('|')!==-1){
          v.split('|').forEach(function(p){if(p){if(!attrCounts[p])attrCounts[p]=0;if(vis)attrCounts[p]++}});
        }else{
          if(v){if(!attrCounts[v])attrCounts[v]=0;if(vis)attrCounts[v]++}
        }
      });
    });
    var badge=wrap.querySelector('.rpt-row-count');
    if(badge)badge.textContent=shown+' of '+total;
    pills.forEach(function(p){
      var ct=p.querySelector('.rpt-pill-ct');
      if(!ct)return;
      var val=p.dataset.val.toUpperCase();
      ct.textContent=attrCounts[val]||0;
    });
    wrap.dataset.page='1';
    rptPaginate(tableId);
  }

  function rptSort(th){
    var table=th.closest('table');
    if(!table)return;
    var idx=[].indexOf.call(th.parentElement.children,th);
    var type=th.dataset.sortType||'text';
    var dir=th.classList.contains('rpt-sort-asc')?'desc':th.classList.contains('rpt-sort-desc')?'none':'asc';
    th.parentElement.querySelectorAll('th').forEach(function(h){h.classList.remove('rpt-sort-asc','rpt-sort-desc')});
    if(dir!=='none')th.classList.add('rpt-sort-'+dir);
    var tbody=table.querySelector('tbody');
    var rows=[].slice.call(tbody.querySelectorAll(':scope > tr:not(.rpt-ctrl-detail)'));
    if(dir==='none')return;
    rows.sort(function(a,b){
      var av=a.children[idx]?a.children[idx].textContent.trim():'';
      var bv=b.children[idx]?b.children[idx].textContent.trim():'';
      var cmp=0;
      if(type==='severity')cmp=(SEV_ORD[av]===undefined?9:SEV_ORD[av])-(SEV_ORD[bv]===undefined?9:SEV_ORD[bv]);
      else if(type==='tier')cmp=(TIER_ORD[av]===undefined?9:TIER_ORD[av])-(TIER_ORD[bv]===undefined?9:TIER_ORD[bv]);
      else if(type==='strategy')cmp=(STRAT_ORD[av.toLowerCase()]===undefined?9:STRAT_ORD[av.toLowerCase()])-(STRAT_ORD[bv.toLowerCase()]===undefined?9:STRAT_ORD[bv.toLowerCase()]);
      else cmp=av.localeCompare(bv);
      return dir==='desc'?-cmp:cmp;
    });
    /* Collect control-detail pairs before moving */
    var pairs=rows.map(function(r){
      var detail=r.nextElementSibling;
      return {row:r,detail:(detail&&detail.classList.contains('rpt-ctrl-detail'))?detail:null};
    });
    pairs.forEach(function(p){
      tbody.appendChild(p.row);
      if(p.detail)tbody.appendChild(p.detail);
    });
    var wrap=th.closest('.rpt-table-wrap');
    if(wrap){wrap.dataset.page='1';rptPaginate(wrap.id)}
  }

  /* Event delegation on the preview wrapper */
  var _searchTimer=0;
  root.addEventListener('click',function(e){
    /* Pill toggle */
    var pill=e.target.closest('.rpt-pill');
    if(pill){pill.classList.toggle('active');var w=pill.closest('.rpt-table-wrap');if(w)rptFilter(w.id);return}
    /* Clear */
    if(e.target.classList.contains('rpt-clear')){
      var w=e.target.closest('.rpt-table-wrap');
      if(!w)return;w.querySelectorAll('.rpt-pill.active').forEach(function(p){p.classList.remove('active')});
      var si=w.querySelector('.rpt-search');if(si)si.value='';rptFilter(w.id);return;
    }
    /* Sortable header */
    var th=e.target.closest('th.rpt-sortable');
    if(th){rptSort(th);return}
    /* Pagination */
    var btn=e.target.closest('.rpt-page-prev,.rpt-page-next');
    if(btn){
      var w=btn.closest('.rpt-table-wrap');if(!w)return;
      var pg=parseInt(w.dataset.page)||1;
      w.dataset.page=btn.classList.contains('rpt-page-prev')?Math.max(1,pg-1):pg+1;
      rptPaginate(w.id);return;
    }
    /* Group expand/collapse */
    var ctrlRow=e.target.closest('.rpt-ctrl-row');
    if(ctrlRow){
      ctrlRow.classList.toggle('expanded');
      var nx=ctrlRow.nextElementSibling;
      while(nx&&nx.classList.contains('rpt-ctrl-detail')){
        nx.classList.toggle('show');
        nx.style.display=nx.classList.contains('show')?'table-row':'none';
        nx=nx.nextElementSibling;
      }
      return;
    }
    /* Expand all */
    if(e.target.classList.contains('rpt-expand-all')){
      var w=e.target.closest('.rpt-table-wrap');
      if(!w)return;
      var anyCollapsed=w.querySelector('.rpt-ctrl-row:not(.expanded)');
      var expand=!!anyCollapsed;
      w.querySelectorAll('.rpt-ctrl-row').forEach(function(r){r.classList.toggle('expanded',expand)});
      w.querySelectorAll('.rpt-ctrl-detail').forEach(function(d){d.classList.toggle('show',expand);d.style.display=expand?'table-row':'none'});
      e.target.textContent=expand?'Collapse All':'Expand All';
      return;
    }
    /* Resource link — scroll within report preview */
    var resLink=e.target.closest('.rpt-res-link');
    if(resLink){
      e.preventDefault();
      var href=resLink.getAttribute('href');
      if(href&&href.charAt(0)==='#'){
        var target=root.querySelector(href)||document.querySelector(href);
        if(target){target.scrollIntoView({behavior:'smooth',block:'center'});target.style.outline='2px solid #67e8f9';setTimeout(function(){target.style.outline=''},2000)}
      }
      return;
    }
    /* Section toggle */
    var tog=e.target.closest('.rpt-section-toggle');
    if(tog){
      tog.classList.toggle('collapsed');
      var body=tog.parentElement.querySelector('.rpt-section-body');
      if(body)body.classList.toggle('collapsed');
      return;
    }
  });
  root.addEventListener('change',function(e){
    if(!e.target.classList.contains('rpt-per-page'))return;
    var w=e.target.closest('.rpt-table-wrap');if(!w)return;
    w.dataset.perPage=e.target.value;w.dataset.page='1';rptPaginate(w.id);
  });
  root.addEventListener('input',function(e){
    if(!e.target.classList.contains('rpt-search'))return;
    clearTimeout(_searchTimer);
    var w=e.target.closest('.rpt-table-wrap');
    _searchTimer=setTimeout(function(){if(w)rptFilter(w.id)},300);
  });
  /* Init: paginate all tables */
  root.querySelectorAll('.rpt-table-wrap').forEach(function(w){
    if(!w.dataset.perPage)w.dataset.perPage='50';
    w.dataset.page='1';
    rptFilter(w.id);
  });
}

function _rptEnabledModules(){
  var order=_rptState.order||_RPT_MODULES.map(function(m){return m.id});
  return order.filter(function(id){
    var m=_RPT_MODULES.find(function(x){return x.id===id});
    return m&&m.enabled&&m.available();
  });
}

function _rptBuildHeader(){
  var title=esc(_rptState.title||'Azure Infrastructure Assessment');
  var author=esc(_rptState.author||'');
  var date=esc(_rptState.date||'');
  var sub=[];
  if(author) sub.push(author);
  if(date) sub.push(date);
  var logoHtml='';
  if(_rptState.logo&&_rptState.logo.dataUri){
    logoHtml='<div class="rpt-logo"><img src="'+_rptState.logo.dataUri+'" alt="Logo" style="max-height:60px;max-width:200px;object-fit:contain"></div>';
  }
  return '<div class="rpt-header">'+logoHtml+'<h1>'+title+'</h1>'+
    (sub.length?'<div class="subtitle">'+sub.join(' &mdash; ')+'</div>':'')+
    '</div>';
}

function _rptBuildTOC(enabled){
  var h='<div class="rpt-toc"><h2>Table of Contents</h2>';
  enabled.forEach(function(id,i){
    var m=_RPT_MODULES.find(function(x){return x.id===id});
    h+='<a href="#s-'+esc(id)+'">'+(i+1)+'. '+esc(m.name)+'</a>';
  });
  h+='</div>';
  return h;
}

function _rptBuildSections(enabled){
  var h='';
  enabled.forEach(function(id){
    var m=_RPT_MODULES.find(function(x){return x.id===id});
    try{h+=m.render(_rlCtx,{});}catch(e){
      h+='<section class="rpt-section" id="s-'+esc(id)+'"><h2>'+esc(m.name)+'</h2>';
      h+='<p>Error rendering section: '+esc(e.message)+'</p></section>';
    }
  });
  return h;
}

function _rptBuildFooter(){
  var ts=new Date().toLocaleString();
  return '<div class="rpt-footer-bar">Generated by Azure Mapper &mdash; '+esc(ts)+'</div>';
}

function _rptSlugify(str){
  return String(str||'report').toLowerCase()
    .replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,60);
}

function _rptEmbedDataBlob(enabled){
  var acctFilter=_rptGetAccountFilter();
  var findings=_rptFilterByAccount(_complianceFindings||[],acctFilter);
  var budrA=_rptFilterByAccount(_budrAssessments||[],acctFilter);
  var budrF=_rptFilterByAccount(_budrFindings||[],acctFilter);
  if(!_inventoryData.length&&_rlCtx)_buildInventoryData();
  var inv=_rptFilterByAccount(_inventoryData||[],acctFilter).map(function(r){
    var c={};Object.keys(r).forEach(function(k){if(k!=='_raw'&&k!=='_related')c[k]=r[k]});return c;
  });
  var contexts=_loadedContexts.map(function(c){
    return {accountId:c.accountId,accountLabel:c.accountLabel,region:c.region};
  });
  // IAM review data — serialize with date strings instead of Date objects
  var iamData=_iamReviewData.map(function(r){
    var c={};for(let k in r){if(k==='_raw')continue;c[k]=r[k]}
    if(c.created instanceof Date)c.created=c.created.toISOString().split('T')[0];
    if(c.lastUsed instanceof Date)c.lastUsed=c.lastUsed.toISOString().split('T')[0];
    return c;
  });
  var blob={_rptFormat:'azuremapper-report',_rptVersion:'1.0',
    title:_rptState.title||'Azure Infrastructure Assessment',
    author:_rptState.author||'',date:_rptState.date||'',
    enabledModules:enabled,contexts:contexts,
    findings:findings,budrAssessments:budrA,budrFindings:budrF,inventoryData:inv,
    iamReviewData:iamData,appRegistry:_appRegistry};
  return '\n<script type="application/json" id="rpt-embedded-data">\n'+JSON.stringify(blob)+'\n<\/script>\n';
}

function _rptFullHTML(enabled,pngDataUrl){
  var title=esc(_rptState.title||'Azure Infrastructure Assessment');
  var html='<!DOCTYPE html>\n<html lang="en">\n<head>\n';
  html+='<meta charset="UTF-8">\n';
  html+='<meta name="viewport" content="width=device-width,initial-scale=1.0">\n';
  html+='<title>'+title+'</title>\n';
  var lt=!document.body.classList.contains('dark-mode');
  var expBg=lt?'#ffffff':'#0f172a';var expTx=lt?'#1e293b':'#e2e8f0';
  html+='<style>\nbody{margin:0;padding:24px 40px;background:'+expBg+';color:'+expTx+';font-family:"Segoe UI",system-ui,sans-serif;line-height:1.6}\n'+_rptCSS()+'\n'+_rptInteractiveCSS()+'\n</style>\n';
  html+='</head>\n<body>\n';
  html+=_rptBuildHeader();
  html+=_rptBuildTOC(enabled);
  html+=_rptBuildSections(enabled);
  html+=_rptBuildFooter();
  html+='<button id="rpt-back-top" title="Back to top" aria-label="Scroll to top">&#9650;</button>\n';
  html+=_rptInteractiveJS()+'\n';
  html+=_rptEmbedDataBlob(enabled);
  html+='\n</body>\n</html>';
  if(pngDataUrl) html=_rptSwapArchPng(html,pngDataUrl);
  return html;
}

function _rptSwapArchPng(html,pngDataUrl){
  return html.replace(
    /src="data:image\/svg\+xml;base64,[^"]+"/,
    'src="'+pngDataUrl+'"'
  );
}

function _rptCapturePNG(){
  return new Promise(function(resolve){
    var svgEl=document.getElementById('mapSvg');
    var root=svgEl?svgEl.querySelector('.map-root'):null;
    if(!root){resolve(null);return;}
    try{
      var clone=svgEl.cloneNode(true);
      _rptPrepClone(clone,root);
      var xml=new XMLSerializer().serializeToString(clone);
      var blob=new Blob([xml],{type:'image/svg+xml;charset=utf-8'});
      var url=URL.createObjectURL(blob);
      var bb=root.getBBox();var pad=40;
      var w=bb.width+pad*2;var h=bb.height+pad*2;
      var scale=Math.min(2,8000/w,8000/h);
      var img=new Image();
      img.onload=function(){
        var c=document.createElement('canvas');
        c.width=Math.round(w*scale);c.height=Math.round(h*scale);
        var cx=c.getContext('2d');cx.drawImage(img,0,0,c.width,c.height);
        URL.revokeObjectURL(url);resolve(c.toDataURL('image/png'));
      };
      img.onerror=function(){URL.revokeObjectURL(url);resolve(null);};
      img.src=url;
    }catch(e){resolve(null);}
  });
}

function _rptPrepClone(clone,root){
  var cloneRoot=clone.querySelector('.map-root');
  if(cloneRoot) cloneRoot.removeAttribute('transform');
  var lt=document.documentElement.dataset.theme==='light';
  // Propagate theme attribute so [data-theme="light"] CSS rules apply in standalone SVG
  if(lt) clone.setAttribute('data-theme','light');
  var bb=root.getBBox();var pad=40;
  clone.setAttribute('viewBox',
    (bb.x-pad)+' '+(bb.y-pad)+' '+(bb.width+pad*2)+' '+(bb.height+pad*2));
  clone.setAttribute('width',bb.width+pad*2);
  clone.setAttribute('height',bb.height+pad*2);
  var bgRect=document.createElementNS('http://www.w3.org/2000/svg','rect');
  bgRect.setAttribute('x',bb.x-pad);bgRect.setAttribute('y',bb.y-pad);
  bgRect.setAttribute('width',bb.width+pad*2);
  bgRect.setAttribute('height',bb.height+pad*2);
  bgRect.setAttribute('fill',lt?'#f1f5f9':'#0a0e17');
  clone.insertBefore(bgRect,clone.firstChild);
  var styles=_rptCollectStyles();
  if(styles){
    var defs=clone.querySelector('defs')||
      clone.insertBefore(document.createElementNS('http://www.w3.org/2000/svg','defs'),clone.firstChild);
    var styleEl=document.createElementNS('http://www.w3.org/2000/svg','style');
    styleEl.textContent=styles;defs.appendChild(styleEl);
  }
}

async function _generateReport(){
  var btn=document.getElementById('rptExportHTML');
  btn.textContent='Generating...';btn.disabled=true;
  try{
    var enabled=_rptEnabledModules();
    if(!enabled.length){_showToast('No sections enabled');return;}
    var hasArch=enabled.indexOf('architecture')>=0;
    var pngDataUrl=hasArch?await _rptCapturePNG():null;
    var html=_rptFullHTML(enabled,pngDataUrl);
    var slug=_rptSlugify(_rptState.title);
    var date=_rptState.date||new Date().toISOString().slice(0,10);
    var filename=slug+'-'+date+'.html';
    downloadBlob(new Blob([html],{type:'text/html'}),filename);
  }catch(e){
    console.error('Report generation failed:',e);
    _showToast('Report generation failed: '+e.message);
  }finally{
    btn.textContent='Generate HTML Report';btn.disabled=false;
  }
}
// (rptExportHTML listener now wired in _renderReportsTab)

// === XLSX EXPORT (SheetJS) ===
var _sheetJSLoaded=false;
function _loadSheetJS(){
  if(_sheetJSLoaded&&window.XLSX) return Promise.resolve(window.XLSX);
  function _tryLoad(src){
    return new Promise(function(resolve,reject){
      var s=document.createElement('script');
      s.src=src;
      s.onload=function(){_sheetJSLoaded=true;resolve(window.XLSX)};
      s.onerror=function(){reject(new Error('Failed to load: '+src))};
      document.head.appendChild(s);
    });
  }
  return _tryLoad('libs/xlsx.bundle.min.js').catch(function(){
    return Promise.reject(new Error('SheetJS (libs/xlsx.bundle.min.js) not found. XLSX export requires this library in the app directory.'));
  });
}

const _XLSX_COLORS={
  headerBg:'1B2A4A',headerFg:'FFFFFF',
  sectionBg:'E2E8F0',sectionFg:'1E293B',
  critFg:'991B1B',critBg:'FEE2E2',
  highFg:'9A3412',highBg:'FFEDD5',
  medFg:'92400E',medBg:'FEF3C7',
  lowFg:'1E40AF',lowBg:'DBEAFE',
  protectedFg:'065F46',protectedBg:'D1FAE5',
  partialFg:'92400E',partialBg:'FEF3C7',
  atRiskFg:'991B1B',atRiskBg:'FEE2E2',
  effortLowFg:'065F46',effortLowBg:'DCFCE7',
  effortMedFg:'92400E',effortMedBg:'FEF3C7',
  effortHighFg:'991B1B',effortHighBg:'FEE2E2',
  stripeBg:'F8FAFC',borderClr:'D1D5DB',
  tierCritBg:'FEE2E2',tierCritFg:'991B1B',
  tierHighBg:'FED7AA',tierHighFg:'9A3412',
  tierMedBg:'FEF3C7',tierMedFg:'92400E',
  tierLowBg:'DBEAFE',tierLowFg:'1E40AF',
  titleFg:'0F172A',subtitleFg:'64748B',
  labelFg:'475569',valueFg:'0F172A',
  linkFg:'2563EB'
};

function _xlsxBorder(weight){
  weight=weight||'thin';
  var clr={rgb:_XLSX_COLORS.borderClr};
  return {top:{style:weight,color:clr},bottom:{style:weight,color:clr},
    left:{style:weight,color:clr},right:{style:weight,color:clr}};
}

function _xlsxHeaderStyle(){
  return {font:{bold:true,color:{rgb:_XLSX_COLORS.headerFg},name:'Calibri',sz:11},
    fill:{fgColor:{rgb:_XLSX_COLORS.headerBg}},
    alignment:{horizontal:'center',vertical:'center',wrapText:true},
    border:_xlsxBorder('thin')};
}

function _xlsxSevStyle(sev){
  var fg={CRITICAL:_XLSX_COLORS.critFg,HIGH:_XLSX_COLORS.highFg,MEDIUM:_XLSX_COLORS.medFg,LOW:_XLSX_COLORS.lowFg};
  var bg={CRITICAL:_XLSX_COLORS.critBg,HIGH:_XLSX_COLORS.highBg,MEDIUM:_XLSX_COLORS.medBg,LOW:_XLSX_COLORS.lowBg};
  return {font:{bold:true,color:{rgb:fg[sev]||'000000'},name:'Calibri',sz:10},
    fill:{fgColor:{rgb:bg[sev]||'FFFFFF'}},
    alignment:{horizontal:'center',vertical:'center'},
    border:_xlsxBorder()};
}

function _xlsxTierStyle(tier){
  var norm=String(tier).toLowerCase().replace(/ /g,'_');
  var map={
    critical:{fg:_XLSX_COLORS.tierCritFg,bg:_XLSX_COLORS.tierCritBg},
    high:{fg:_XLSX_COLORS.tierHighFg,bg:_XLSX_COLORS.tierHighBg},
    medium:{fg:_XLSX_COLORS.tierMedFg,bg:_XLSX_COLORS.tierMedBg},
    low:{fg:_XLSX_COLORS.tierLowFg,bg:_XLSX_COLORS.tierLowBg},
    protected:{fg:_XLSX_COLORS.protectedFg,bg:_XLSX_COLORS.protectedBg},
    partial:{fg:_XLSX_COLORS.partialFg,bg:_XLSX_COLORS.partialBg},
    at_risk:{fg:_XLSX_COLORS.atRiskFg,bg:_XLSX_COLORS.atRiskBg}
  };
  var m=map[norm]||{fg:'000000',bg:'FFFFFF'};
  return {font:{bold:true,color:{rgb:m.fg},name:'Calibri',sz:10},
    fill:{fgColor:{rgb:m.bg}},alignment:{horizontal:'center',vertical:'center'},
    border:_xlsxBorder()};
}

function _xlsxEffortStyle(effort){
  var norm=String(effort).toLowerCase().replace(/ /g,'');
  var map={
    low:{fg:_XLSX_COLORS.effortLowFg,bg:_XLSX_COLORS.effortLowBg},
    med:{fg:_XLSX_COLORS.effortMedFg,bg:_XLSX_COLORS.effortMedBg},
    high:{fg:_XLSX_COLORS.effortHighFg,bg:_XLSX_COLORS.effortHighBg}
  };
  var m=map[norm]||{fg:'000000',bg:'FFFFFF'};
  return {font:{color:{rgb:m.fg},name:'Calibri',sz:10},
    fill:{fgColor:{rgb:m.bg}},alignment:{horizontal:'center',vertical:'center'},
    border:_xlsxBorder()};
}

function _xlsxCellStyle(isStripe){
  var s={font:{name:'Calibri',sz:10,color:{rgb:'1E293B'}},
    alignment:{vertical:'center',wrapText:true},
    border:_xlsxBorder()};
  if(isStripe) s.fill={fgColor:{rgb:_XLSX_COLORS.stripeBg}};
  return s;
}

function _xlsxAutoWidth(ws,data,minWidths){
  if(!data||!data.length) return;
  var colWidths=[];
  data.forEach(function(row,ri){
    row.forEach(function(cell,i){
      var len=String(cell!=null?cell:'').length;
      if(ri===0) len=Math.max(len+4,12);
      else len=len+3;
      colWidths[i]=Math.max(colWidths[i]||8,len);
    });
  });
  if(minWidths){
    minWidths.forEach(function(mw,i){if(mw&&i<colWidths.length) colWidths[i]=Math.max(colWidths[i],mw)});
  }
  ws['!cols']=colWidths.map(function(w){return {wch:Math.min(w,60)}});
}

function _xlsxAddSheet(wb,name,headers,rows,opts){
  opts=opts||{};
  var data=[headers].concat(rows);
  var ws=XLSX.utils.aoa_to_sheet(data);
  _xlsxAutoWidth(ws,data,opts.minWidths);
  var hdrStyle=_xlsxHeaderStyle();
  headers.forEach(function(_,i){
    var addr=XLSX.utils.encode_cell({r:0,c:i});
    if(ws[addr]) ws[addr].s=hdrStyle;
  });
  // Style severity column — colored text + tinted fill (cache by value)
  if(typeof opts.sevCol==='number'){
    var _sevCache={};
    for(let r=1;r<data.length;r++){
      var addr=XLSX.utils.encode_cell({r:r,c:opts.sevCol});
      if(ws[addr]){
        var val=String(ws[addr].v||'');
        if(val){
          if(!_sevCache[val]) _sevCache[val]=_xlsxSevStyle(val);
          ws[addr].s=_sevCache[val];
        }
      }
    }
  }
  // Style tier column (cache by value)
  if(typeof opts.tierCol==='number'){
    var _tierCache={};
    for(let r=1;r<data.length;r++){
      var addr=XLSX.utils.encode_cell({r:r,c:opts.tierCol});
      if(ws[addr]){
        var val=String(ws[addr].v||'');
        if(val){
          if(!_tierCache[val]) _tierCache[val]=_xlsxTierStyle(val);
          ws[addr].s=_tierCache[val];
        }
      }
    }
  }
  // Style effort column (cache by value)
  if(typeof opts.effortCol==='number'){
    var _effortCache={};
    for(let r=1;r<data.length;r++){
      var addr=XLSX.utils.encode_cell({r:r,c:opts.effortCol});
      if(ws[addr]){
        var val=String(ws[addr].v||'');
        if(val){
          if(!_effortCache[val]) _effortCache[val]=_xlsxEffortStyle(val);
          ws[addr].s=_effortCache[val];
        }
      }
    }
  }
  // Apply base cell styles + row striping to all other cells
  // Cache common styles to reduce object allocation (~35k+ cells in large reports)
  var _cellPlain=_xlsxCellStyle(false);
  var _cellStripe=_xlsxCellStyle(true);
  var _border=_xlsxBorder();
  for(let r=1;r<data.length;r++){
    var sty=r%2===0?_cellStripe:_cellPlain;
    for(let c=0;c<headers.length;c++){
      var addr=XLSX.utils.encode_cell({r:r,c:c});
      if(ws[addr]&&!ws[addr].s) ws[addr].s=sty;
      else if(ws[addr]&&ws[addr].s&&!ws[addr].s.border) ws[addr].s.border=_border;
    }
  }
  // Apply hyperlinks (opts.links = [{r:rowIdx, c:colIdx, url:string}])
  if(opts.links&&opts.links.length){
    var linkStyle={font:{name:'Calibri',sz:10,color:{rgb:_XLSX_COLORS.linkFg},underline:true},
      alignment:{vertical:'center',wrapText:true},border:_xlsxBorder()};
    var linkStripeStyle={font:{name:'Calibri',sz:10,color:{rgb:_XLSX_COLORS.linkFg},underline:true},
      fill:{fgColor:{rgb:_XLSX_COLORS.stripeBg}},alignment:{vertical:'center',wrapText:true},border:_xlsxBorder()};
    opts.links.forEach(function(lk){
      var addr=XLSX.utils.encode_cell({r:lk.r+1,c:lk.c}); // +1 for header row
      if(ws[addr]&&lk.url){
        ws[addr].l={Target:lk.url,Tooltip:'Open in Azure Portal'};
        ws[addr].s=(lk.r+1)%2===0?linkStripeStyle:linkStyle;
      }
    });
  }
  // Row height for header
  ws['!rows']=[{hpx:28}];
  // Autofilter — enables sort/filter dropdowns
  var lastCol=XLSX.utils.encode_col(headers.length-1);
  var lastRow=data.length;
  ws['!autofilter']={ref:'A1:'+lastCol+lastRow};
  // Freeze panes — freeze header row
  ws['!views']=[{state:'frozen',ySplit:1}];
  XLSX.utils.book_append_sheet(wb,ws,name);
}

function _xlsxSummarySection(ws,row,label,cols){
  var addr=XLSX.utils.encode_cell({r:row,c:0});
  ws[addr]={v:label,t:'s',s:{font:{bold:true,sz:12,color:{rgb:_XLSX_COLORS.headerFg},name:'Calibri'},
    fill:{fgColor:{rgb:_XLSX_COLORS.headerBg}},alignment:{vertical:'center'},
    border:_xlsxBorder()}};
  for(let c=1;c<cols;c++){
    var a2=XLSX.utils.encode_cell({r:row,c:c});
    ws[a2]={v:'',t:'s',s:{fill:{fgColor:{rgb:_XLSX_COLORS.headerBg}},border:_xlsxBorder()}};
  }
  if(cols>1) ws['!merges']=(ws['!merges']||[]).concat([{s:{r:row,c:0},e:{r:row,c:cols-1}}]);
}

function _xlsxSummaryRow(ws,row,label,value,cols){
  var lAddr=XLSX.utils.encode_cell({r:row,c:0});
  ws[lAddr]={v:label,t:'s',s:{font:{bold:true,sz:10,color:{rgb:_XLSX_COLORS.labelFg},name:'Calibri'},
    alignment:{vertical:'center'},border:_xlsxBorder()}};
  var vAddr=XLSX.utils.encode_cell({r:row,c:1});
  var vType=typeof value==='number'?'n':'s';
  ws[vAddr]={v:value,t:vType,s:{font:{sz:10,color:{rgb:_XLSX_COLORS.valueFg},name:'Calibri'},
    alignment:{vertical:'center'},border:_xlsxBorder()}};
  if(cols>2){
    for(let c=2;c<cols;c++){
      var a=XLSX.utils.encode_cell({r:row,c:c});
      ws[a]={v:'',t:'s',s:{border:_xlsxBorder()}};
    }
  }
}

function _rptBuildXlsxSummary(wb, preFilteredFindings){
  var c=_rlCtx;
  var cols=4;
  var ws={};
  var r=0;
  var hasLogo=!!_rptState.logo;
  // When logo present, offset title/subtitle to col 1 so logo gets col 0
  var tCol=hasLogo?1:0;
  // Title row — merged across columns (skip col 0 when logo present)
  var titleAddr=XLSX.utils.encode_cell({r:r,c:tCol});
  ws[titleAddr]={v:_rptState.title||'Azure Infrastructure Assessment',t:'s',
    s:{font:{bold:true,sz:18,color:{rgb:_XLSX_COLORS.titleFg},name:'Calibri'},
      alignment:{vertical:'center'},border:{bottom:{style:'medium',color:{rgb:_XLSX_COLORS.headerBg}}}}};
  for(let cc=tCol+1;cc<cols;cc++){
    ws[XLSX.utils.encode_cell({r:r,c:cc})]={v:'',t:'s',
      s:{border:{bottom:{style:'medium',color:{rgb:_XLSX_COLORS.headerBg}}}}};
  }
  if(hasLogo){
    // Empty styled cell under logo so bottom border is consistent
    ws[XLSX.utils.encode_cell({r:r,c:0})]={v:'',t:'s',
      s:{border:{bottom:{style:'medium',color:{rgb:_XLSX_COLORS.headerBg}}}}};
  }
  ws['!merges']=[{s:{r:0,c:tCol},e:{r:0,c:cols-1}}];
  // Row height: taller when logo present (logo is 0.5" = 36pt)
  ws['!rows']=[{hpx:hasLogo?42:30}];
  r++;
  // Subtitle row
  var subParts=[];
  if(_rptState.author) subParts.push('Prepared by '+_rptState.author);
  subParts.push(_rptState.date||new Date().toISOString().slice(0,10));
  var subAddr=XLSX.utils.encode_cell({r:r,c:tCol});
  ws[subAddr]={v:subParts.join('  |  '),t:'s',
    s:{font:{sz:10,color:{rgb:_XLSX_COLORS.subtitleFg},name:'Calibri',italic:true},
      alignment:{vertical:'center'}}};
  for(let cc=tCol+1;cc<cols;cc++) ws[XLSX.utils.encode_cell({r:r,c:cc})]={v:'',t:'s'};
  ws['!merges'].push({s:{r:r,c:tCol},e:{r:r,c:cols-1}});
  r+=2;
  // Infrastructure Overview section
  if(c){
    _xlsxSummarySection(ws,r,'INFRASTRUCTURE OVERVIEW',cols);r++;
    var counts=[['VNets',(c.vpcs||[]).length],['Subnets',(c.subnets||[]).length],
      ['Virtual Machines',(c.instances||[]).length],['SQL Databases',(c.rdsInstances||[]).length],
      ['Load Balancers',(c.albs||[]).length],['Container Instances',(c.ecsServices||[]).length],
      ['Function Apps',(c.lambdaFns||[]).length],['NSGs',(c.sgs||[]).length]];
    // Two-column layout: resource pairs side by side
    for(let i=0;i<counts.length;i+=2){
      var lAddr=XLSX.utils.encode_cell({r:r,c:0});
      ws[lAddr]={v:counts[i][0],t:'s',s:{font:{bold:true,sz:10,color:{rgb:_XLSX_COLORS.labelFg},name:'Calibri'},border:_xlsxBorder(),alignment:{vertical:'center'}}};
      var vAddr=XLSX.utils.encode_cell({r:r,c:1});
      ws[vAddr]={v:counts[i][1],t:'n',s:{font:{bold:true,sz:11,color:{rgb:_XLSX_COLORS.valueFg},name:'Calibri'},border:_xlsxBorder(),alignment:{horizontal:'center',vertical:'center'}}};
      if(i+1<counts.length){
        var l2=XLSX.utils.encode_cell({r:r,c:2});
        ws[l2]={v:counts[i+1][0],t:'s',s:{font:{bold:true,sz:10,color:{rgb:_XLSX_COLORS.labelFg},name:'Calibri'},border:_xlsxBorder(),alignment:{vertical:'center'}}};
        var v2=XLSX.utils.encode_cell({r:r,c:3});
        ws[v2]={v:counts[i+1][1],t:'n',s:{font:{bold:true,sz:11,color:{rgb:_XLSX_COLORS.valueFg},name:'Calibri'},border:_xlsxBorder(),alignment:{horizontal:'center',vertical:'center'}}};
      }
      r++;
    }
    // Region row
    var regions=c._regions?Array.from(c._regions):[];
    if(regions.length){
      var regLabel=XLSX.utils.encode_cell({r:r,c:0});
      ws[regLabel]={v:'Regions',t:'s',s:{font:{bold:true,sz:10,color:{rgb:_XLSX_COLORS.labelFg},name:'Calibri'},border:_xlsxBorder(),alignment:{vertical:'center'}}};
      var regVal=XLSX.utils.encode_cell({r:r,c:1});
      ws[regVal]={v:regions.join(', '),t:'s',s:{font:{sz:10,color:{rgb:_XLSX_COLORS.valueFg},name:'Calibri'},border:_xlsxBorder(),alignment:{vertical:'center'}}};
      ws['!merges'].push({s:{r:r,c:1},e:{r:r,c:cols-1}});
      r++;
    }
    r++;
  }
  // Compliance Findings section (use pre-filtered if provided, otherwise account-filter)
  var _sumFindings=preFilteredFindings||_rptFilterByAccount(_complianceFindings||[],_rptGetAccountFilter());
  if(_sumFindings.length){
    _xlsxSummarySection(ws,r,'COMPLIANCE FINDINGS',cols);r++;
    _xlsxSummaryRow(ws,r,'Total Findings',_sumFindings.length,cols);r++;
    var sevs={CRITICAL:0,HIGH:0,MEDIUM:0,LOW:0};
    _sumFindings.forEach(function(f){sevs[f.severity]=(sevs[f.severity]||0)+1});
    ['CRITICAL','HIGH','MEDIUM','LOW'].forEach(function(s){
      var addr=XLSX.utils.encode_cell({r:r,c:0});
      ws[addr]={v:s,t:'s',s:_xlsxSevStyle(s)};
      var vAddr=XLSX.utils.encode_cell({r:r,c:1});
      ws[vAddr]={v:sevs[s],t:'n',s:{font:{bold:true,sz:11,color:{rgb:'0F172A'},name:'Calibri'},
        alignment:{horizontal:'center',vertical:'center'},border:_xlsxBorder()}};
      for(let cc=2;cc<cols;cc++) ws[XLSX.utils.encode_cell({r:r,c:cc})]={v:'',t:'s',s:{border:_xlsxBorder()}};
      r++;
    });
    // Framework breakdown
    r++;
    var fws=[].concat(Object.keys(_FW_LABELS));
    var fwHdr=XLSX.utils.encode_cell({r:r,c:0});
    ws[fwHdr]={v:'Framework',t:'s',s:_xlsxHeaderStyle()};
    ws[XLSX.utils.encode_cell({r:r,c:1})]={v:'Findings',t:'s',s:_xlsxHeaderStyle()};
    ws[XLSX.utils.encode_cell({r:r,c:2})]={v:'Critical',t:'s',s:_xlsxHeaderStyle()};
    ws[XLSX.utils.encode_cell({r:r,c:3})]={v:'High',t:'s',s:_xlsxHeaderStyle()};
    r++;
    fws.forEach(function(fw){
      var ff=_sumFindings.filter(function(f){return f.framework===fw});
      if(!ff.length) return;
      var isStripe=(r%2===0);
      ws[XLSX.utils.encode_cell({r:r,c:0})]={v:_FW_LABELS[fw]||fw,t:'s',s:_xlsxCellStyle(isStripe)};
      ws[XLSX.utils.encode_cell({r:r,c:1})]={v:ff.length,t:'n',s:{font:{bold:true,sz:10,name:'Calibri'},alignment:{horizontal:'center'},border:_xlsxBorder(),fill:isStripe?{fgColor:{rgb:_XLSX_COLORS.stripeBg}}:undefined}};
      var critCt=ff.filter(function(f){return f.severity==='CRITICAL'}).length;
      var highCt=ff.filter(function(f){return f.severity==='HIGH'}).length;
      ws[XLSX.utils.encode_cell({r:r,c:2})]={v:critCt,t:'n',s:critCt>0?_xlsxSevStyle('CRITICAL'):_xlsxCellStyle(isStripe)};
      ws[XLSX.utils.encode_cell({r:r,c:3})]={v:highCt,t:'n',s:highCt>0?_xlsxSevStyle('HIGH'):_xlsxCellStyle(isStripe)};
      r++;
    });
    r++;
  }
  // BUDR section (account-filtered to match detail sheets)
  var _sumBudr=_rptFilterByAccount(_budrAssessments||[],_rptGetAccountFilter());
  if(_sumBudr.length){
    _xlsxSummarySection(ws,r,'BACKUP & DISASTER RECOVERY',cols);r++;
    _xlsxSummaryRow(ws,r,'Total Assessments',_sumBudr.length,cols);r++;
    var tc={protected:0,partial:0,at_risk:0};
    _sumBudr.forEach(function(a){if(a.profile&&tc[a.profile.tier]!==undefined)tc[a.profile.tier]++});
    [['Protected',tc.protected||0,'protected'],['Partial',tc.partial||0,'partial'],['At Risk',tc.at_risk||0,'at_risk']].forEach(function(t){
      ws[XLSX.utils.encode_cell({r:r,c:0})]={v:t[0],t:'s',s:_xlsxTierStyle(t[2])};
      ws[XLSX.utils.encode_cell({r:r,c:1})]={v:t[1],t:'n',s:{font:{bold:true,sz:11,name:'Calibri'},alignment:{horizontal:'center'},border:_xlsxBorder()}};
      for(let cc=2;cc<cols;cc++) ws[XLSX.utils.encode_cell({r:r,c:cc})]={v:'',t:'s',s:{border:_xlsxBorder()}};
      r++;
    });
  }
  // Set sheet range
  ws['!ref']=XLSX.utils.encode_range({s:{r:0,c:0},e:{r:r,c:cols-1}});
  // Column widths: narrow col A for logo when present, otherwise standard
  ws['!cols']=hasLogo?[{wch:14},{wch:24},{wch:16},{wch:16}]:[{wch:24},{wch:16},{wch:16},{wch:16}];
  // !rows already set above (taller when logo present)
  XLSX.utils.book_append_sheet(wb,ws,'Summary');
}

function _rptBuildXlsxCompliance(wb, preFiltered){
  var f=preFiltered||_rptFilterByAccount(_complianceFindings||[], _rptGetAccountFilter());
  if(!f||!f.length) return;
  var headers=['Account','Region','Priority','Effort','Severity','Framework','Control','CKV','Resource','Finding','Remediation'];
  var sorted=f.slice().sort(function(a,b){
    var ta=_classifyTier(a),tb=_classifyTier(b);
    if(ta!==tb) return(_PRIORITY_ORDER[ta]||9)-(_PRIORITY_ORDER[tb]||9);
    return (_SEV_ORDER[a.severity]||9)-(_SEV_ORDER[b.severity]||9);
  });
  var rows=sorted.map(function(x){
    var tier=_classifyTier(x);
    var effort=_EFFORT_LABELS[_getEffort(x)]||'Med';
    return [_rptAccountLabel(x._subscriptionId)||'',x._region||'',_TIER_META[tier].name,effort,x.severity,_FW_LABELS[x.framework]||x.framework||'',x.control,
      x.ckv||'',x.resourceName||x.resource,x.message,x.remediation];
  });
  _xlsxAddSheet(wb,'Compliance',headers,rows,{sevCol:4,tierCol:2,effortCol:3,
    minWidths:[16,14,14,14,12,20,14,14,28,40,40]});
}

function _rptBuildXlsxBUDR(wb){
  var filteredBudr=_rptFilterByAccount(_budrAssessments||[], _rptGetAccountFilter());
  if(!filteredBudr.length) return;
  var headers=['Account','Region','VPC','Resource Type','Resource ID','Name','DR Tier','RTO','RPO','Backup Signals'];
  var tierOrder={at_risk:0,partial:1,protected:2};
  var sorted=filteredBudr.slice().sort(function(a,b){
    return (tierOrder[a.profile?a.profile.tier:'']||9)-(tierOrder[b.profile?b.profile.tier:'']||9);
  });
  var rows=sorted.map(function(a){
    var tier=a.profile?a.profile.tier:'unknown';
    var rto=a.profile?a.profile.rto:'N/A';
    var rpo=a.profile?a.profile.rpo:'N/A';
    var sigs=a.signals?Object.keys(a.signals).map(function(k){return k+': '+a.signals[k]}).join(', '):'';
    return [_rptAccountLabel(a._subscriptionId||a.account)||'',a.region||'',a.vpcId||'',a.type,a.id,a.name||'',tier,rto,rpo,sigs];
  });
  var budrLinks=[];
  rows.forEach(function(row,ri){
    var region=row[1],type=row[3],id=row[4];
    var url=_azurePortalUrl(type,id,region);
    if(url) budrLinks.push({r:ri,c:4,url:url});
  });
  _xlsxAddSheet(wb,'BUDR',headers,rows,{tierCol:6,
    minWidths:[16,14,16,16,24,20,14,10,10,40],links:budrLinks});
}

function _rptBuildXlsxInventory(wb){
  var c=_rlCtx;
  if(!c) return;
  var acctFilter=_rptGetAccountFilter();
  var headers=['Account','Region','VPC','Type','ID','Name','Configuration','State / AZ','Details'];
  var rows=[];
  var links=[];
  function _af(arr){
    if(!acctFilter||acctFilter==='all') return arr||[];
    return (arr||[]).filter(function(r){return (r._subscriptionId||'')===acctFilter});
  }
  // Shared lookups
  var _invSubVpc={};(c.subnets||[]).forEach(function(s){if(s.SubnetId)_invSubVpc[s.SubnetId]=s.VpcId||''});
  var _invInstVpc={};(c.instances||[]).forEach(function(i){if(i.InstanceId)_invInstVpc[i.InstanceId]=i.VpcId||_invSubVpc[i.SubnetId]||''});
  function _a(r){return _rptAccountLabel(r._subscriptionId)||''}
  function _r(r){return r._region||''}
  _af(c.vpcs).forEach(function(v){
    rows.push([_a(v),_r(v),v.VpcId,'VPC',v.VpcId,_rptTagName(v),v.CidrBlock,v.State||'available','']);
  });
  _af(c.subnets).forEach(function(s){
    var pub=c.pubSubs&&c.pubSubs.has(s.SubnetId)?'Public':'Private';
    rows.push([_a(s),_r(s),s.VpcId||'','Subnet',s.SubnetId,_rptTagName(s),s.CidrBlock,s.AvailabilityZone,pub]);
  });
  _af(c.instances).forEach(function(i){
    var state=i.State?i.State.Name:'';
    var az=i.Placement?i.Placement.AvailabilityZone:'';
    rows.push([_a(i),_r(i),i.VpcId||_invSubVpc[i.SubnetId]||'','VM',i.InstanceId,_rptTagName(i),i.InstanceType,state,az]);
  });
  _af(c.rdsInstances).forEach(function(d){
    var vpc=(d.DBSubnetGroup&&d.DBSubnetGroup.VpcId)||'';
    rows.push([_a(d),_r(d),vpc,'SQL',d.DBInstanceIdentifier,d.DBInstanceIdentifier,d.Engine+' / '+d.DBInstanceClass,d.MultiAZ?'Multi-AZ':'Single-AZ',d.StorageType||'']);
  });
  _af(c.albs).forEach(function(a){
    rows.push([_a(a),_r(a),a.VpcId||'','ALB',a.LoadBalancerName||'',a.LoadBalancerName,a.Type||'application',a.Scheme||'',(a.AvailabilityZones||[]).length+' AZs']);
  });
  _af(c.ecsServices).forEach(function(s){
    var nc=s.networkConfiguration&&s.networkConfiguration.awsvpcConfiguration;
    var sid=nc&&nc.subnets&&nc.subnets[0]?nc.subnets[0]:'';
    rows.push([_a(s),_r(s),sid?_invSubVpc[sid]||'':'','Container',s.serviceName||'',s.serviceName,s.launchType||'FARGATE',s.runningCount+'/'+s.desiredCount+' tasks','']);
  });
  _af(c.lambdaFns).forEach(function(fn){
    var vpc=(fn.VpcConfig&&fn.VpcConfig.VpcId)||'';
    rows.push([_a(fn),_r(fn),vpc,'FuncApp',fn.FunctionName||'',fn.FunctionName,fn.Runtime||'',fn.MemorySize+'MB / '+fn.Timeout+'s','']);
  });
  _af(c.sgs).forEach(function(sg){
    var rules=(sg.IpPermissions||[]).length+' inbound, '+(sg.IpPermissionsEgress||[]).length+' outbound';
    rows.push([_a(sg),_r(sg),sg.VpcId||'','Security Group',sg.GroupId,sg.GroupName||_rptTagName(sg),rules,'','']);
  });
  _af(c.nacls).forEach(function(n){
    var entries=(n.Entries||[]).length+' rules';
    rows.push([_a(n),_r(n),n.VpcId||'','Subnet NSG',n.NetworkAclId,_rptTagName(n),entries,n.IsDefault?'Default':'Custom','']);
  });
  _af(c.rts).forEach(function(rt){
    var routes=(rt.Routes||[]).length+' routes';
    rows.push([_a(rt),_r(rt),rt.VpcId||'','Route Table',rt.RouteTableId,_rptTagName(rt),routes,'','']);
  });
  _af(c.volumes).forEach(function(v){
    var att=(v.Attachments||[])[0];
    var vpc=att?_invInstVpc[att.InstanceId]||'':'';
    rows.push([_a(v),_r(v),vpc,'EBS Volume',v.VolumeId,_rptTagName(v),v.VolumeType+' / '+v.Size+'GB',v.State||'',att?att.Device||'':'unattached']);
  });
  _af(c.snapshots).forEach(function(s){
    rows.push([_a(s),_r(s),'','EBS Snapshot',s.SnapshotId,_rptTagName(s),s.VolumeSize+'GB',s.State||'',s.Description||'']);
  });
  _af(c.enis).forEach(function(e){
    rows.push([_a(e),_r(e),e.VpcId||'','ENI',e.NetworkInterfaceId,_rptTagName(e),e.InterfaceType||'',e.Status||'',e.PrivateIpAddress||'']);
  });
  _af(c.igws).forEach(function(g){
    var att=(g.Attachments||[])[0];
    rows.push([_a(g),_r(g),att?att.VpcId||'':'','IGW',g.InternetGatewayId,_rptTagName(g),'',att?att.State||'':'detached','']);
  });
  _af(c.nats).forEach(function(n){
    rows.push([_a(n),_r(n),n.VpcId||'','NAT Gateway',n.NatGatewayId,_rptTagName(n),'',n.State||'',n.SubnetId||'']);
  });
  _af(c.vpces).forEach(function(ep){
    rows.push([_a(ep),_r(ep),ep.VpcId||'','VPC Endpoint',ep.VpcEndpointId,ep.ServiceName||'',ep.VpcEndpointType||'',ep.State||'','']);
  });
  _af(c.ecacheClusters).forEach(function(ec){
    rows.push([_a(ec),_r(ec),ec.VpcId||'','ElastiCache',ec.CacheClusterId,ec.CacheClusterId,ec.Engine+' / '+ec.CacheNodeType,ec.CacheClusterStatus||'',ec.NumCacheNodes+' nodes']);
  });
  _af(c.redshiftClusters).forEach(function(rs){
    rows.push([_a(rs),_r(rs),rs.VpcId||'','Redshift',rs.ClusterIdentifier,rs.ClusterIdentifier,rs.NodeType,rs.ClusterStatus||'',rs.NumberOfNodes+' nodes']);
  });
  _af(c.s3bk).forEach(function(b){
    rows.push([_a(b),_r(b),'','Storage Account',b.Name,b.Name,'','',b.CreationDate||'']);
  });
  (c.peerings||[]).forEach(function(p){
    var req=p.RequesterVpcInfo||{};var acc=p.AccepterVpcInfo||{};
    rows.push([_a(p),_r(p),req.VpcId||'','VPC Peering',p.VpcPeeringConnectionId,_rptTagName(p),req.CidrBlock+' <> '+acc.CidrBlock,p.Status?p.Status.Code:'','']);
  });
  (c.zones||[]).forEach(function(z){
    var recs=c.recsByZone&&c.recsByZone[z.Id]?c.recsByZone[z.Id].length:z.ResourceRecordSetCount||0;
    var vis=z.Config&&z.Config.PrivateZone?'private':'public';
    rows.push([_a(z),_r(z),'','Route 53',z.Id,z.Name||z.Id,recs+' records',vis,'']);
  });
  (c.wafAcls||[]).forEach(function(w){
    var ruleCount=(w.Rules||[]).length;
    rows.push([_a(w),_r(w),'','WAF',w.Id||w.Name,w.Name||w.Id||'',ruleCount+' rules','','']);
  });
  (c.cfDistributions||[]).forEach(function(cf){
    rows.push([_a(cf),_r(cf),'','CloudFront',cf.Id,cf.DomainName||cf.Id,cf.Status||'','','']);
  });
  (c.vpns||[]).forEach(function(v){
    rows.push([_a(v),_r(v),'','VPN',v.VpnConnectionId,_rptTagName(v)||(v.VpnConnectionId),v.Type||'',v.State||'','']);
  });
  (c.tgwAttachments||[]).forEach(function(t){
    rows.push([_a(t),_r(t),t.VpcId||'','TGW Attachment',t.TransitGatewayAttachmentId||t.TransitGatewayId||'',_rptTagName(t)||'',t.ResourceType||'',t.State||'','']);
  });
  (c.tgs||[]).forEach(function(tg){
    rows.push([_a(tg),_r(tg),tg.VpcId||'','Target Group',tg.TargetGroupName||'',tg.TargetGroupName||'',tg.Protocol+':'+tg.Port,tg.TargetType||'','']);
  });
  if(!rows.length) return;
  // Replace empty cells with "-" so XLSX has no blank gaps
  rows.forEach(function(row){for(let i=0;i<row.length;i++){if(row[i]==='')row[i]='-'}});
  // Generate hyperlinks for ID column (4) and VPC column (2)
  rows.forEach(function(row,ri){
    var region=row[1],type=row[3],id=row[4],vpc=row[2];
    var idUrl=_azurePortalUrl(type,id,region);
    if(idUrl) links.push({r:ri,c:4,url:idUrl});
    if(vpc&&vpc!=='-'){var vUrl=_azurePortalUrl('VPC',vpc,region);if(vUrl) links.push({r:ri,c:2,url:vUrl})}
  });
  _xlsxAddSheet(wb,'Inventory',headers,rows,{minWidths:[16,14,16,16,24,22,22,18,14],links:links});
}

function _rptBuildXlsxActionPlan(wb, preFiltered){
  var all=preFiltered||_rptFilterByAccount((_complianceFindings||[]).concat(_budrFindings||[]), _rptGetAccountFilter());
  if(!all.length) return;
  var headers=['Account','Region','Priority','Severity','Effort','Framework','Control','Resource','Finding',
    'Remediation','Owner','Target Date','Status'];
  var tiers=_getTierGroups(all);
  var rows=[];
  _PRIORITY_KEYS.forEach(function(t){
    var rgs=tiers[t];
    if(!rgs) return;
    var tierName=_TIER_META[t].name;
    rgs.forEach(function(rg){
      rg.findings.forEach(function(f){
        var effort=_EFFORT_MAP[f.control]||'med';
        rows.push([_rptAccountLabel(f._subscriptionId)||'',f._region||'',tierName,f.severity,_EFFORT_LABELS[effort]||effort,
          _FW_LABELS[f.framework]||f.framework||'',f.control,
          f.resourceName||f.resource,f.message,f.remediation,'','','Open']);
      });
    });
  });
  _xlsxAddSheet(wb,'Action Plan',headers,rows,{sevCol:3,tierCol:2,effortCol:4,
    minWidths:[16,14,14,12,14,20,14,28,40,40,14,14,12]});
}

// Inject company logo into XLSX zip (Summary sheet, top-right corner)
async function _xlsxInjectLogo(zip){
  var logo=_rptState.logo;
  if(!logo) return;
  try{
    var base64=logo.dataUri.split(',')[1];
    var binary=atob(base64);
    var bytes=new Uint8Array(binary.length);
    for(let i=0;i<binary.length;i++) bytes[i]=binary.charCodeAt(i);
    var ext=logo.ext==='jpeg'?'png':logo.ext; // normalize
    zip.file('xl/media/image1.'+ext,bytes);
    // Register image content type
    var ctXml=await zip.file('[Content_Types].xml').async('string');
    if(ctXml.indexOf('Extension="'+ext+'"')===-1){
      ctXml=ctXml.replace('</Types>','<Default Extension="'+ext+'" ContentType="image/'+ext+'"/></Types>');
    }
    // Register drawing content type
    if(ctXml.indexOf('/drawing+xml')===-1){
      ctXml=ctXml.replace('</Types>','<Override PartName="/xl/drawings/drawing1.xml" ContentType="application/vnd.openxmlformats-officedocument.drawing+xml"/></Types>');
    }
    zip.file('[Content_Types].xml',ctXml);
    // Fixed size: 1" x 0.5" in EMUs (1 inch = 914400 EMUs), anchored at A1
    var w=914400,h=457200;
    var aspect=logo.width/logo.height;
    if(aspect>2){h=w/aspect;}else if(aspect<2){w=h*aspect;}
    // Drawing XML — oneCellAnchor at A1 (col 0, row 0) with padding
    var drawXml='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'+
      '<xdr:wsDr xmlns:xdr="http://schemas.openxmlformats.org/drawingml/2006/spreadsheetDrawing" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">'+
      '<xdr:oneCellAnchor>'+
      '<xdr:from><xdr:col>0</xdr:col><xdr:colOff>76200</xdr:colOff><xdr:row>0</xdr:row><xdr:rowOff>38100</xdr:rowOff></xdr:from>'+
      '<xdr:ext cx="'+Math.round(w)+'" cy="'+Math.round(h)+'"/>'+
      '<xdr:pic><xdr:nvPicPr><xdr:cNvPr id="2" name="Logo"/><xdr:cNvPicPr><a:picLocks noChangeAspect="1"/></xdr:cNvPicPr></xdr:nvPicPr>'+
      '<xdr:blipFill><a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId1"/>'+
      '<a:stretch><a:fillRect/></a:stretch></xdr:blipFill>'+
      '<xdr:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="'+Math.round(w)+'" cy="'+Math.round(h)+'"/></a:xfrm>'+
      '<a:prstGeom prst="rect"><a:avLst/></a:prstGeom></xdr:spPr>'+
      '</xdr:pic><xdr:clientData/></xdr:oneCellAnchor></xdr:wsDr>';
    zip.file('xl/drawings/drawing1.xml',drawXml);
    // Drawing rels — link image
    zip.file('xl/drawings/_rels/drawing1.xml.rels',
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'+
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'+
      '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/image" Target="../media/image1.'+ext+'"/>'+
      '</Relationships>');
    // Sheet1 rels — link drawing
    var wsRelsPath='xl/worksheets/_rels/sheet1.xml.rels';
    var wsRels;
    try{wsRels=await zip.file(wsRelsPath).async('string');}catch(e){wsRels=null;}
    if(!wsRels) wsRels='<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"></Relationships>';
    wsRels=wsRels.replace('</Relationships>',
      '<Relationship Id="rId99" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/drawing" Target="../drawings/drawing1.xml"/></Relationships>');
    zip.file(wsRelsPath,wsRels);
    // Add <drawing> ref to sheet1.xml
    var s1=await zip.file('xl/worksheets/sheet1.xml').async('string');
    if(s1.indexOf('<drawing')===-1){
      s1=s1.replace('</worksheet>','<drawing r:id="rId99" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/></worksheet>');
      zip.file('xl/worksheets/sheet1.xml',s1);
    }
  }catch(e){console.warn('Logo injection failed:',e);}
}

// Post-process XLSX zip: logo injection + freeze panes
async function _xlsxPostProcess(wbBuf,sheetNames){
  var zip=await JSZip.loadAsync(wbBuf);
  // Logo on Summary sheet
  if(_rptState.logo) await _xlsxInjectLogo(zip);
  // Freeze panes on data sheets
  for(let i=0;i<sheetNames.length;i++){
    var path='xl/worksheets/sheet'+(i+1)+'.xml';
    var f=zip.file(path);
    if(!f) continue;
    var xml=await f.async('string');
    // Skip Summary sheet (index 0) — it's a dashboard, not a data table
    if(i===0) continue;
    // Inject pane into sheetView to freeze row 1
    var paneXml='<pane ySplit="1" topLeftCell="A2" activePane="bottomLeft" state="frozen"/>';
    xml=xml.replace(
      '<sheetView workbookViewId="0"/>',
      '<sheetView tabSelected="'+(i===1?'1':'0')+'" workbookViewId="0">'+paneXml+'</sheetView>'
    );
    xml=xml.replace(
      /<sheetView workbookViewId="0"><\/sheetView>/,
      '<sheetView tabSelected="'+(i===1?'1':'0')+'" workbookViewId="0">'+paneXml+'</sheetView>'
    );
    zip.file(path,xml);
  }
  var result=await zip.generateAsync({type:'blob',mimeType:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'});
  zip=null;
  return result;
}

// === COMPLIANCE-ONLY XLSX (SheetJS) ===
async function _exportComplianceXlsx(opts){
  _showToast('Generating XLSX...');
  try{
    var XLSX=await _loadSheetJS();
    var wb=XLSX.utils.book_new();
    // Filter findings by selected frameworks/severities/muted
    var view=_buildComplianceView({frameworks:opts.frameworks,severities:opts.severities,includeMuted:opts.includeMuted});
    var filtered=view.filtered;
    _rptBuildXlsxSummary(wb, filtered);
    _rptBuildXlsxCompliance(wb, filtered);
    _rptBuildXlsxActionPlan(wb, filtered);
    if(wb.SheetNames.length<1){_showToast('No data to export','error');return}
    var date=new Date().toISOString().slice(0,10);
    var fname='compliance-report-'+date+'.xlsx';
    var sheetNames=wb.SheetNames.slice();
    var wbBuf=XLSX.write(wb,{type:'array',bookType:'xlsx'});
    wb=null;
    await new Promise(function(r){setTimeout(r,0)});
    var blob=await _xlsxPostProcess(wbBuf,sheetNames);
    wbBuf=null;
    downloadBlob(blob,fname);
    blob=null;
    _showToast('Compliance report exported');
  }catch(e){
    console.error('Compliance XLSX export failed:',e);
    _showToast('Export failed: '+e.message,'error');
  }
}

// === FULL ASSESSMENT EXPORTS ===
async function _exportFullXlsx(){
  _showToast('Generating full assessment XLSX...');
  try{
    var XLSX=await _loadSheetJS();
    var wb=XLSX.utils.book_new();
    _rptBuildXlsxSummary(wb);
    _rptBuildXlsxClassification(wb);
    _rptBuildXlsxAppSummary(wb);
    _rptBuildXlsxIAMReview(wb);
    _rptBuildXlsxCompliance(wb);
    _rptBuildXlsxFirewall(wb);
    _rptBuildXlsxBUDR(wb);
    _rptBuildXlsxActionPlan(wb);
    _rptBuildXlsxInventory(wb);
    if(wb.SheetNames.length<2){_showToast('No data to export','error');return}
    var date=new Date().toISOString().slice(0,10);
    var fname='full-assessment-'+date+'.xlsx';
    var sheetNames=wb.SheetNames.slice();
    var wbBuf=XLSX.write(wb,{type:'array',bookType:'xlsx'});
    wb=null;
    await new Promise(function(r){setTimeout(r,0)});
    var blob=await _xlsxPostProcess(wbBuf,sheetNames);
    wbBuf=null;
    downloadBlob(blob,fname);
    blob=null;
    _showToast('Full assessment exported');
  }catch(e){
    console.error('Full XLSX export failed:',e);
    _showToast('Export failed: '+e.message,'error');
  }
}

function _exportFullHTML(){
  var esc=function(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')};
  var now=new Date().toISOString().slice(0,19).replace('T',' ');
  var c=_rlCtx;
  // Collect tabs with data
  var tabs=[];
  if(c) tabs.push({id:'summary',label:'Summary'});
  if(!_classificationData.length&&c) runClassificationEngine(c);
  if(_classificationData&&_classificationData.length) tabs.push({id:'classification',label:'Classification'});
  if(typeof _autoDiscoverApps==='function') _autoDiscoverApps();
  if(_appRegistry&&_appRegistry.length) tabs.push({id:'appsummary',label:'App Summary'});
  if(_iamReviewData&&_iamReviewData.length) tabs.push({id:'iam',label:'IAM Review'});
  if(_complianceFindings&&_complianceFindings.length) tabs.push({id:'compliance',label:'Compliance'});
  if(c&&((c.sgs&&c.sgs.length)||(c.nacls&&c.nacls.length)||(c.rts&&c.rts.length))) tabs.push({id:'firewall',label:'Firewall'});
  if(_budrAssessments&&_budrAssessments.length) tabs.push({id:'budr',label:'BUDR'});
  if(_inventoryData&&_inventoryData.length) tabs.push({id:'inventory',label:'Inventory'});
  if(!tabs.length){_showToast('No data to export','error');return}
  // Helper: build table HTML from headers + rows
  function tbl(id,headers,rows,opts){
    opts=opts||{};
    var s='<div class="tbl-wrap"><input type="text" class="tbl-search" data-table="'+id+'" placeholder="Search..."/>';
    s+='<table id="'+id+'"><thead><tr>';
    headers.forEach(function(h,i){s+='<th data-col="'+i+'">'+esc(h)+'</th>'});
    s+='</tr></thead><tbody>';
    rows.forEach(function(row,ri){
      s+='<tr class="'+(ri%2===0?'':'stripe')+'">';
      row.forEach(function(cell,ci){
        var cls='';var style='';
        if(opts.sevCol===ci){var sv=String(cell).toUpperCase();if(sevClr[sv])style=' style="color:'+sevClr[sv].fg+';background:'+sevClr[sv].bg+';font-weight:700;text-align:center"'}
        if(opts.tierCol===ci){var tv=String(cell).toLowerCase();if(tierClr[tv])style=' style="color:'+tierClr[tv].fg+';background:'+tierClr[tv].bg+';font-weight:700;text-align:center"'}
        s+='<td'+style+'>'+esc(cell)+'</td>';
      });
      s+='</tr>';
    });
    if(!rows.length) s+='<tr><td colspan="'+headers.length+'" class="empty">No data</td></tr>';
    s+='</tbody></table></div>';
    return s;
  }
  var sevClr={CRITICAL:{fg:'#991b1b',bg:'#fecaca'},HIGH:{fg:'#9a3412',bg:'#ffedd5'},MEDIUM:{fg:'#92400e',bg:'#fef3c7'},LOW:{fg:'#1e40af',bg:'#dbeafe'}};
  var tierClr={critical:{fg:'#991b1b',bg:'#fecaca'},high:{fg:'#9a3412',bg:'#fed7aa'},medium:{fg:'#92400e',bg:'#fef3c7'},low:{fg:'#1e40af',bg:'#dbeafe'},protected:{fg:'#065f46',bg:'#d1fae5'},partial:{fg:'#92400e',bg:'#fef3c7'},at_risk:{fg:'#991b1b',bg:'#fecaca'}};
  var h='<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>Azure Infrastructure Assessment</title><style>';
  h+='*{margin:0;padding:0;box-sizing:border-box}';
  h+='body{font-family:"Segoe UI",system-ui,-apple-system,sans-serif;color:#1e293b;background:#f8fafc}';
  h+='.header{background:#1B2A4A;color:#fff;padding:20px 32px}';
  h+='.header h1{font-size:22px;font-weight:700}.header .sub{font-size:12px;color:#94a3b8;margin-top:4px}';
  h+='.tab-bar{display:flex;background:#0f172a;padding:0 32px;gap:0;overflow-x:auto}';
  h+='.tab-btn{padding:10px 18px;color:#94a3b8;font-size:12px;font-weight:600;cursor:pointer;border:none;background:none;border-bottom:2px solid transparent;white-space:nowrap;font-family:inherit}';
  h+='.tab-btn:hover{color:#e2e8f0}.tab-btn.active{color:#38bdf8;border-bottom-color:#38bdf8}';
  h+='.tab-content{display:none;padding:24px 32px;max-width:1400px;margin:0 auto}.tab-content.active{display:block}';
  h+='.stat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:12px;margin-bottom:24px}';
  h+='.stat-card{background:#fff;border:1px solid #e2e8f0;border-radius:8px;padding:16px;text-align:center}';
  h+='.stat-card .val{font-size:28px;font-weight:800;color:#0f172a}.stat-card .lbl{font-size:11px;color:#64748b;text-transform:uppercase;letter-spacing:0.5px;margin-top:4px}';
  h+='.tbl-wrap{margin-top:16px}.tbl-search{width:100%;max-width:320px;padding:8px 12px;border:1px solid #e2e8f0;border-radius:6px;font-size:12px;margin-bottom:10px;font-family:inherit}';
  h+='table{width:100%;border-collapse:collapse;font-size:11px;background:#fff;border:1px solid #e2e8f0;border-radius:8px;overflow:hidden}';
  h+='thead th{background:#f1f5f9;color:#475569;font-weight:600;text-transform:uppercase;font-size:10px;letter-spacing:0.5px;padding:10px 12px;text-align:left;border-bottom:2px solid #e2e8f0;cursor:pointer;user-select:none}';
  h+='thead th:hover{background:#e2e8f0}';
  h+='tbody td{padding:7px 12px;border-bottom:1px solid #f1f5f9;vertical-align:top}';
  h+='tr.stripe td{background:#f8fafc}.empty{text-align:center;padding:24px;color:#94a3b8;font-style:italic}';
  h+='.sev-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-weight:700;font-size:10px;text-transform:uppercase}';
  h+='@media print{.tab-bar{display:none}.tab-content{display:block!important;page-break-before:always}.tbl-search{display:none}body{background:#fff}}';
  h+='</style></head><body>';
  // Header
  h+='<div class="header"><h1>Azure Infrastructure Assessment</h1>';
  h+='<div class="sub">Generated '+esc(now)+' &bull; '+tabs.length+' sections</div></div>';
  // Tab bar
  h+='<div class="tab-bar">';
  tabs.forEach(function(t,i){h+='<button class="tab-btn'+(i===0?' active':'')+'" data-tab="'+t.id+'">'+esc(t.label)+'</button>'});
  h+='</div>';
  // Summary tab
  if(c){
    h+='<div class="tab-content active" id="tab-summary"><h2 style="font-size:18px;margin-bottom:16px">Infrastructure Overview</h2>';
    h+='<div class="stat-grid">';
    var counts=[['VNets',(c.vpcs||[]).length],['Subnets',(c.subnets||[]).length],['VMs',(c.instances||[]).length],
      ['SQL',(c.rdsInstances||[]).length],['App GWs',(c.albs||[]).length],['Containers',(c.ecsServices||[]).length],
      ['Function Apps',(c.lambdaFns||[]).length],['NSGs',(c.sgs||[]).length]];
    counts.forEach(function(ct){h+='<div class="stat-card"><div class="val">'+ct[1]+'</div><div class="lbl">'+esc(ct[0])+'</div></div>'});
    h+='</div>';
    if(_complianceFindings&&_complianceFindings.length){
      var view=_buildComplianceView({});
      h+='<h3 style="font-size:14px;margin:20px 0 10px">Compliance Summary</h3><div class="stat-grid">';
      h+='<div class="stat-card"><div class="val" style="color:'+view.score.color+'">'+view.score.score+'</div><div class="lbl">Score ('+view.score.grade+')</div></div>';
      ['CRITICAL','HIGH','MEDIUM','LOW'].forEach(function(s){
        var clr=sevClr[s];
        h+='<div class="stat-card"><div class="val" style="color:'+clr.fg+'">'+view.sevCounts[s]+'</div><div class="lbl">'+s+'</div></div>';
      });
      h+='</div>';
    }
    h+='</div>';
  }
  // Classification tab
  if(_classificationData&&_classificationData.length){
    var tierPri={critical:1,high:2,medium:3,low:4};
    var clRows=_classificationData.slice().sort(function(a,b){return (tierPri[a.tier]||99)-(tierPri[b.tier]||99)}).map(function(r){
      var meta=_TIER_RPO_RTO[r.tier]||_TIER_RPO_RTO.low;
      return [r.id,r.name||'',r.type,r.tier?r.tier.charAt(0).toUpperCase()+r.tier.slice(1):'',meta.rpo||'',meta.rto||'',r.vpcName||r.vpcId||'',r.auto?'Auto':'Manual'];
    });
    h+='<div class="tab-content" id="tab-classification"><h2 style="font-size:18px;margin-bottom:8px">Resource Classification</h2>';
    h+='<p style="color:#64748b;font-size:12px;margin-bottom:12px">'+_classificationData.length+' classified resources</p>';
    h+=tbl('tblClass',['Resource ID','Name','Type','Tier','RPO','RTO','VPC','Source'],clRows,{tierCol:3});
    h+='</div>';
  }
  // App Summary tab
  if(_appRegistry&&_appRegistry.length){
    var appRows=_appRegistry.map(function(app){
      var matched=_matchAppResources(app);
      var best='low';
      var tp2={critical:1,high:2,medium:3,low:4};
      matched.forEach(function(r){if((tp2[r.tier]||99)<(tp2[best]||99))best=r.tier});
      var tier=app.tier||best;
      return [app.name,app.type||'',tier.charAt(0).toUpperCase()+tier.slice(1),matched.length];
    });
    h+='<div class="tab-content" id="tab-appsummary"><h2 style="font-size:18px;margin-bottom:8px">Application Summary</h2>';
    h+='<p style="color:#64748b;font-size:12px;margin-bottom:12px">'+_appRegistry.length+' registered applications</p>';
    h+=tbl('tblApp',['Application','Type','Tier','Resources'],appRows,{tierCol:2});
    h+='</div>';
  }
  // IAM Review tab
  if(_iamReviewData&&_iamReviewData.length){
    var iamRows=_iamReviewData.slice().sort(function(a,b){
      if(a.isAdmin!==b.isAdmin)return a.isAdmin?-1:1;
      return b.findings.length-a.findings.length;
    }).map(function(r){
      return [r.name,r.type,r.isAdmin?'YES':'No',r.hasMFA?'Yes':'No',
        r.policies,r.findings.length,r.lastUsed?r.lastUsed.toISOString().split('T')[0]:'Never'];
    });
    h+='<div class="tab-content" id="tab-iam"><h2 style="font-size:18px;margin-bottom:8px">IAM Review</h2>';
    h+='<p style="color:#64748b;font-size:12px;margin-bottom:12px">'+_iamReviewData.length+' principals</p>';
    h+=tbl('tblIam',['Name','Type','Admin','MFA','Policies','Findings','Last Used'],iamRows);
    h+='</div>';
  }
  // Compliance tab
  if(_complianceFindings&&_complianceFindings.length){
    var cv=_buildComplianceView({});
    var compRows=cv.filtered.slice().sort(function(a,b){
      var ta=_classifyTier(a),tb=_classifyTier(b);
      if(ta!==tb)return(_PRIORITY_ORDER[ta]||9)-(_PRIORITY_ORDER[tb]||9);
      return(_SEV_ORDER[a.severity]||9)-(_SEV_ORDER[b.severity]||9);
    }).map(function(f){
      return [_TIER_META[_classifyTier(f)].name,f.severity,_FW_LABELS[f.framework]||f.framework,
        f.control,f.resourceName||f.resource,f.message];
    });
    h+='<div class="tab-content" id="tab-compliance"><h2 style="font-size:18px;margin-bottom:8px">Compliance Findings</h2>';
    h+='<p style="color:#64748b;font-size:12px;margin-bottom:12px">'+cv.filtered.length+' findings</p>';
    h+=tbl('tblComp',['Priority','Severity','Framework','Control','Resource','Finding'],compRows,{sevCol:1,tierCol:0});
    h+='</div>';
  }
  // Firewall tab
  if(c&&((c.sgs&&c.sgs.length)||(c.nacls&&c.nacls.length)||(c.rts&&c.rts.length))){
    h+='<div class="tab-content" id="tab-firewall"><h2 style="font-size:18px;margin-bottom:12px">Firewall &amp; Network</h2>';
    if(c.sgs&&c.sgs.length){
      var sgRows=c.sgs.map(function(sg){
        var openNet=false;
        (sg.IpPermissions||[]).forEach(function(p){
          (p.IpRanges||[]).forEach(function(r){if(r.CidrIp==='0.0.0.0/0')openNet=true});
          (p.Ipv6Ranges||[]).forEach(function(r){if(r.CidrIpv6==='::/0')openNet=true});
        });
        return [sg.GroupId,sg.GroupName||'',sg.VpcId||'',(sg.IpPermissions||[]).length,(sg.IpPermissionsEgress||[]).length,openNet?'YES':'No'];
      });
      h+='<h3 style="font-size:14px;margin:16px 0 8px">Security Groups ('+c.sgs.length+')</h3>';
      h+=tbl('tblSg',['Group ID','Name','VPC','Inbound','Outbound','Open to Internet'],sgRows);
    }
    if(c.nacls&&c.nacls.length){
      var naclRows=c.nacls.map(function(n){
        return [n.NetworkAclId,n.VpcId||'',(n.Entries||[]).length,n.IsDefault?'Yes':'No'];
      });
      h+='<h3 style="font-size:14px;margin:16px 0 8px">NACLs ('+c.nacls.length+')</h3>';
      h+=tbl('tblNacl',['NACL ID','VPC','Rules','Default'],naclRows);
    }
    if(c.rts&&c.rts.length){
      var rtRows=c.rts.map(function(rt){
        return [rt.RouteTableId,rt.VpcId||'',(rt.Routes||[]).length];
      });
      h+='<h3 style="font-size:14px;margin:16px 0 8px">Route Tables ('+c.rts.length+')</h3>';
      h+=tbl('tblRt',['Route Table ID','VPC','Routes'],rtRows);
    }
    h+='</div>';
  }
  // BUDR tab
  if(_budrAssessments&&_budrAssessments.length){
    var budrRows=_budrAssessments.map(function(a){
      var tier=a.profile?a.profile.tier:'unknown';
      var rto=a.profile?a.profile.rto:'N/A';
      var rpo=a.profile?a.profile.rpo:'N/A';
      var sigs=a.signals?Object.keys(a.signals).map(function(k){return k+': '+a.signals[k]}).join(', '):'';
      return [a.id,a.type,tier,rto,rpo,sigs];
    });
    h+='<div class="tab-content" id="tab-budr"><h2 style="font-size:18px;margin-bottom:8px">Backup &amp; DR Assessment</h2>';
    h+='<p style="color:#64748b;font-size:12px;margin-bottom:12px">'+_budrAssessments.length+' resources assessed</p>';
    h+=tbl('tblBudr',['Resource','Type','DR Tier','RTO','RPO','Signals'],budrRows,{tierCol:2});
    h+='</div>';
  }
  // Inventory tab
  if(_inventoryData&&_inventoryData.length){
    var invRows=_inventoryData.map(function(r){
      return [r.type,r.name||'',r.config||'',r.state||'',r.vpcName||'',r.region||'',r.account||''];
    });
    h+='<div class="tab-content" id="tab-inventory"><h2 style="font-size:18px;margin-bottom:8px">Resource Inventory</h2>';
    h+='<p style="color:#64748b;font-size:12px;margin-bottom:12px">'+_inventoryData.length+' resources</p>';
    h+=tbl('tblInv',['Type','Name','Config','State','VNet','Region','Account'],invRows);
    h+='</div>';
  }
  // Embedded JS: tab switching, sorting, search
  h+='<script>';
  h+='document.querySelectorAll(".tab-btn").forEach(function(btn){';
  h+='  btn.addEventListener("click",function(){';
  h+='    document.querySelectorAll(".tab-btn").forEach(function(b){b.classList.remove("active")});';
  h+='    document.querySelectorAll(".tab-content").forEach(function(t){t.classList.remove("active")});';
  h+='    btn.classList.add("active");';
  h+='    var panel=document.getElementById("tab-"+btn.dataset.tab);';
  h+='    if(panel)panel.classList.add("active");';
  h+='  });';
  h+='});';
  // Sort on header click
  h+='document.querySelectorAll("thead th").forEach(function(th){';
  h+='  th.addEventListener("click",function(){';
  h+='    var table=th.closest("table"),idx=+th.dataset.col,tbody=table.querySelector("tbody");';
  h+='    var rows=Array.from(tbody.querySelectorAll("tr"));';
  h+='    var asc=th.dataset.sort!=="asc";th.dataset.sort=asc?"asc":"desc";';
  h+='    rows.sort(function(a,b){';
  h+='      var av=(a.cells[idx]||{}).textContent||"",bv=(b.cells[idx]||{}).textContent||"";';
  h+='      var an=parseFloat(av),bn=parseFloat(bv);';
  h+='      if(!isNaN(an)&&!isNaN(bn))return asc?an-bn:bn-an;';
  h+='      return asc?av.localeCompare(bv):bv.localeCompare(av);';
  h+='    });';
  h+='    rows.forEach(function(r,i){r.className=i%2?\"stripe\":\"\";tbody.appendChild(r)});';
  h+='  });';
  h+='});';
  // Search filter
  h+='document.querySelectorAll(".tbl-search").forEach(function(inp){';
  h+='  inp.addEventListener("input",function(){';
  h+='    var q=inp.value.toLowerCase(),tbl=document.getElementById(inp.dataset.table);';
  h+='    if(!tbl)return;';
  h+='    Array.from(tbl.querySelectorAll("tbody tr")).forEach(function(r){';
  h+='      r.style.display=r.textContent.toLowerCase().indexOf(q)>=0?"":"none";';
  h+='    });';
  h+='  });';
  h+='});';
  h+='<\/script>';
  h+='<p style="text-align:center;color:#94a3b8;font-size:11px;margin:32px 0;padding-top:16px;border-top:1px solid #e2e8f0">Azure Mapper &bull; Full Assessment Report &bull; '+esc(now)+'</p>';
  h+='</body></html>';
  downloadBlob(new Blob([h],{type:'text/html'}),'full-assessment-report.html');
  _showToast('HTML report exported');
}

function _exportFullCSV(){
  var csvFiles=[];
  // Classification
  if(_classificationData&&_classificationData.length){
    var rows=[['Resource ID','Name','Type','Tier','RPO','RTO','VPC','Auto']];
    _classificationData.forEach(function(r){
      var meta=_TIER_RPO_RTO[r.tier]||_TIER_RPO_RTO.low;
      rows.push([r.id,r.name||'',r.type,r.tier||'',meta.rpo||'',meta.rto||'',r.vpcName||r.vpcId||'',r.auto?'Auto':'Manual']);
    });
    csvFiles.push({name:'classification.csv',data:rows});
  }
  // IAM
  if(_iamReviewData&&_iamReviewData.length){
    var rows=[['Name','Type','Admin','MFA','Console','Policies','Findings','Last Used']];
    _iamReviewData.forEach(function(r){
      rows.push([r.name,r.type,r.isAdmin?'YES':'No',r.hasMFA?'Yes':'No',r.hasConsole?'Yes':'No',r.policies,r.findings.length,
        r.lastUsed?r.lastUsed.toISOString().split('T')[0]:'Never']);
    });
    csvFiles.push({name:'iam-review.csv',data:rows});
  }
  // Compliance
  if(_complianceFindings&&_complianceFindings.length){
    var rows=[['Priority','Effort','Severity','Framework','Control','CKV','Resource','Finding','Remediation']];
    _complianceFindings.forEach(function(f){
      rows.push([_TIER_META[_classifyTier(f)].name,_EFFORT_LABELS[_getEffort(f)]||'Med',f.severity,f.framework,f.control,f.ckv||'',
        f.resourceName||f.resource,f.message,f.remediation||'']);
    });
    csvFiles.push({name:'compliance.csv',data:rows});
  }
  // BUDR
  if(_budrAssessments&&_budrAssessments.length){
    var rows=[['Resource','Type','DR Tier','RTO','RPO','Signals']];
    _budrAssessments.forEach(function(a){
      var tier=a.profile?a.profile.tier:'unknown';
      var sigs=a.signals?Object.keys(a.signals).map(function(k){return k+': '+a.signals[k]}).join('; '):'';
      rows.push([a.id,a.type,tier,a.profile?a.profile.rto:'N/A',a.profile?a.profile.rpo:'N/A',sigs]);
    });
    csvFiles.push({name:'budr.csv',data:rows});
  }
  // Inventory
  if(_inventoryData&&_inventoryData.length){
    var rows=[['Type','Name','ID','Config','State','VNet','Region','Account','Classification','BUDR']];
    _inventoryData.forEach(function(r){
      rows.push([r.type,r.name||'',r.id,r.config||'',r.state||'',r.vpcName||'',r.region||'',r.account||'',r.classificationTier||'',r.budrTier||'']);
    });
    csvFiles.push({name:'inventory.csv',data:rows});
  }
  if(!csvFiles.length){_showToast('No data to export','error');return}
  // Single CSV if only one, else zip
  function toCsv(rows){
    return rows.map(function(r){return r.map(function(c){return '"'+String(c).replace(/"/g,'""')+'"'}).join(',')}).join('\n');
  }
  if(csvFiles.length===1){
    downloadBlob(new Blob([toCsv(csvFiles[0].data)],{type:'text/csv'}),csvFiles[0].name);
    return;
  }
  // Use JSZip if available, else fall back to individual downloads
  if(typeof JSZip!=='undefined'){
    var zip=new JSZip();
    csvFiles.forEach(function(f){zip.file(f.name,toCsv(f.data))});
    zip.generateAsync({type:'blob'}).then(function(blob){
      downloadBlob(blob,'full-assessment-csvs.zip');
      _showToast('CSV bundle exported');
    });
  }else{
    csvFiles.forEach(function(f){downloadBlob(new Blob([toCsv(f.data)],{type:'text/csv'}),f.name)});
    _showToast(csvFiles.length+' CSV files exported');
  }
}

function _rptBuildXlsxAppSummary(wb){
  if(!_classificationData.length&&_rlCtx) runClassificationEngine(_rlCtx);
  if(typeof _autoDiscoverApps==='function') _autoDiscoverApps();
  if(!_appRegistry.length) return;
  var tierPri={critical:1,high:2,medium:3,low:4};
  var sumHeaders=['Application','Type','Criticality','Resources','RPO','RTO'];
  var sumRows=[];
  var detailRows=[];
  _appRegistry.forEach(function(app){
    var matched=_matchAppResources(app);
    var bestTier='low';
    matched.forEach(function(r){if((tierPri[r.tier]||99)<(tierPri[bestTier]||99)) bestTier=r.tier});
    var tier=app.tier||bestTier;
    var meta=_TIER_RPO_RTO[tier]||_TIER_RPO_RTO.low;
    sumRows.push([app.name,app.type||'',tier.toUpperCase(),matched.length,meta.rpo,meta.rto]);
    matched.forEach(function(r){
      detailRows.push([app.name,r.name,r.type,r.tier.toUpperCase(),r.vpcName||'',r.id]);
    });
  });
  sumRows.sort(function(a,b){return(tierPri[a[2].toLowerCase()]||99)-(tierPri[b[2].toLowerCase()]||99)});
  _xlsxAddSheet(wb,'App Summary',sumHeaders,sumRows,{tierCol:2,minWidths:[25,15,12,10,10,10]});
  // Detail sheet with tier styling and console links
  var detHeaders=['Application','Resource','Type','Tier','VPC','ID'];
  var detLinks=[];
  detailRows.forEach(function(row,ri){
    var type=row[2],id=row[5];
    var url=_azurePortalUrl(type,id,'us-east-1');
    if(url) detLinks.push({r:ri,c:5,url:url});
  });
  _xlsxAddSheet(wb,'App Resources',detHeaders,detailRows,{tierCol:3,minWidths:[25,30,15,10,20,25],links:detLinks});
}

function _rptBuildXlsxIAMReview(wb){
  if(!_iamReviewData.length){
    var raw=safeParse(gv('in_rbac'));
    if(raw){var p=parseIAMData(raw);if(p)prepareIAMReviewData(p)}
  }
  if(!_iamReviewData.length) return;
  var headers=['Name','Type','Admin','MFA','Console','Policies','Findings','Cross-Account Trusts','Created','Last Used'];
  var rows=_iamReviewData.slice().sort(function(a,b){
    if(a.isAdmin!==b.isAdmin) return a.isAdmin?-1:1;
    return b.findings.length-a.findings.length;
  }).map(function(r){
    return [r.name,r.type,r.isAdmin?'YES':'No',
      r.hasMFA?'Yes':'No',r.hasConsole?'Yes':'No',
      r.policies,r.findings.length,
      r.crossAccounts.length?r.crossAccounts.join(', '):'—',
      r.created?r.created.toISOString().split('T')[0]:'—',
      r.lastUsed?r.lastUsed.toISOString().split('T')[0]:'Never'];
  });
  _xlsxAddSheet(wb,'IAM Review',headers,rows,{minWidths:[24,10,10,8,10,10,10,28,14,14]});
  // Highlight admin cells (col 2) in red
  var wsName='IAM Review';
  var ws=wb.Sheets[wsName];
  if(!ws) return;
  for(let r=1;r<=rows.length;r++){
    var addr=XLSX.utils.encode_cell({r:r,c:2});
    if(ws[addr]&&String(ws[addr].v)==='YES'){
      ws[addr].s={font:{bold:true,color:{rgb:_XLSX_COLORS.critFg},name:'Calibri',sz:10},
        fill:{fgColor:{rgb:_XLSX_COLORS.critBg}},alignment:{horizontal:'center',vertical:'center'},
        border:_xlsxBorder()};
    }
  }
}

function _rptBuildXlsxClassification(wb){
  if(!_classificationData||!_classificationData.length) return;
  var headers=['Resource ID','Name','Type','Tier','RPO','RTO','VPC','Auto-Classified'];
  var tierPri={critical:1,high:2,medium:3,low:4};
  var rows=_classificationData.slice().sort(function(a,b){
    return (tierPri[a.tier]||99)-(tierPri[b.tier]||99);
  }).map(function(r){
    var meta=_TIER_RPO_RTO[r.tier]||_TIER_RPO_RTO.low;
    return [r.id,r.name||'',r.type,
      r.tier?r.tier.charAt(0).toUpperCase()+r.tier.slice(1):'',
      meta.rpo||'',meta.rto||'',r.vpcName||r.vpcId||'',
      r.auto?'Auto':'Manual'];
  });
  _xlsxAddSheet(wb,'Classification',headers,rows,{tierCol:3,minWidths:[28,22,16,12,10,10,20,14]});
}

function _rptBuildXlsxFirewall(wb){
  var c=_rlCtx;
  if(!c) return;
  var acctFilter=_rptGetAccountFilter();
  function _af(arr){
    if(!acctFilter||acctFilter==='all') return arr||[];
    return (arr||[]).filter(function(r){return (r._subscriptionId||'')===acctFilter});
  }
  // Security Groups
  var sgs=_af(c.sgs);
  if(sgs.length){
    var sgHeaders=['Account','Region','Group ID','Name','VPC','Inbound Rules','Outbound Rules','Open to Internet'];
    var sgRows=sgs.map(function(sg){
      var inbound=(sg.IpPermissions||[]).length;
      var outbound=(sg.IpPermissionsEgress||[]).length;
      var openNet=false;
      (sg.IpPermissions||[]).forEach(function(p){
        (p.IpRanges||[]).forEach(function(r){if(r.CidrIp==='0.0.0.0/0')openNet=true});
        (p.Ipv6Ranges||[]).forEach(function(r){if(r.CidrIpv6==='::/0')openNet=true});
      });
      return [_rptAccountLabel(sg._subscriptionId)||'',sg._region||'',sg.GroupId,sg.GroupName||_rptTagName(sg),
        sg.VpcId||'',inbound,outbound,openNet?'YES':'No'];
    });
    _xlsxAddSheet(wb,'Security Groups',sgHeaders,sgRows,{minWidths:[16,14,22,22,22,14,14,16]});
    // Highlight open-to-internet cells in red
    var ws=wb.Sheets['Security Groups'];
    if(ws){
      for(let r=1;r<=sgRows.length;r++){
        var addr=XLSX.utils.encode_cell({r:r,c:7});
        if(ws[addr]&&String(ws[addr].v)==='YES'){
          ws[addr].s={font:{bold:true,color:{rgb:_XLSX_COLORS.critFg},name:'Calibri',sz:10},
            fill:{fgColor:{rgb:_XLSX_COLORS.critBg}},alignment:{horizontal:'center',vertical:'center'},
            border:_xlsxBorder()};
        }
      }
    }
  }
  // NACLs
  var nacls=_af(c.nacls);
  if(nacls.length){
    var naclHeaders=['Account','Region','NACL ID','Name','VPC','Rules','Default','Subnets'];
    var naclRows=nacls.map(function(n){
      var subs=(n.Associations||[]).map(function(a){return a.SubnetId}).filter(Boolean).join(', ');
      return [_rptAccountLabel(n._subscriptionId)||'',n._region||'',n.NetworkAclId,_rptTagName(n),
        n.VpcId||'',(n.Entries||[]).length,n.IsDefault?'Yes':'No',subs||'—'];
    });
    _xlsxAddSheet(wb,'NACLs',naclHeaders,naclRows,{minWidths:[16,14,22,22,22,10,10,30]});
  }
  // Route Tables
  var rts=_af(c.rts);
  if(rts.length){
    var rtHeaders=['Account','Region','Route Table ID','Name','VPC','Routes','Subnets'];
    var rtRows=rts.map(function(rt){
      var subs=(rt.Associations||[]).filter(function(a){return a.SubnetId}).map(function(a){return a.SubnetId}).join(', ');
      return [_rptAccountLabel(rt._subscriptionId)||'',rt._region||'',rt.RouteTableId,_rptTagName(rt),
        rt.VpcId||'',(rt.Routes||[]).length,subs||'(main)'];
    });
    _xlsxAddSheet(wb,'Route Tables',rtHeaders,rtRows,{minWidths:[16,14,22,22,22,10,30]});
  }
}

// === DOCX EXPORT ===
async function _generateDocx(tone){
  var btn=document.getElementById('rptExportDOCX');
  if(btn){btn.textContent='Generating...';btn.disabled=true;}
  try{
    var enabled=_rptEnabledModules();
    if(!enabled.length){_showToast('No sections enabled');return;}
    var isExec=(tone==='executive');
    var title=_rptState.title||'Azure Infrastructure Assessment';
    var author=_rptState.author||'';
    var date=_rptState.date||new Date().toISOString().slice(0,10);
    var body=_docxBuildBody(enabled,isExec,title,author,date);
    var stylesXml=_docxStyles();
    var docXml=_docxWrap(body);
    var zip=new JSZip();
    zip.file('[Content_Types].xml',
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'+
      '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'+
      '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'+
      '<Default Extension="xml" ContentType="application/xml"/>'+
      '<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>'+
      '<Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>'+
      '</Types>');
    zip.file('_rels/.rels',
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'+
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'+
      '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>'+
      '</Relationships>');
    zip.file('word/document.xml',docXml);
    zip.file('word/styles.xml',stylesXml);
    zip.file('word/_rels/document.xml.rels',
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'+
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'+
      '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>'+
      '</Relationships>');
    var blob=await zip.generateAsync({type:'blob',mimeType:'application/vnd.openxmlformats-officedocument.wordprocessingml.document'});
    var slug=_rptSlugify(title);
    downloadBlob(blob,slug+'-'+tone+'-'+date+'.docx');
    _showToast('DOCX report exported ('+tone+')');
  }catch(e){
    console.error('DOCX export failed:',e);
    _showToast('DOCX export failed: '+e.message);
  }finally{
    if(btn){btn.textContent='Export DOCX';btn.disabled=false;}
  }
}

function _docxEsc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}

function _docxP(text,style){
  var pPr=style?'<w:pPr><w:pStyle w:val="'+style+'"/></w:pPr>':'';
  return '<w:p>'+pPr+'<w:r><w:t xml:space="preserve">'+_docxEsc(text)+'</w:t></w:r></w:p>';
}

function _docxBoldP(label,value){
  return '<w:p><w:r><w:rPr><w:b/></w:rPr><w:t xml:space="preserve">'+_docxEsc(label)+': </w:t></w:r>'+
    '<w:r><w:t xml:space="preserve">'+_docxEsc(value)+'</w:t></w:r></w:p>';
}

function _docxTableRow(cells,isHeader){
  var h='<w:tr>';
  cells.forEach(function(c){
    h+='<w:tc><w:tcPr>';
    if(isHeader) h+='<w:shd w:val="clear" w:fill="1B2A4A"/>';
    h+='</w:tcPr><w:p><w:r>';
    if(isHeader) h+='<w:rPr><w:b/><w:color w:val="FFFFFF"/><w:sz w:val="18"/></w:rPr>';
    else h+='<w:rPr><w:sz w:val="18"/></w:rPr>';
    h+='<w:t xml:space="preserve">'+_docxEsc(c)+'</w:t></w:r></w:p></w:tc>';
  });
  return h+'</w:tr>';
}

function _docxTable(headers,rows,maxRows){
  if(maxRows&&rows.length>maxRows) rows=rows.slice(0,maxRows);
  var h='<w:tbl><w:tblPr><w:tblStyle w:val="TableGrid"/><w:tblW w:w="0" w:type="auto"/>'+
    '<w:tblBorders><w:top w:val="single" w:sz="4" w:color="D1D5DB"/>'+
    '<w:left w:val="single" w:sz="4" w:color="D1D5DB"/>'+
    '<w:bottom w:val="single" w:sz="4" w:color="D1D5DB"/>'+
    '<w:right w:val="single" w:sz="4" w:color="D1D5DB"/>'+
    '<w:insideH w:val="single" w:sz="4" w:color="D1D5DB"/>'+
    '<w:insideV w:val="single" w:sz="4" w:color="D1D5DB"/>'+
    '</w:tblBorders></w:tblPr>';
  h+=_docxTableRow(headers,true);
  rows.forEach(function(r){h+=_docxTableRow(r,false)});
  h+='</w:tbl>';
  return h;
}

function _docxBuildBody(enabled,isExec,title,author,date){
  var h='';
  // Title page
  h+=_docxP(title,'Title');
  var sub=[];
  if(author) sub.push('Prepared by '+author);
  sub.push(date);
  sub.push(isExec?'Executive Summary':'Technical Assessment');
  h+=_docxP(sub.join('  |  '),'Subtitle');
  h+='<w:p><w:pPr><w:pBdr><w:bottom w:val="single" w:sz="12" w:color="1B2A4A"/></w:pBdr></w:pPr></w:p>';
  // TOC
  h+=_docxP('Table of Contents','Heading1');
  enabled.forEach(function(id,i){
    var m=_RPT_MODULES.find(function(x){return x.id===id});
    if(m) h+=_docxP((i+1)+'. '+m.name,'TOCEntry');
  });
  h+='<w:p><w:r><w:br w:type="page"/></w:r></w:p>';
  // Sections
  enabled.forEach(function(id){
    if(id==='exec-summary') h+=_docxExecSummary(isExec);
    else if(id==='compliance') h+=_docxCompliance(isExec);
    else if(id==='budr') h+=_docxBUDR(isExec);
    else if(id==='iam-review') h+=_docxIAMReview(isExec);
    else if(id==='inventory') h+=_docxInventory(isExec);
    else if(id==='action-plan') h+=_docxActionPlan(isExec);
    else if(id==='app-summary') h+=_docxAppSummary(isExec);
    else if(id==='architecture') h+=_docxP('(Architecture diagram — see HTML report for interactive map)');
    else if(id==='iac-recs') h+=_docxIaCRecs(isExec);
  });
  // Footer
  h+=_docxP('');
  h+=_docxP('Generated by Azure Mapper — '+new Date().toLocaleString(),'Footer');
  return h;
}

function _docxExecSummary(isExec){
  var h=_docxP('Executive Summary','Heading1');
  var c=_rlCtx;
  if(!c) return h+_docxP('No infrastructure data loaded.');
  var counts=[['VNets',(c.vpcs||[]).length],['Subnets',(c.subnets||[]).length],
    ['Virtual Machines',(c.instances||[]).length],['SQL Databases',(c.rdsInstances||[]).length],
    ['Load Balancers',(c.albs||[]).length],['Function Apps',(c.lambdaFns||[]).length],
    ['NSGs',(c.sgs||[]).length],['Container Instances',(c.ecsServices||[]).length]];
  if(isExec){
    h+=_docxP('This report covers the Azure infrastructure assessment performed on '+(_rptState.date||'today')+'. The environment spans '+
      (c._regions?c._regions.size:1)+' region(s) with '+(c.vpcs||[]).length+' VNet(s) hosting '+
      ((c.instances||[]).length+(c.rdsInstances||[]).length+(c.lambdaFns||[]).length)+' compute/database resources.');
    h+=_docxP('');
    h+=_docxP('Infrastructure at a Glance','Heading2');
  }else{
    h+=_docxP('Infrastructure Overview','Heading2');
  }
  h+=_docxTable(['Resource Type','Count'],counts.map(function(x){return [x[0],String(x[1])]}));
  // Compliance summary
  var _dxFindings=_rptFilterByAccount(_complianceFindings||[], _rptGetAccountFilter());
  if(_dxFindings.length){
    h+=_docxP('');
    h+=_docxP('Security Posture','Heading2');
    var sevs={CRITICAL:0,HIGH:0,MEDIUM:0,LOW:0};
    _dxFindings.forEach(function(f){sevs[f.severity]=(sevs[f.severity]||0)+1});
    if(isExec){
      var total=_dxFindings.length;
      var critHigh=sevs.CRITICAL+sevs.HIGH;
      h+=_docxP(total+' compliance findings identified. '+critHigh+' are Critical or High severity and require immediate attention.');
    }
    h+=_docxTable(['Severity','Count'],
      [['CRITICAL',String(sevs.CRITICAL)],['HIGH',String(sevs.HIGH)],
       ['MEDIUM',String(sevs.MEDIUM)],['LOW',String(sevs.LOW)]]);
  }
  return h;
}

function _docxCompliance(isExec){
  var h=_docxP('Compliance Findings','Heading1');
  var f=_rptFilterByAccount(_complianceFindings||[], _rptGetAccountFilter());
  if(!f||!f.length) return h+_docxP('No compliance findings.');
  if(isExec){
    // Executive: only critical + high, summarized by framework
    h+=_docxP('The following summarizes compliance findings requiring management attention.');
    var fws={};
    f.forEach(function(x){
      var fw=_FW_LABELS[x.framework]||x.framework||'Other';
      if(!fws[fw]) fws[fw]={total:0,crit:0,high:0};
      fws[fw].total++;
      if(x.severity==='CRITICAL') fws[fw].crit++;
      if(x.severity==='HIGH') fws[fw].high++;
    });
    h+=_docxTable(['Framework','Total','Critical','High'],
      Object.keys(fws).map(function(k){return [k,String(fws[k].total),String(fws[k].crit),String(fws[k].high)]}));
    // Top critical findings
    var critFindings=f.filter(function(x){return x.severity==='CRITICAL'||x.severity==='HIGH'});
    if(critFindings.length){
      h+=_docxP('');h+=_docxP('Top Priority Findings','Heading2');
      var maxShow=Math.min(critFindings.length,15);
      h+=_docxTable(['Severity','Resource','Finding','Remediation'],
        critFindings.slice(0,maxShow).map(function(x){
          return [x.severity,x.resourceName||x.resource,x.message,x.remediation];
        }),maxShow);
      if(critFindings.length>maxShow) h+=_docxP('... and '+(critFindings.length-maxShow)+' more. See XLSX for full details.');
    }
  }else{
    // Technical: full table (capped at 500 for DOCX; use XLSX for complete data)
    h+=_docxP(f.length+' findings across all frameworks and severity levels.');
    var sorted=f.slice().sort(function(a,b){return (_SEV_ORDER[a.severity]||9)-(_SEV_ORDER[b.severity]||9)});
    var maxDocx=500;
    h+=_docxTable(['Severity','Framework','Control','Resource','Finding','Remediation'],
      sorted.slice(0,maxDocx).map(function(x){
        return [x.severity,_FW_LABELS[x.framework]||x.framework||'',x.control,
          x.resourceName||x.resource,x.message,x.remediation];
      }));
    if(sorted.length>maxDocx) h+=_docxP('Showing '+maxDocx+' of '+sorted.length+' findings. Export XLSX for the complete dataset.');
  }
  return h;
}

function _docxBUDR(isExec){
  var h=_docxP('Backup & Disaster Recovery','Heading1');
  var filteredBudr=_rptFilterByAccount(_budrAssessments||[], _rptGetAccountFilter());
  if(!filteredBudr.length) return h+_docxP('No BUDR assessments.');
  var tc={protected:0,partial:0,at_risk:0};
  filteredBudr.forEach(function(a){if(a.profile&&tc[a.profile.tier]!==undefined)tc[a.profile.tier]++});
  if(isExec){
    var atRisk=tc.at_risk||0;
    h+=_docxP(filteredBudr.length+' resources assessed for disaster recovery readiness. '+
      atRisk+' resource(s) are at risk with insufficient backup coverage.');
    h+=_docxTable(['DR Tier','Count'],[['Protected',String(tc.protected||0)],
      ['Partial',String(tc.partial||0)],['At Risk',String(tc.at_risk||0)]]);
    var risky=filteredBudr.filter(function(a){return a.profile&&a.profile.tier==='at_risk'});
    if(risky.length){
      h+=_docxP('');h+=_docxP('At-Risk Resources','Heading2');
      h+=_docxTable(['Type','Name','RTO','RPO'],
        risky.slice(0,20).map(function(a){
          return [a.type,a.name||a.id,a.profile.rto,a.profile.rpo];
        }));
    }
  }else{
    h+=_docxTable(['Tier','Count'],[['Protected',String(tc.protected||0)],
      ['Partial',String(tc.partial||0)],['At Risk',String(tc.at_risk||0)]]);
    h+=_docxP('');
    h+=_docxTable(['Type','Resource','Name','DR Tier','RTO','RPO'],
      filteredBudr.map(function(a){
        var tier=a.profile?a.profile.tier:'unknown';
        return [a.type,a.id,a.name||'',tier,
          a.profile?a.profile.rto:'N/A',a.profile?a.profile.rpo:'N/A'];
      }));
  }
  return h;
}

function _docxIAMReview(isExec){
  var h=_docxP('IAM Review','Heading1');
  if(!_iamReviewData.length){
    var raw=safeParse(gv('in_rbac'));
    if(raw){var p=parseIAMData(raw);if(p)prepareIAMReviewData(p)}
  }
  if(!_iamReviewData.length) return h+_docxP('No IAM data available.');
  var admins=_iamReviewData.filter(function(r){return r.isAdmin});
  var crossAcct=_iamReviewData.filter(function(r){return r.crossAccounts.length>0});
  if(isExec){
    h+=_docxP(_iamReviewData.length+' IAM entities reviewed. '+admins.length+
      ' have administrative access. '+crossAcct.length+' have cross-account trust relationships.');
    if(admins.length){
      h+=_docxP('');h+=_docxP('Admin Access Entities','Heading2');
      h+=_docxTable(['Name','Type','Last Used'],
        admins.map(function(r){return [r.name,r.type,r.lastUsed?r.lastUsed.toISOString().split('T')[0]:'Never']}));
    }
  }else{
    h+=_docxBoldP('Total Entities',String(_iamReviewData.length));
    h+=_docxBoldP('Admins',String(admins.length));
    h+=_docxBoldP('Cross-Account',String(crossAcct.length));
    h+=_docxP('');
    h+=_docxTable(['Name','Type','Admin','MFA','Policies','Findings'],
      _iamReviewData.map(function(r){
        return [r.name,r.type,r.isAdmin?'YES':'No',r.hasMFA?'Yes':'No',
          String(r.policies),String(r.findings.length)];
      }));
  }
  return h;
}

function _docxInventory(isExec){
  var h=_docxP('Resource Inventory','Heading1');
  if(!_rlCtx) return h+_docxP('No data loaded.');
  if(!_inventoryData.length) _buildInventoryData();
  var filteredInv=_rptFilterByAccount(_inventoryData, _rptGetAccountFilter());
  if(isExec){
    // Executive: type summary only
    h+=_docxP('The environment contains '+filteredInv.length+' tracked resources across the following categories:');
    var typeCounts={};
    filteredInv.forEach(function(r){typeCounts[r.type]=(typeCounts[r.type]||0)+1});
    h+=_docxTable(['Resource Type','Count'],
      Object.keys(typeCounts).sort(function(a,b){return typeCounts[b]-typeCounts[a]})
        .map(function(k){return [k,String(typeCounts[k])]}));
  }else{
    // Technical: full resource table (same as xlsx Inventory columns)
    var c=_rlCtx;
    var acctF=_rptGetAccountFilter();
    function _daf(arr){
      if(!acctF||acctF==='all') return arr||[];
      return (arr||[]).filter(function(r){return (r._subscriptionId||'')===acctF});
    }
    var rows=[];
    _daf(c.vpcs).forEach(function(v){rows.push(['VNet',v.id||v.VpcId,_rptTagName(v),v.CidrBlock||(v.properties?.addressSpace?.addressPrefixes?.[0])||''])});
    _daf(c.subnets).forEach(function(s){rows.push(['Subnet',s.id||s.SubnetId,_rptTagName(s),s.CidrBlock||(s.properties?.addressPrefix)||''])});
    _daf(c.instances).forEach(function(i){rows.push(['VM',i.id||i.InstanceId,_rptTagName(i),i.InstanceType||i.properties?.hardwareProfile?.vmSize||''])});
    _daf(c.rdsInstances).forEach(function(d){rows.push(['SQL',d.id||d.DBInstanceIdentifier,d.name||d.DBInstanceIdentifier,d.Engine||''])});
    _daf(c.albs).forEach(function(a){rows.push(['App GW',a.name||a.LoadBalancerName||'',a.name||a.LoadBalancerName,a.properties?.sku?.name||''])});
    _daf(c.lambdaFns).forEach(function(fn){rows.push(['Function App',fn.name||fn.FunctionName||'',fn.name||fn.FunctionName,fn.properties?.runtime||fn.Runtime||''])});
    _daf(c.sgs).forEach(function(sg){rows.push(['NSG',sg.id||sg.GroupId,sg.name||sg.GroupName||'',sg.VpcId||''])});
    h+=_docxP(rows.length+' resources:');
    h+=_docxTable(['Type','ID','Name','Config'],rows);
  }
  return h;
}

function _docxActionPlan(isExec){
  var h=_docxP('Action Plan','Heading1');
  var acctF=_rptGetAccountFilter();
  var all=_rptFilterByAccount((_complianceFindings||[]).concat(_budrFindings||[]), acctF);
  if(!all.length) return h+_docxP('No action items.');
  var tiers=_getTierGroups(all);
  if(isExec){
    h+=_docxP('Remediation priorities organized by business impact:');
    _PRIORITY_KEYS.forEach(function(t){
      var rgs=tiers[t];if(!rgs) return;
      var meta=_TIER_META[t];
      var count=rgs.reduce(function(s,rg){return s+rg.findings.length},0);
      h+=_docxP('');
      h+=_docxP(meta.name+' ('+count+' items)','Heading2');
      h+=_docxP(meta.label||'');
      // Show top 5 per tier
      var shown=0;
      rgs.forEach(function(rg){
        rg.findings.forEach(function(f){
          if(shown>=5) return;
          h+=_docxBoldP(f.severity,f.message);
          shown++;
        });
      });
      if(count>5) h+=_docxP('... and '+(count-5)+' more items');
    });
  }else{
    var maxPerTier=200;
    _PRIORITY_KEYS.forEach(function(t){
      var rgs=tiers[t];if(!rgs) return;
      var meta=_TIER_META[t];
      h+=_docxP('');h+=_docxP(meta.name,'Heading2');
      var rows=[];
      rgs.forEach(function(rg){
        rg.findings.forEach(function(f){
          rows.push([f.severity,f.control,f.resourceName||f.resource,f.message,f.remediation]);
        });
      });
      var total=rows.length;
      h+=_docxTable(['Severity','Control','Resource','Finding','Remediation'],rows.slice(0,maxPerTier));
      if(total>maxPerTier) h+=_docxP('Showing '+maxPerTier+' of '+total+'. See XLSX for complete list.');
    });
  }
  return h;
}

function _docxAppSummary(isExec){
  var h=_docxP('Application Summary','Heading1');
  if(!_appRegistry.length) return h+_docxP('No applications defined.');
  var tierPri={critical:1,high:2,medium:3,low:4};
  if(isExec){
    h+=_docxP(_appRegistry.length+' applications registered in the environment:');
    var rows=_appRegistry.map(function(app){
      var matched=_matchAppResources(app);
      var tier=app.tier||'low';
      return [app.name,app.type||'',(tier).toUpperCase(),String(matched.length)];
    }).sort(function(a,b){return(tierPri[a[2].toLowerCase()]||99)-(tierPri[b[2].toLowerCase()]||99)});
    h+=_docxTable(['Application','Type','Criticality','Resources'],rows);
  }else{
    _appRegistry.forEach(function(app){
      var matched=_matchAppResources(app);
      var tier=app.tier||'low';
      var meta=_TIER_RPO_RTO[tier]||_TIER_RPO_RTO.low;
      h+=_docxP('');h+=_docxP(app.name+' ('+tier.toUpperCase()+')','Heading2');
      h+=_docxBoldP('Type',app.type||'N/A');
      h+=_docxBoldP('RPO',meta.rpo);
      h+=_docxBoldP('RTO',meta.rto);
      h+=_docxBoldP('Resources',String(matched.length));
      if(matched.length){
        h+=_docxTable(['Resource','Type','Tier','ID'],
          matched.map(function(r){return [r.name,r.type,r.tier.toUpperCase(),r.id]}));
      }
    });
  }
  return h;
}

function _docxIaCRecs(isExec){
  var h=_docxP('IaC Recommendations','Heading1');
  if(isExec) return h+_docxP('Infrastructure as Code recommendations are available in the detailed technical report.');
  h+=_docxP('Terraform and ARM Template snippets for remediation are available in the HTML report.');
  return h;
}

