document.getElementById('dlBash').addEventListener('click',function(){
  document.getElementById('exportScriptMenu').style.display='none';
  var script=[
'#!/usr/bin/env bash',
'# Azure Network Mapper — Data Export Script',
'# Usage:',
'#   ./export-azure-data.sh                                 # default subscription + location',
'#   ./export-azure-data.sh -s <subscription-id> -r eastus',
'#   ./export-azure-data.sh -s <subscription-id> -a         # all regions, skip empty',
'#   ./export-azure-data.sh -P sub1,sub2,sub3 -a            # multi-subscription, all regions',
'#   ./export-azure-data.sh -s <subscription-id> -r eastus -o ./out',
'set -euo pipefail',
'SUBSCRIPTION="";REGION="";OUTDIR="";ALL_REGIONS=false;PROFILES=""',
'usage(){ echo "Usage: $0 [-s subscription] [-r location] [-o dir] [-a all-locations] [-P subscriptions]"; exit 1; }',
'while getopts "s:r:o:P:ah" opt; do case $opt in s) SUBSCRIPTION="$OPTARG";; r) REGION="$OPTARG";; o) OUTDIR="$OPTARG";; P) PROFILES="$OPTARG";; a) ALL_REGIONS=true;; *) usage;; esac; done',
'[[ -n "$SUBSCRIPTION" && ! "$SUBSCRIPTION" =~ ^[a-zA-Z0-9_-]+$ ]] && echo "ERROR: Invalid subscription" >&2 && exit 1',
'[[ -n "$REGION" && ! "$REGION" =~ ^[a-zA-Z0-9-]+$ ]] && echo "ERROR: Invalid location" >&2 && exit 1',
'command -v az &>/dev/null || { echo "ERROR: Azure CLI not found. Install: https://docs.microsoft.com/en-us/cli/azure/install-azure-cli" >&2; exit 1; }',
'_has_data(){ python3 -c "import json,sys;d=json.load(sys.stdin);v=d.get(\'value\',d) if isinstance(d,dict) else d;sys.exit(0 if isinstance(v,list) and len(v)>0 else 1)" 2>/dev/null; }',
'AZ_FLAGS=();CUR_OUT=""',
'run(){ local label="$1" fn="$2"; shift 2; printf "  %-35s" "$label..."; if output=$(az "${AZ_FLAGS[@]}" "$@" 2>&1); then if printf \'%s\' "$output" | _has_data; then echo "$output" > "$CUR_OUT/$fn"; echo "OK ($(wc -c < "$CUR_OUT/$fn" | tr -d \' \') bytes)"; else echo "SKIP (empty)"; fi; else echo "SKIP"; fi; }',
'has_resources(){ local r; r=$(az "${AZ_FLAGS[@]}" network vnet list 2>/dev/null) || return 1; [ "$(printf \'%s\' "$r" | python3 -c \'import json,sys;print(len(json.load(sys.stdin)))\' 2>/dev/null)" != "0" ]; }',
'export_all(){',
'mkdir -p "$CUR_OUT"',
'echo "── Network ─────────────────────────────────"',
'run "VNets"                   "vnets.json"                   network vnet list',
'run "Subnets"                 "subnets.json"                 network vnet subnet list --ids $(az network vnet list --query "[].subnets[].id" -o tsv 2>/dev/null) 2>/dev/null || run "Subnets" "subnets.json" network vnet list --query "[].{value:subnets}"',
'run "Route Tables (UDRs)"     "route-tables.json"            network route-table list',
'run "NSGs"                    "nsgs.json"                    network nsg list',
'run "NICs"                    "nics.json"                    network nic list',
'run "Public IPs"              "public-ips.json"              network public-ip list',
'',
'echo "── Gateways ────────────────────────────────"',
'run "NAT Gateways"            "nat-gateways.json"            network nat gateway list',
'run "Private Endpoints"       "private-endpoints.json"       network private-endpoint list',
'run "Azure Firewalls"         "firewalls.json"               network firewall list',
'run "Azure Bastion"           "bastions.json"                network bastion list',
'',
'echo "── Compute ─────────────────────────────────"',
'run "Virtual Machines"        "vms.json"                     vm list',
'run "Azure SQL"               "sql-servers.json"             sql server list',
'run "Container Instances"     "containers.json"              container list',
'run "Function Apps"           "func-apps.json"               functionapp list',
'run "Redis Cache"             "redis.json"                   redis list',
'run "AKS Clusters"            "aks-clusters.json"            aks list',
'',
'echo "── Load Balancing ──────────────────────────"',
'run "Load Balancers"          "load-balancers.json"          network lb list',
'run "App Gateways"            "app-gateways.json"            network application-gateway list',
'',
'echo "── Connectivity ────────────────────────────"',
'run "VNet Peerings"           "vnet-peerings.json"           network vnet peering list',
'run "VPN Connections"         "vpn-connections.json"         network vpn-connection list',
'run "Virtual WANs"            "virtual-wans.json"            network vwan list',
'',
'echo "── Storage ──────────────────────────────────"',
'run "Managed Disks"           "disks.json"                   disk list',
'run "Disk Snapshots"          "snapshots.json"               snapshot list',
'run "Storage Accounts"        "storage-accounts.json"        storage account list',
'',
'echo "── DNS ─────────────────────────────────────"',
'run "Private DNS Zones"       "private-dns-zones.json"       network private-dns zone list',
'run "DNS Record Sets"         "dns-records.json"             network private-dns record-set list',
'',
'echo "── Security ────────────────────────────────"',
'run "WAF Policies"            "waf-policies.json"            network application-gateway waf-policy list',
'run "Front Door"              "front-door.json"              afd profile list',
'',
'echo "── RBAC ─────────────────────────────────────"',
'run "Role Assignments"        "rbac.json"                    role assignment list',
'',
'echo "── Resource Groups ──────────────────────────"',
'run "Resource Groups"         "resource-groups.json"         group list',
'}',
'',
'echo "Azure Network Mapper — Data Export"',
'echo ""',
'PROF_LIST=()',
'if [[ -n "$PROFILES" ]]; then IFS=\',\' read -ra PROF_LIST <<< "$PROFILES"',
'elif [[ -n "$SUBSCRIPTION" ]]; then PROF_LIST=("$SUBSCRIPTION"); fi',
'if [[ ${#PROF_LIST[@]} -gt 0 ]]; then',
'  [[ -z "$OUTDIR" ]] && OUTDIR="./azure-export-multi-$(date +%Y%m%d-%H%M%S)"',
'  echo "  Subscriptions: ${PROF_LIST[*]}"',
'  for sub in "${PROF_LIST[@]}"; do',
'    sub=$(echo "$sub" | xargs)',
'    echo ""; echo "=== Subscription: $sub ==="',
'    AZ_FLAGS=(--subscription "$sub")',
'    if $ALL_REGIONS; then',
'      locations=$(az account list-locations --query \'[].name\' -o tsv 2>/dev/null | sort)',
'      skip=0',
'      for loc in $locations; do',
'        AZ_FLAGS=(--subscription "$sub")',
'        if ! has_resources; then skip=$((skip+1)); continue; fi',
'        echo "  Location: $loc"; CUR_OUT="$OUTDIR/$sub/$loc"; export_all',
'      done',
'      [ $skip -gt 0 ] && echo "  Skipped $skip empty locations"',
'    else',
'      CUR_OUT="$OUTDIR/$sub"; export_all',
'    fi',
'  done',
'elif $ALL_REGIONS; then',
'  AZ_FLAGS=(); [[ -n "$SUBSCRIPTION" ]] && AZ_FLAGS+=(--subscription "$SUBSCRIPTION")',
'  [[ -z "$OUTDIR" ]] && OUTDIR="./azure-export-${SUBSCRIPTION:-default}-alllocations-$(date +%Y%m%d-%H%M%S)"',
'  locations=$(az account list-locations --query \'[].name\' -o tsv 2>/dev/null | sort)',
'  echo "  Mode: All Locations  Subscription: ${SUBSCRIPTION:-default}"; skip=0',
'  for loc in $locations; do',
'    if ! has_resources; then echo "  $loc — empty, skipping"; skip=$((skip+1)); continue; fi',
'    echo "  Location: $loc"; CUR_OUT="$OUTDIR/$loc"; export_all',
'  done',
'  [ $skip -gt 0 ] && echo "  Skipped $skip empty locations"',
'else',
'  AZ_FLAGS=(); [[ -n "$SUBSCRIPTION" ]] && AZ_FLAGS+=(--subscription "$SUBSCRIPTION")',
'  [[ -z "$OUTDIR" ]] && OUTDIR="./azure-export-${SUBSCRIPTION:-default}-$(date +%Y%m%d-%H%M%S)"',
'  echo "  Subscription: ${SUBSCRIPTION:-default}  Location: ${REGION:-all}  Output: $OUTDIR"',
'  CUR_OUT="$OUTDIR"; export_all',
'fi',
'echo ""',
'count=$(find "$OUTDIR" -name \'*.json\' 2>/dev/null | wc -l | tr -d \' \')',
'size=$(du -sh "$OUTDIR" 2>/dev/null | cut -f1)',
'echo "Done! $count files ($size) -> $OUTDIR"',
'echo "Drag folder onto Upload JSON Files or paste individually."'
  ].join('\n');
  var blob=new Blob([script],{type:'text/x-shellscript'});
  downloadBlob(blob,'export-azure-data.sh');
  _showToast('Bash script downloaded — run: chmod +x export-azure-data.sh && ./export-azure-data.sh');
});
document.getElementById('dlPowershell').addEventListener('click',function(){
  document.getElementById('exportScriptMenu').style.display='none';
  var script=[
'#Requires -Version 7.0',
'<#',
'.SYNOPSIS',
'    Azure Network Mapper - Data Export Script (PowerShell)',
'.DESCRIPTION',
'    Exports all Azure CLI data needed for the web-based mapper tool.',
'    Supports multi-location sweep and parallel execution.',
'.PARAMETER Subscription',
'    Azure subscription ID (optional)',
'.PARAMETER Location',
'    Azure location/region (optional)',
'.PARAMETER OutputDir',
'    Output directory (optional)',
'.PARAMETER AllLocations',
'    Sweep all enabled locations into subfolders',
'.PARAMETER MaxParallel',
'    Max concurrent API calls (default: 6)',
'.EXAMPLE',
'    ./export-azure-data.ps1',
'    ./export-azure-data.ps1 -Subscription <sub-id> -Location eastus',
'    ./export-azure-data.ps1 -Subscription <sub-id> -AllLocations -MaxParallel 8',
'    ./export-azure-data.ps1 -Subscriptions sub1,sub2,sub3 -AllLocations',
'#>',
'[CmdletBinding()]',
'param([Alias("s")][string]$Subscription,[Alias("r")][string]$Location,[Alias("o")][string]$OutputDir,[switch]$AllLocations,[string[]]$Subscriptions,[int]$MaxParallel=6)',
'$ErrorActionPreference="Stop"',
'if(-not $PSBoundParameters.ContainsKey(\'Subscription\')){$Subscription=$null}',
'if($Subscription -and $Subscription -notmatch \'^[a-zA-Z0-9_-]+$\'){Write-Error "Invalid subscription";exit 1}',
'if($Location -and $Location -notmatch \'^[a-zA-Z0-9-]+$\'){Write-Error "Invalid location";exit 1}',
'if(-not(Get-Command az -ErrorAction SilentlyContinue)){Write-Error "Azure CLI not found. Install: https://docs.microsoft.com/en-us/cli/azure/install-azure-cli";exit 1}',
'$subList=@()',
'if($Subscriptions){$subList=@($Subscriptions|ForEach-Object{$_ -split ","}|ForEach-Object{$_.Trim()}|Where-Object{$_})}',
'if($Subscription -and $subList.Count -eq 0){$subList=@($Subscription)}',
'$azFlags=@(); if($Subscription){$azFlags+=@("--subscription",$Subscription)}',
'function Get-BaseFlags([string]$sub){$f=@();if($sub){$f+=@("--subscription",$sub)};return $f}',
'$exports=@(',
'  @{Label="VNets";File="vnets.json";Cmd=@("network","vnet","list")},',
'  @{Label="Route Tables";File="route-tables.json";Cmd=@("network","route-table","list")},',
'  @{Label="NSGs";File="nsgs.json";Cmd=@("network","nsg","list")},',
'  @{Label="NICs";File="nics.json";Cmd=@("network","nic","list")},',
'  @{Label="Public IPs";File="public-ips.json";Cmd=@("network","public-ip","list")},',
'  @{Label="NAT Gateways";File="nat-gateways.json";Cmd=@("network","nat","gateway","list")},',
'  @{Label="Private Endpoints";File="private-endpoints.json";Cmd=@("network","private-endpoint","list")},',
'  @{Label="Azure Firewalls";File="firewalls.json";Cmd=@("network","firewall","list")},',
'  @{Label="Azure Bastion";File="bastions.json";Cmd=@("network","bastion","list")},',
'  @{Label="Virtual Machines";File="vms.json";Cmd=@("vm","list")},',
'  @{Label="Azure SQL";File="sql-servers.json";Cmd=@("sql","server","list")},',
'  @{Label="Container Instances";File="containers.json";Cmd=@("container","list")},',
'  @{Label="Function Apps";File="func-apps.json";Cmd=@("functionapp","list")},',
'  @{Label="Redis Cache";File="redis.json";Cmd=@("redis","list")},',
'  @{Label="AKS Clusters";File="aks-clusters.json";Cmd=@("aks","list")},',
'  @{Label="Load Balancers";File="load-balancers.json";Cmd=@("network","lb","list")},',
'  @{Label="App Gateways";File="app-gateways.json";Cmd=@("network","application-gateway","list")},',
'  @{Label="VNet Peerings";File="vnet-peerings.json";Cmd=@("network","vnet","peering","list")},',
'  @{Label="VPN Connections";File="vpn-connections.json";Cmd=@("network","vpn-connection","list")},',
'  @{Label="Virtual WANs";File="virtual-wans.json";Cmd=@("network","vwan","list")},',
'  @{Label="Managed Disks";File="disks.json";Cmd=@("disk","list")},',
'  @{Label="Disk Snapshots";File="snapshots.json";Cmd=@("snapshot","list")},',
'  @{Label="Storage Accounts";File="storage-accounts.json";Cmd=@("storage","account","list")},',
'  @{Label="Private DNS Zones";File="private-dns-zones.json";Cmd=@("network","private-dns","zone","list")},',
'  @{Label="WAF Policies";File="waf-policies.json";Cmd=@("network","application-gateway","waf-policy","list")},',
'  @{Label="Front Door";File="front-door.json";Cmd=@("afd","profile","list")},',
'  @{Label="RBAC Assignments";File="rbac.json";Cmd=@("role","assignment","list")},',
'  @{Label="Resource Groups";File="resource-groups.json";Cmd=@("group","list")}',
')',
'function Export-Region{param([string]$SubName,[string]$OutPath,[int]$Parallel)',
'  $flags=Get-BaseFlags $SubName;New-Item -ItemType Directory -Path $OutPath -Force|Out-Null',
'  $results=$exports|ForEach-Object -ThrottleLimit $Parallel -Parallel{',
'    $fp=Join-Path $using:OutPath $_.File',
'    try{$r=& az @using:flags @($_.Cmd) 2>&1',
'      if($LASTEXITCODE -eq 0){$j=($r|Out-String)|ConvertFrom-Json;$arr=if($j -is [System.Array]){$j}elseif($j.value -is [System.Array]){$j.value}else{@()};if($arr.Count -gt 0){$r|Out-File -FilePath $fp -Encoding utf8;$sz=(Get-Item $fp).Length;@{L=$_.Label;S="OK";D="${sz} bytes"}}else{@{L=$_.Label;S="SKIP";D="empty"}}}',
'      else{$m=($r|Out-String).Trim();if($m.Length -gt 60){$m=$m.Substring(0,60)};@{L=$_.Label;S="SKIP";D=$m}}}',
'    catch{@{L=$_.Label;S="SKIP";D=$_.Exception.Message.Substring(0,[Math]::Min(60,$_.Exception.Message.Length))}}}',
'  foreach($r in $results){$c=if($r.S -eq "OK"){"Green"}else{"Yellow"};Write-Host("  {0,-30} {1} ({2})" -f $r.L,$r.S,$r.D)-ForegroundColor $c}}',
'Write-Host "`n  Azure Network Mapper - Data Export (PowerShell)`n" -ForegroundColor Magenta',
'function Test-HasResources([string[]]$f){try{$r=& az @f network vnet list 2>&1;if($LASTEXITCODE -ne 0){return $false};$v=$r|ConvertFrom-Json;return($v.Count -gt 0)}catch{return $false}}',
'if($Subscriptions){',
'  if(-not $OutputDir){$ts=Get-Date -Format "yyyyMMdd-HHmmss";$OutputDir="./azure-export-multi-${ts}"}',
'  New-Item -ItemType Directory -Path $OutputDir -Force|Out-Null',
'  Write-Host "  Subscriptions: $($subList -join \', \')`n" -ForegroundColor Cyan',
'  foreach($sub in $subList){',
'    Write-Host "`n  === Subscription: $sub ===" -ForegroundColor Magenta',
'    $subDir=Join-Path $OutputDir $sub',
'    Export-Region -SubName $sub -OutPath $subDir -Parallel $MaxParallel}',
'}elseif($AllLocations){',
'  Write-Host "  Mode: All Locations (parallel x$MaxParallel)" -ForegroundColor Cyan',
'  if(-not $OutputDir){$ts=Get-Date -Format "yyyyMMdd-HHmmss";$lb=if($Subscription){$Subscription}else{"default"};$OutputDir="./azure-export-${lb}-alllocations-${ts}"}',
'  New-Item -ItemType Directory -Path $OutputDir -Force|Out-Null',
'  Write-Host "  Output: $OutputDir`n"',
'  Export-Region -SubName $Subscription -OutPath $OutputDir -Parallel $MaxParallel',
'}else{',
'  if(-not $OutputDir){$ts=Get-Date -Format "yyyyMMdd-HHmmss";$lb=if($Subscription){$Subscription}else{"default"};$OutputDir="./azure-export-${lb}-${ts}"}',
'  Write-Host "  Subscription: $($Subscription ? $Subscription : \'default\')  Location: $($Location ? $Location : \'all\')  Output: $OutputDir`n"',
'  Export-Region -SubName $Subscription -OutPath $OutputDir -Parallel $MaxParallel}',
'$af=Get-ChildItem -Path $OutputDir -Filter "*.json" -Recurse -ErrorAction SilentlyContinue',
'$fc=($af|Measure-Object).Count;$tb=($af|Measure-Object -Property Length -Sum).Sum',
'$ts2=if($tb -gt 1MB){"{0:N1} MB" -f($tb/1MB)}elseif($tb -gt 1KB){"{0:N0} KB" -f($tb/1KB)}else{"$tb bytes"}',
'Write-Host "`n  Done! $fc files ($ts2) -> $OutputDir`n" -ForegroundColor Green'
  ].join('\r\n');
  var blob=new Blob([script],{type:'text/plain'});
  downloadBlob(blob,'export-azure-data.ps1');
  _showToast('PowerShell script downloaded — run: ./export-azure-data.ps1');
});
document.getElementById('fileInput').addEventListener('change',async function(){
  const files=[...this.files];
  if(!files.length)return;
  const status=document.getElementById('uploadStatus');
  status.style.display='block';
  status.textContent=`Reading ${files.length} file(s)...`;
  let matched=0,skipped=[];
  for(const f of files){
    let text;
    try{text=await f.text();JSON.parse(text)}catch(e){skipped.push(f.name+' (invalid JSON)');continue}
    const inputId=matchFile(f.name, text);
    if(!inputId){skipped.push(f.name);continue}
    const el=document.getElementById(inputId);
    if(el){el.value=text;el.className='ji valid';matched++}
  }
  // expand sections with data
  document.querySelectorAll('.sec-hdr.collapsed').forEach(h=>{
    const body=h.nextElementSibling;
    if(body){const ta=body.querySelectorAll('.ji.valid');if(ta.length)h.click()}
  });
  let msg=matched+' of '+files.length+' files loaded';
  if(skipped.length)msg+=' | Skipped: '+skipped.join(', ');
  status.textContent=msg;
  status.style.color=skipped.length?'var(--accent-orange)':'var(--accent-green)';
  this.value='';
  if(matched>0){_iamData=null;_parseCache={};renderMap()}
});
