// #region IAC GENERATOR
// === TERRAFORM / ARM / BICEP EXPORT ===
let _iacType='terraform'; // 'terraform' | 'arm' | 'bicep'
let _iacOutput=''; // raw generated text

function _sanitizeName(s){
  if(!s)return 'unnamed';
  return s.replace(/[^a-zA-Z0-9_-]/g,'_').replace(/^[0-9]/,'r$&').replace(/-/g,'_').toLowerCase();
}

function _tfName(resource,prefix){
  const n=resource.Tags&&resource.Tags.find(t=>t.Key==='Name');
  const raw=n?n.Value:(resource.VpcId||resource.SubnetId||resource.GroupId||resource.InstanceId||prefix||'res');
  return _sanitizeName(raw);
}

// --- ID -> TF resource name maps (built during generation) ---
let _tfIdMap={};

function _tfRef(id,attr){
  if(_tfIdMap[id])return _tfIdMap[id]+'.'+attr;
  return '"'+id+'"';
}

// --- Circular SG detection ---
function detectCircularSGs(sgs){
  const graph={};
  sgs.forEach(sg=>{
    graph[sg.GroupId]=new Set();
    (sg.IpPermissions||[]).concat(sg.IpPermissionsEgress||[]).forEach(rule=>{
      (rule.UserIdGroupPairs||[]).forEach(pair=>{
        if(pair.GroupId&&pair.GroupId!==sg.GroupId)graph[sg.GroupId].add(pair.GroupId);
      });
    });
  });
  const cycles=[];
  const visited=new Set(),inStack=new Set();
  function dfs(node,path){
    if(inStack.has(node)){
      const ci=path.indexOf(node);
      if(ci>=0)cycles.push(path.slice(ci));
      return;
    }
    if(visited.has(node))return;
    visited.add(node);inStack.add(node);path.push(node);
    (graph[node]||new Set()).forEach(nb=>dfs(nb,[...path]));
    inStack.delete(node);
  }
  Object.keys(graph).forEach(n=>{if(!visited.has(n))dfs(n,[])});
  return cycles;
}

// --- HCL Generation ---
function generateTerraform(ctx,opts){
  if(!ctx||!ctx.vpcs)return '# No data loaded';
  _tfIdMap={};
  const lines=[];
  const vars=[];
  const imports=[];
  const warnings=[];
  const mode=opts.mode||'import';
  const scopeVpc=opts.scopeVpcId||null;
  const includeVars=opts.includeVars!==false;

  // Filter by scope
  const vpcs=scopeVpc?ctx.vpcs.filter(v=>v.VpcId===scopeVpc):ctx.vpcs;
  const vpcIds=new Set(vpcs.map(v=>v.VpcId));
  const subnets=(ctx.subnets||[]).filter(s=>vpcIds.has(s.VpcId));
  const subIds=new Set(subnets.map(s=>s.SubnetId));
  const sgs=(ctx.sgs||[]).filter(s=>vpcIds.has(s.VpcId));
  const rts=(ctx.rts||[]).filter(r=>{const assoc=(r.Associations||[]); return assoc.some(a=>vpcIds.has(a.SubnetId?subnets.find(s=>s.SubnetId===a.SubnetId)?.VpcId:null))||vpcIds.has(r.VpcId)});
  const nacls=(ctx.nacls||[]).filter(n=>vpcIds.has(n.VpcId));
  const igws=(ctx.igws||[]).filter(g=>(g.Attachments||[]).some(a=>vpcIds.has(a.VpcId)));
  const nats=(ctx.nats||[]).filter(n=>vpcIds.has(n.VpcId));
  const vpces=(ctx.vpces||[]).filter(v=>vpcIds.has(v.VpcId));
  const instances=(ctx.instances||[]).filter(i=>subIds.has(i.SubnetId));
  const rdsInstances=(ctx.rdsInstances||[]).filter(r=>{const sn=r.DBSubnetGroup;return sn&&(sn.Subnets||[]).some(s=>subIds.has(s.SubnetIdentifier))});
  const lambdaFns=(ctx.lambdaFns||[]).filter(l=>{const vc=l.VpcConfig;return vc&&(vc.SubnetIds||[]).some(s=>subIds.has(s))});
  const ecsServices=(ctx.ecsServices||[]).filter(e=>{const nc=(e.networkConfiguration||{}).awsvpcConfiguration;return nc&&(nc.subnets||[]).some(s=>subIds.has(s))});
  const ecacheClusters=(ctx.ecacheClusters||[]).filter(c=>c.CacheSubnetGroupName);
  const redshiftClusters=(ctx.redshiftClusters||[]).filter(c=>c.ClusterSubnetGroupName);
  const albs=(ctx.albs||[]).filter(a=>(a.AvailabilityZones||[]).some(az=>subIds.has(az.SubnetId)));
  const volumes=(ctx.volumes||[]).filter(v=>v.Attachments&&v.Attachments.some(a=>instances.find(i=>i.InstanceId===a.InstanceId)));
  const s3bk=scopeVpc?[]:(ctx.s3bk||[]);
  const peerings=(ctx.peerings||[]).filter(p=>{const a=p.AccepterVpcInfo,r=p.RequesterVpcInfo;return(a&&vpcIds.has(a.VpcId))||(r&&vpcIds.has(r.VpcId))});
  const cfDistributions=scopeVpc?[]:(ctx.cfDistributions||[]);

  // Header
  lines.push('# Generated by Azure Mapper — azurerm provider');
  lines.push('# Date: '+new Date().toISOString().split('T')[0]);
  lines.push('# Mode: '+(mode==='import'?'Import Existing':mode==='create'?'Create New':'Full Recreate'));
  lines.push('#');
  lines.push('# KNOWN LIMITATIONS - Review before applying:');
  lines.push('# - AMI IDs are region-specific and may need updating');
  lines.push('# - Key pair names must exist in the target account');
  lines.push('# - IAM roles/instance profiles are not included');
  lines.push('# - Passwords and secrets are placeholder values');
  lines.push('# - Custom DNS/DHCP options may need manual configuration');
  lines.push('');

  // Provider
  lines.push('terraform {');
  lines.push('  required_providers {');
  lines.push('    azurerm = {');
  lines.push('      source  = "hashicorp/azurerm"');
  lines.push('      version = "~> 3.0"');
  lines.push('    }');
  lines.push('  }');
  lines.push('}');
  lines.push('');
  lines.push('provider "azurerm" {');
  lines.push('  features {}');
  lines.push('  subscription_id = var.azure_subscription_id');
  lines.push('}');
  lines.push('');

  // Variables
  if(includeVars){
    const region=vpcs.length&&(vpcs[0].location||vpcs[0].properties&&vpcs[0].properties.location)?
      (vpcs[0].location||vpcs[0].properties.location):
      (subnets.length&&subnets[0].location?subnets[0].location:'eastus');
    vars.push({name:'azure_subscription_id',desc:'Azure Subscription ID',type:'string',def:'00000000-0000-0000-0000-000000000000'});
    vars.push({name:'azure_location',desc:'Azure region/location',type:'string',def:region});
    vars.push({name:'resource_group_name',desc:'Azure Resource Group name',type:'string',def:'rg-network'});
    const vnCidrs=vpcs.map(v=>v.CidrBlock||v.properties&&v.properties.addressSpace&&v.properties.addressSpace.addressPrefixes&&v.properties.addressSpace.addressPrefixes[0]).filter(Boolean);
    if(vnCidrs.length)vars.push({name:'vnet_address_spaces',desc:'VNet address spaces',type:'list(string)',def:vnCidrs});
    const vmSizes=new Set(instances.map(i=>i.InstanceType||i.properties&&i.properties.hardwareProfile&&i.properties.hardwareProfile.vmSize).filter(Boolean));
    if(vmSizes.size)vars.push({name:'vm_sizes',desc:'VM sizes in use — map from source instance types',type:'map(string)',def:null});
  }

  vars.forEach(v=>{
    lines.push('variable "'+v.name+'" {');
    lines.push('  description = "'+v.desc+'"');
    lines.push('  type        = '+v.type);
    if(v.def!==null&&v.def!==undefined){
      if(Array.isArray(v.def)){
        lines.push('  default     = '+JSON.stringify(v.def));
      }else{
        lines.push('  default     = "'+v.def+'"');
      }
    }
    lines.push('}');
    lines.push('');
  });

  // Detect circular SGs
  const sgCycles=detectCircularSGs(sgs);
  const cyclicSgIds=new Set();
  sgCycles.forEach(c=>c.forEach(id=>cyclicSgIds.add(id)));

  // --- VNets (VPCs) ---
  vpcs.forEach(vpc=>{
    const name=_tfName(vpc,'vnet');
    const vnetId=vpc.id||vpc.VpcId;
    const resName='azurerm_virtual_network.'+name;
    _tfIdMap[vnetId]=resName;
    if(mode==='import')imports.push({to:resName,id:vnetId});
    const vnetName=(vpc.Tags&&vpc.Tags.find(t=>t.Key==='Name')?vpc.Tags.find(t=>t.Key==='Name').Value:(vpc.name||vnetId));
    lines.push('# VNet: '+vnetName);
    lines.push('resource "azurerm_virtual_network" "'+name+'" {');
    lines.push('  name                = "'+(vpc.name||vnetName)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    const cidr=vpc.CidrBlock||(vpc.properties&&vpc.properties.addressSpace&&vpc.properties.addressSpace.addressPrefixes&&vpc.properties.addressSpace.addressPrefixes[0])||'10.0.0.0/16';
    lines.push('  address_space       = ["'+cidr+'"]');
    _writeTags(lines,vpc);
    lines.push('}');
    lines.push('');
  });

  // --- Subnets ---
  subnets.forEach(sub=>{
    const name=_tfName(sub,'subnet');
    const subId=sub.id||sub.SubnetId;
    const parentVnetId=sub.VpcId||(sub.id&&sub.id.split('/subnets/')[0])||'';
    const resName='azurerm_subnet.'+name;
    _tfIdMap[subId]=resName;
    if(mode==='import')imports.push({to:resName,id:subId});
    lines.push('resource "azurerm_subnet" "'+name+'" {');
    lines.push('  name                 = "'+(sub.name||name)+'"');
    lines.push('  resource_group_name  = var.resource_group_name');
    lines.push('  virtual_network_name = '+_tfRef(parentVnetId,'name'));
    const prefix=sub.CidrBlock||(sub.properties&&sub.properties.addressPrefix)||'10.0.0.0/24';
    lines.push('  address_prefixes     = ["'+prefix+'"]');
    lines.push('}');
    lines.push('');
  });

  // --- Route Tables (UDRs) ---
  rts.forEach(rt=>{
    const name=_tfName(rt,'rt');
    const rtId=rt.id||rt.RouteTableId;
    const resName='azurerm_route_table.'+name;
    _tfIdMap[rtId]=resName;
    if(mode==='import')imports.push({to:resName,id:rtId});
    lines.push('resource "azurerm_route_table" "'+name+'" {');
    lines.push('  name                = "'+(rt.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    (rt.Routes||rt.properties&&rt.properties.routes||[]).forEach(route=>{
      if(route.GatewayId==='local')return;
      const dest=route.DestinationCidrBlock||route.properties&&route.properties.addressPrefix||'';
      const nh=route.GatewayId||route.NatGatewayId||route.properties&&route.properties.nextHopType||'None';
      if(!dest)return;
      lines.push('');
      lines.push('  route {');
      lines.push('    name           = "'+(route.name||('route-'+dest.replace(/[^a-zA-Z0-9]/g,'-')))+'"');
      lines.push('    address_prefix = "'+dest+'"');
      lines.push('    next_hop_type  = "'+(nh==='local'?'VnetLocal':nh)+'"');
      lines.push('  }');
    });
    _writeTags(lines,rt);
    lines.push('}');
    lines.push('');
    // RT-Subnet associations
    (rt.Associations||[]).forEach((assoc,ai)=>{
      if(assoc.Main)return;
      if(!assoc.SubnetId)return;
      const aname=name+'_assoc_'+ai;
      lines.push('resource "azurerm_subnet_route_table_association" "'+aname+'" {');
      lines.push('  subnet_id      = '+_tfRef(assoc.SubnetId,'id'));
      lines.push('  route_table_id = '+_tfRef(rtId,'id'));
      lines.push('}');
      lines.push('');
    });
  });

  // --- NAT Gateways ---
  nats.forEach(nat=>{
    const name=_tfName(nat,'nat');
    const natId=nat.id||nat.NatGatewayId;
    const resName='azurerm_nat_gateway.'+name;
    _tfIdMap[natId]=resName;
    if(mode==='import')imports.push({to:resName,id:natId});
    lines.push('resource "azurerm_nat_gateway" "'+name+'" {');
    lines.push('  name                = "'+(nat.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    lines.push('  sku_name            = "Standard"');
    _writeTags(lines,nat);
    lines.push('}');
    lines.push('');
    if(nat.SubnetId){
      lines.push('resource "azurerm_subnet_nat_gateway_association" "'+name+'_assoc" {');
      lines.push('  subnet_id      = '+_tfRef(nat.SubnetId,'id'));
      lines.push('  nat_gateway_id = '+_tfRef(natId,'id'));
      lines.push('}');
      lines.push('');
    }
  });

  // --- NSGs (Security Groups) ---
  sgs.forEach(sg=>{
    const name=_tfName(sg,'nsg');
    const sgId=sg.id||sg.GroupId;
    const resName='azurerm_network_security_group.'+name;
    _tfIdMap[sgId]=resName;
    if(mode==='import')imports.push({to:resName,id:sgId});
    lines.push('resource "azurerm_network_security_group" "'+name+'" {');
    lines.push('  name                = "'+(sg.GroupName||sg.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    // Inbound rules
    let ruleIdx=100;
    (sg.IpPermissions||sg.properties&&sg.properties.securityRules||[]).forEach(rule=>{
      const proto=rule.IpProtocol||rule.properties&&rule.properties.protocol||'*';
      const fromPort=rule.FromPort!=null?rule.FromPort:(rule.properties&&rule.properties.destinationPortRange?rule.properties.destinationPortRange.split('-')[0]:0);
      const toPort=rule.ToPort!=null?rule.ToPort:(rule.properties&&rule.properties.destinationPortRange?rule.properties.destinationPortRange.split('-').pop():65535);
      const cidrs=(rule.IpRanges||[]).map(r=>r.CidrIp).filter(Boolean);
      const src=cidrs.length?cidrs[0]:'*';
      lines.push('');
      lines.push('  security_rule {');
      lines.push('    name                       = "inbound-rule-'+ruleIdx+'"');
      lines.push('    priority                   = '+ruleIdx);
      lines.push('    direction                  = "Inbound"');
      lines.push('    access                     = "Allow"');
      lines.push('    protocol                   = "'+(proto==='-1'?'*':proto)+'"');
      lines.push('    source_port_range          = "*"');
      lines.push('    destination_port_range     = "'+(fromPort===toPort?String(fromPort):fromPort+'-'+toPort)+'"');
      lines.push('    source_address_prefix      = "'+src+'"');
      lines.push('    destination_address_prefix = "*"');
      lines.push('  }');
      ruleIdx+=10;
    });
    _writeTags(lines,sg);
    lines.push('}');
    lines.push('');
    // Associate NSG to subnet if VpcId available
    if(sg.VpcId){
      // NSG-subnet associations are managed per subnet in Azure — emit a comment
      lines.push('# Associate '+name+' to relevant subnets via azurerm_subnet_network_security_group_association');
      lines.push('');
    }
  });

  // --- Private Endpoints (VPC Endpoints) ---
  vpces.forEach(vpce=>{
    const name=_tfName(vpce,'pvtep');
    const vpceId=vpce.id||vpce.VpcEndpointId;
    const resName='azurerm_private_endpoint.'+name;
    _tfIdMap[vpceId]=resName;
    if(mode==='import')imports.push({to:resName,id:vpceId});
    lines.push('resource "azurerm_private_endpoint" "'+name+'" {');
    lines.push('  name                = "'+(vpce.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    const subnetId=vpce.SubnetIds&&vpce.SubnetIds[0]||vpce.SubnetId||'';
    if(subnetId)lines.push('  subnet_id           = '+_tfRef(subnetId,'id'));
    lines.push('');
    lines.push('  private_service_connection {');
    lines.push('    name                           = "'+(vpce.name||name)+'-psc"');
    lines.push('    private_connection_resource_id = "PLACEHOLDER" # Set actual resource ID');
    lines.push('    is_manual_connection           = false');
    if(vpce.ServiceName)lines.push('    subresource_names              = ["'+(vpce.ServiceName.split('.').pop())+'"]');
    lines.push('  }');
    _writeTags(lines,vpce);
    lines.push('}');
    lines.push('');
  });

  // --- Virtual Machines ---
  instances.forEach(inst=>{
    const name=_tfName(inst,'vm');
    const instId=inst.id||inst.InstanceId;
    const resName='azurerm_linux_virtual_machine.'+name;
    _tfIdMap[instId]=resName;
    if(mode==='import')imports.push({to:resName,id:instId});
    lines.push('resource "azurerm_linux_virtual_machine" "'+name+'" {');
    lines.push('  name                = "'+(inst.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    const vmSize=inst.InstanceType||inst.properties&&inst.properties.hardwareProfile&&inst.properties.hardwareProfile.vmSize||'Standard_D2s_v3';
    lines.push('  size                = "'+vmSize+'" # Map EC2 instance type to Azure VM size');
    lines.push('  admin_username      = "azureuser"');
    lines.push('');
    lines.push('  admin_ssh_key {');
    lines.push('    username   = "azureuser"');
    lines.push('    public_key = file("~/.ssh/id_rsa.pub") # Set actual public key path');
    lines.push('  }');
    lines.push('');
    lines.push('  network_interface_ids = []  # PLACEHOLDER: reference azurerm_network_interface resources');
    lines.push('');
    lines.push('  os_disk {');
    lines.push('    caching              = "ReadWrite"');
    lines.push('    storage_account_type = "Premium_LRS"');
    lines.push('  }');
    lines.push('');
    lines.push('  source_image_reference {');
    const imgId=inst.ImageId||'';
    lines.push('    publisher = "Canonical" # Map from AMI: '+imgId);
    lines.push('    offer     = "UbuntuServer"');
    lines.push('    sku       = "18.04-LTS"');
    lines.push('    version   = "latest"');
    lines.push('  }');
    _writeTags(lines,inst);
    lines.push('}');
    lines.push('');
  });

  // --- Managed Disks (EBS Volumes) ---
  volumes.forEach(vol=>{
    const name=_tfName(vol,'disk');
    const volId=vol.id||vol.VolumeId;
    const resName='azurerm_managed_disk.'+name;
    _tfIdMap[volId]=resName;
    if(mode==='import')imports.push({to:resName,id:volId});
    lines.push('resource "azurerm_managed_disk" "'+name+'" {');
    lines.push('  name                 = "'+(vol.name||name)+'"');
    lines.push('  location             = var.azure_location');
    lines.push('  resource_group_name  = var.resource_group_name');
    const skuMap={'gp2':'Standard_LRS','gp3':'StandardSSD_LRS','io1':'Premium_LRS','io2':'UltraSSD_LRS'};
    lines.push('  storage_account_type = "'+(skuMap[vol.VolumeType]||'StandardSSD_LRS')+'"');
    lines.push('  create_option        = "Empty"');
    if(vol.Size)lines.push('  disk_size_gb         = '+vol.Size);
    if(vol.Encrypted)lines.push('  encryption_settings { enabled = true }');
    _writeTags(lines,vol);
    lines.push('}');
    lines.push('');
  });

  // --- Load Balancers ---
  albs.forEach(alb=>{
    const name=_tfName(alb,'lb');
    const lbId=alb.id||alb.LoadBalancerArn;
    const resName='azurerm_lb.'+name;
    _tfIdMap[lbId]=resName;
    if(mode==='import')imports.push({to:resName,id:lbId});
    lines.push('resource "azurerm_lb" "'+name+'" {');
    lines.push('  name                = "'+(alb.LoadBalancerName||alb.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    lines.push('  sku                 = "Standard"');
    lines.push('');
    lines.push('  frontend_ip_configuration {');
    lines.push('    name                 = "frontend"');
    lines.push('    public_ip_address_id = "PLACEHOLDER" # Set actual public IP resource ID');
    lines.push('  }');
    _writeTags(lines,alb);
    lines.push('}');
    lines.push('');
  });

  // --- SQL Databases (RDS Instances) ---
  rdsInstances.forEach(rds=>{
    const name=_sanitizeName(rds.DBInstanceIdentifier||rds.name||'sql');
    const resName='azurerm_mssql_server.'+name;
    _tfIdMap[rds.DBInstanceIdentifier||rds.name]=resName;
    if(mode==='import')imports.push({to:resName,id:rds.DBInstanceIdentifier||''});
    lines.push('resource "azurerm_mssql_server" "'+name+'" {');
    lines.push('  name                         = "'+(rds.DBInstanceIdentifier||name)+'"');
    lines.push('  location                     = var.azure_location');
    lines.push('  resource_group_name          = var.resource_group_name');
    lines.push('  version                      = "12.0"');
    lines.push('  administrator_login          = "sqladmin" # PLACEHOLDER');
    lines.push('  administrator_login_password = "CHANGE_ME" # PLACEHOLDER - use Key Vault');
    lines.push('}');
    lines.push('');
    lines.push('resource "azurerm_mssql_database" "'+name+'_db" {');
    lines.push('  name      = "'+(rds.DBName||name+'-db')+'"');
    lines.push('  server_id = azurerm_mssql_server.'+name+'.id');
    if(rds.DBInstanceClass)lines.push('  sku_name  = "GP_S_Gen5_2" # Map from: '+rds.DBInstanceClass);
    lines.push('}');
    lines.push('');
  });

  // --- Redis Cache (ElastiCache) ---
  ecacheClusters.forEach(ec=>{
    const name=_sanitizeName(ec.name||ec.CacheClusterId||'redis');
    const resName='azurerm_redis_cache.'+name;
    _tfIdMap[ec.CacheClusterId||ec.name]=resName;
    if(mode==='import')imports.push({to:resName,id:ec.id||ec.CacheClusterId||''});
    lines.push('resource "azurerm_redis_cache" "'+name+'" {');
    lines.push('  name                = "'+(ec.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    lines.push('  capacity            = '+(ec.NumCacheNodes||1));
    lines.push('  family              = "C"');
    lines.push('  sku_name            = "Standard"');
    lines.push('  enable_non_ssl_port = false');
    lines.push('  minimum_tls_version = "1.2"');
    lines.push('}');
    lines.push('');
  });

  // --- AKS Clusters (Redshift/ECS → AKS) ---
  redshiftClusters.forEach(rs=>{
    const name=_sanitizeName(rs.name||rs.ClusterIdentifier||'aks');
    const resName='azurerm_kubernetes_cluster.'+name;
    _tfIdMap[rs.ClusterIdentifier||rs.name]=resName;
    if(mode==='import')imports.push({to:resName,id:rs.id||rs.ClusterIdentifier||''});
    lines.push('resource "azurerm_kubernetes_cluster" "'+name+'" {');
    lines.push('  name                = "'+(rs.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    lines.push('  dns_prefix          = "'+(rs.name||name)+'"');
    lines.push('');
    lines.push('  default_node_pool {');
    lines.push('    name       = "default"');
    lines.push('    node_count = '+(rs.NumberOfNodes||2));
    lines.push('    vm_size    = "Standard_D2_v2"');
    lines.push('  }');
    lines.push('');
    lines.push('  identity {');
    lines.push('    type = "SystemAssigned"');
    lines.push('  }');
    _writeTags(lines,rs);
    lines.push('}');
    lines.push('');
  });

  // --- Function Apps (Lambda) ---
  lambdaFns.forEach(fn=>{
    const name=_sanitizeName(fn.name||fn.FunctionName||'funcapp');
    const resName='azurerm_function_app.'+name;
    _tfIdMap[fn.FunctionName||fn.name]=resName;
    if(mode==='import')imports.push({to:resName,id:fn.id||fn.FunctionName||''});
    lines.push('resource "azurerm_function_app" "'+name+'" {');
    lines.push('  name                       = "'+(fn.name||name)+'"');
    lines.push('  location                   = var.azure_location');
    lines.push('  resource_group_name        = var.resource_group_name');
    lines.push('  app_service_plan_id        = "PLACEHOLDER" # Set actual App Service Plan ID');
    lines.push('  storage_account_name       = "PLACEHOLDER" # Set actual storage account name');
    lines.push('  storage_account_access_key = "PLACEHOLDER" # Use Key Vault reference');
    const runtime=fn.Runtime||fn.properties&&fn.properties.siteConfig&&fn.properties.siteConfig.linuxFxVersion||'';
    if(runtime)lines.push('  # Runtime: '+runtime+' — set app_settings FUNCTIONS_WORKER_RUNTIME accordingly');
    const vc=fn.VpcConfig;
    if(vc&&(vc.SubnetIds||[]).length){
      lines.push('');
      lines.push('  site_config {');
      lines.push('    vnet_route_all_enabled = true');
      lines.push('  }');
    }
    _writeTags(lines,fn);
    lines.push('}');
    lines.push('');
  });

  // --- Container Groups (ECS Services) ---
  ecsServices.forEach(svc=>{
    const name=_sanitizeName(svc.name||svc.serviceName||'container');
    lines.push('# Container Group: '+(svc.name||svc.serviceName));
    lines.push('# NOTE: ECS services map to Azure Container Groups or AKS deployments.');
    lines.push('# This skeleton uses azurerm_container_group. Adjust for AKS if needed.');
    lines.push('resource "azurerm_container_group" "'+name+'" {');
    lines.push('  name                = "'+(svc.name||name)+'"');
    lines.push('  location            = var.azure_location');
    lines.push('  resource_group_name = var.resource_group_name');
    lines.push('  ip_address_type     = "Private"');
    lines.push('  os_type             = "Linux"');
    lines.push('');
    lines.push('  container {');
    lines.push('    name   = "'+(svc.name||name)+'"');
    lines.push('    image  = "PLACEHOLDER" # Set actual container image');
    lines.push('    cpu    = "0.5"');
    lines.push('    memory = "1.5"');
    lines.push('  }');
    _writeTags(lines,svc);
    lines.push('}');
    lines.push('');
  });

  // --- Storage Accounts ---
  s3bk.forEach(bk=>{
    const name=_sanitizeName(bk.name||bk.Name||'storage');
    const resName='azurerm_storage_account.'+name;
    _tfIdMap[bk.Name||bk.name]=resName;
    if(mode==='import')imports.push({to:resName,id:bk.id||bk.Name||''});
    lines.push('resource "azurerm_storage_account" "'+name+'" {');
    lines.push('  name                     = "'+(bk.name||name)+'" # Must be globally unique, 3-24 chars');
    lines.push('  resource_group_name      = var.resource_group_name');
    lines.push('  location                 = var.azure_location');
    lines.push('  account_tier             = "Standard"');
    lines.push('  account_replication_type = "LRS"');
    lines.push('  min_tls_version          = "TLS1_2"');
    _writeTags(lines,bk);
    lines.push('}');
    lines.push('');
  });

  // --- VNet Peerings ---
  peerings.forEach(peer=>{
    const name=_sanitizeName(peer.name||peer.VpcPeeringConnectionId||'peer');
    const peerId=peer.id||peer.VpcPeeringConnectionId;
    const resName='azurerm_virtual_network_peering.'+name;
    _tfIdMap[peerId]=resName;
    if(mode==='import')imports.push({to:resName,id:peerId});
    const localVnetId=peer.RequesterVpcInfo&&peer.RequesterVpcInfo.VpcId||peer.properties&&peer.properties.remoteVirtualNetwork&&peer.properties.remoteVirtualNetwork.id||'';
    const remoteVnetId=peer.AccepterVpcInfo&&peer.AccepterVpcInfo.VpcId||'';
    lines.push('resource "azurerm_virtual_network_peering" "'+name+'" {');
    lines.push('  name                      = "'+(peer.name||name)+'"');
    lines.push('  resource_group_name       = var.resource_group_name');
    if(localVnetId)lines.push('  virtual_network_name      = '+_tfRef(localVnetId,'name'));
    if(remoteVnetId)lines.push('  remote_virtual_network_id = '+_tfRef(remoteVnetId,'id'));
    lines.push('  allow_virtual_network_access = true');
    lines.push('  allow_forwarded_traffic      = true');
    lines.push('}');
    lines.push('');
  });

  // --- Azure Front Door / CDN (CloudFront) ---
  cfDistributions.forEach(cf=>{
    const name=_sanitizeName(cf.name||cf.Id||'frontdoor');
    lines.push('# Azure Front Door Profile: '+(cf.name||cf.DomainName||cf.Id));
    lines.push('# NOTE: Azure Front Door replaces CloudFront. This is a skeleton.');
    lines.push('resource "azurerm_cdn_frontdoor_profile" "'+name+'" {');
    lines.push('  name                = "'+(cf.name||name)+'"');
    lines.push('  resource_group_name = var.resource_group_name');
    lines.push('  sku_name            = "Standard_AzureFrontDoor"');
    _writeTags(lines,cf);
    lines.push('}');
    lines.push('');
  });

  // --- Import blocks (Terraform 1.5+) ---
  if(mode==='import'&&imports.length){
    lines.push('');
    lines.push('# === Import Blocks (Terraform 1.5+) ===');
    lines.push('# Run: terraform plan to verify imports match existing state');
    lines.push('');
    imports.forEach(imp=>{
      lines.push('import {');
      lines.push('  to = '+imp.to);
      lines.push('  id = "'+imp.id+'"');
      lines.push('}');
      lines.push('');
    });
  }

  // Warnings
  if(instances.some(i=>i.ImageId))warnings.push('Source image references are placeholders. Map AMI IDs to Azure Marketplace images for your OS.');
  if(instances.some(i=>i.KeyName))warnings.push('SSH key paths are placeholders. Update admin_ssh_key.public_key in each VM resource.');
  if(rdsInstances.length||redshiftClusters.length)warnings.push('Database passwords are placeholders. Use Azure Key Vault references instead.');
  if(sgCycles.length)warnings.push(sgCycles.length+' circular NSG reference(s) detected. Review security_rule priorities.');

  _iacOutput=lines.join('\n');
  return {code:_iacOutput,warnings:warnings,stats:{vpcs:vpcs.length,subnets:subnets.length,sgs:sgs.length,instances:instances.length,total:imports.length||lines.filter(l=>l.startsWith('resource ')).length}};
}

function _writeTags(lines,resource){
  // Support both Azure flat tag object and Tags array format
  let tagObj={};
  if(resource.tags&&typeof resource.tags==='object'&&!Array.isArray(resource.tags)){
    tagObj=resource.tags;
  }else if(Array.isArray(resource.Tags)){
    resource.Tags.filter(t=>t.Key&&!t.Key.startsWith('aws:')&&!t.Key.startsWith('microsoft:')).forEach(t=>{tagObj[t.Key]=t.Value||'';});
  }
  const keys=Object.keys(tagObj);
  if(!keys.length)return;
  lines.push('');
  lines.push('  tags = {');
  keys.forEach(k=>{
    const safeK=k.match(/^[a-zA-Z_][a-zA-Z0-9_]*$/)?k:('"'+k+'"');
    lines.push('    '+safeK+' = "'+((tagObj[k]||'').replace(/\\/g,'\\\\').replace(/"/g,'\\"'))+'"');
  });
  lines.push('  }');
}

function _writeSGRule(lines,rule){
  const fromPort=rule.FromPort!=null?rule.FromPort:0;
  const toPort=rule.ToPort!=null?rule.ToPort:0;
  const proto=rule.IpProtocol||'-1';
  lines.push('    protocol    = "'+proto+'"');
  lines.push('    from_port   = '+fromPort);
  lines.push('    to_port     = '+toPort);
  const cidrs=(rule.IpRanges||[]).map(r=>r.CidrIp).filter(Boolean);
  const v6cidrs=(rule.Ipv6Ranges||[]).map(r=>r.CidrIpv6).filter(Boolean);
  const sgRefs=(rule.UserIdGroupPairs||[]).map(p=>p.GroupId).filter(Boolean);
  if(cidrs.length)lines.push('    cidr_blocks = '+JSON.stringify(cidrs));
  if(v6cidrs.length)lines.push('    ipv6_cidr_blocks = '+JSON.stringify(v6cidrs));
  if(sgRefs.length)lines.push('    security_groups = ['+sgRefs.map(s=>_tfRef(s,'id')).join(', ')+']');
  const desc=(rule.IpRanges||[]).find(r=>r.Description);
  if(desc)lines.push('    description = "'+(desc.Description||'').replace(/\\/g,'\\\\').replace(/"/g,'\\"')+'"');
}

function _writeSGRuleFlat(lines,rule){
  const fromPort=rule.FromPort!=null?rule.FromPort:0;
  const toPort=rule.ToPort!=null?rule.ToPort:0;
  const proto=rule.IpProtocol||'-1';
  lines.push('  protocol         = "'+proto+'"');
  lines.push('  from_port        = '+fromPort);
  lines.push('  to_port          = '+toPort);
  const cidrs=(rule.IpRanges||[]).map(r=>r.CidrIp).filter(Boolean);
  const sgRefs=(rule.UserIdGroupPairs||[]).map(p=>p.GroupId).filter(Boolean);
  if(cidrs.length)lines.push('  cidr_blocks      = '+JSON.stringify(cidrs));
  if(sgRefs.length&&sgRefs[0])lines.push('  source_security_group_id = '+_tfRef(sgRefs[0],'id'));
}

// --- ARM Template Generation ---
function generateArmTemplate(ctx,opts){
  if(!ctx||!ctx.vpcs)return '// No data loaded';
  const scopeVpc=opts.scopeVpcId||null;
  const vpcs=scopeVpc?ctx.vpcs.filter(v=>(v.id||v.VpcId)===scopeVpc):ctx.vpcs;
  const vpcIds=new Set(vpcs.map(v=>v.id||v.VpcId));
  const subnets=(ctx.subnets||[]).filter(s=>vpcIds.has(s.VpcId)||vpcIds.has(s.id&&s.id.split('/subnets/')[0]));
  const subIds=new Set(subnets.map(s=>s.id||s.SubnetId));
  const sgs=(ctx.sgs||[]).filter(s=>vpcIds.has(s.VpcId)||s.id);
  const nats=(ctx.nats||[]).filter(n=>vpcIds.has(n.VpcId)||n.id);
  const instances=(ctx.instances||[]).filter(i=>subIds.has(i.SubnetId)||i.id);
  const rts=(ctx.rts||[]).filter(r=>(r.VpcId&&vpcIds.has(r.VpcId))||r.id);
  const rdsInstances=(ctx.rdsInstances||[]);
  const albs=(ctx.albs||[]).filter(a=>(a.AvailabilityZones||[]).some(az=>subIds.has(az.SubnetId))||a.id);

  const warnings=[];
  const location='[parameters(\'location\')]';
  const rgName='[parameters(\'resourceGroupName\')]';

  // ARM template skeleton
  const template={
    '$schema':'https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#',
    contentVersion:'1.0.0.0',
    parameters:{
      location:{type:'string',defaultValue:'eastus',metadata:{description:'Azure region for all resources'}},
      resourceGroupName:{type:'string',defaultValue:'rg-network',metadata:{description:'Resource group name'}},
      adminPassword:{type:'securestring',metadata:{description:'Admin password for VMs and databases — use Key Vault reference'}}
    },
    variables:{},
    resources:[],
    outputs:{}
  };

  const res=template.resources;

  // Helper: ARM tags from resource
  function armTags(resource){
    if(resource.tags&&typeof resource.tags==='object'&&!Array.isArray(resource.tags))return resource.tags;
    const t={};
    (resource.Tags||[]).filter(tag=>tag.Key&&!tag.Key.startsWith('aws:')&&!tag.Key.startsWith('microsoft:')).forEach(tag=>{t[tag.Key]=tag.Value||'';});
    return t;
  }
  function armName(resource,prefix){
    const n=resource.Tags&&resource.Tags.find(t=>t.Key==='Name');
    const raw=n?n.Value:(resource.name||resource.VpcId||resource.SubnetId||resource.GroupId||resource.id||prefix||'res');
    return raw.replace(/[^a-zA-Z0-9-]/g,'-').toLowerCase().slice(0,80);
  }

  // VNets
  vpcs.forEach(vpc=>{
    const vname=armName(vpc,'vnet');
    const cidr=vpc.CidrBlock||(vpc.properties&&vpc.properties.addressSpace&&vpc.properties.addressSpace.addressPrefixes&&vpc.properties.addressSpace.addressPrefixes[0])||'10.0.0.0/16';
    res.push({
      type:'Microsoft.Network/virtualNetworks',
      apiVersion:'2023-04-01',
      name:vpc.name||vname,
      location:location,
      tags:armTags(vpc),
      properties:{
        addressSpace:{addressPrefixes:[cidr]},
        subnets:subnets.filter(s=>s.VpcId===(vpc.id||vpc.VpcId)||(s.id&&s.id.startsWith((vpc.id||'')))).map(s=>({
          name:s.name||armName(s,'subnet'),
          properties:{
            addressPrefix:s.CidrBlock||s.properties&&s.properties.addressPrefix||'10.0.0.0/24'
          }
        }))
      }
    });
  });

  // NSGs
  sgs.forEach(sg=>{
    const sgname=armName(sg,'nsg');
    let ruleIdx=100;
    const securityRules=(sg.IpPermissions||sg.properties&&sg.properties.securityRules||[]).map(rule=>{
      const proto=rule.IpProtocol||rule.properties&&rule.properties.protocol||'*';
      const fromPort=rule.FromPort!=null?String(rule.FromPort):(rule.properties&&rule.properties.destinationPortRange||'*');
      const toPort=rule.ToPort!=null?String(rule.ToPort):fromPort;
      const cidrs=(rule.IpRanges||[]).map(r=>r.CidrIp).filter(Boolean);
      const r={
        name:'inbound-rule-'+(ruleIdx),
        properties:{
          priority:ruleIdx,
          protocol:proto==='-1'?'*':proto,
          access:'Allow',
          direction:'Inbound',
          sourceAddressPrefix:cidrs.length?cidrs[0]:'*',
          sourcePortRange:'*',
          destinationAddressPrefix:'*',
          destinationPortRange:fromPort===toPort?fromPort:fromPort+'-'+toPort
        }
      };
      ruleIdx+=10;
      return r;
    });
    res.push({
      type:'Microsoft.Network/networkSecurityGroups',
      apiVersion:'2023-04-01',
      name:sg.GroupName||sg.name||sgname,
      location:location,
      tags:armTags(sg),
      properties:{securityRules:securityRules}
    });
  });

  // Route Tables (UDRs)
  rts.forEach(rt=>{
    const rtname=armName(rt,'udr');
    const routes=(rt.Routes||rt.properties&&rt.properties.routes||[])
      .filter(r=>r.GatewayId!=='local')
      .map((r,i)=>({
        name:r.name||'route-'+i,
        properties:{
          addressPrefix:r.DestinationCidrBlock||r.properties&&r.properties.addressPrefix||'',
          nextHopType:r.NatGatewayId?'VirtualAppliance':(r.GatewayId?'Internet':'None'),
          nextHopIpAddress:r.NatGatewayId||r.properties&&r.properties.nextHopIpAddress||undefined
        }
      }));
    res.push({
      type:'Microsoft.Network/routeTables',
      apiVersion:'2023-04-01',
      name:rt.name||rtname,
      location:location,
      tags:armTags(rt),
      properties:{routes:routes}
    });
  });

  // NAT Gateways
  nats.forEach(nat=>{
    const natname=armName(nat,'nat');
    res.push({
      type:'Microsoft.Network/natGateways',
      apiVersion:'2023-04-01',
      name:nat.name||natname,
      location:location,
      sku:{name:'Standard'},
      tags:armTags(nat),
      properties:{idleTimeoutInMinutes:4}
    });
  });

  // VMs
  instances.forEach(inst=>{
    const vmname=armName(inst,'vm');
    const vmSize=inst.InstanceType||inst.properties&&inst.properties.hardwareProfile&&inst.properties.hardwareProfile.vmSize||'Standard_D2s_v3';
    res.push({
      type:'Microsoft.Compute/virtualMachines',
      apiVersion:'2023-03-01',
      name:inst.name||vmname,
      location:location,
      tags:armTags(inst),
      properties:{
        hardwareProfile:{vmSize:vmSize+' /* map from source instance type */'},
        storageProfile:{
          imageReference:{publisher:'Canonical',offer:'UbuntuServer',sku:'18.04-LTS',version:'latest'},
          osDisk:{createOption:'FromImage',managedDisk:{storageAccountType:'Premium_LRS'}}
        },
        osProfile:{
          computerName:inst.name||vmname,
          adminUsername:'azureuser',
          adminPassword:'[parameters(\'adminPassword\')]'
        },
        networkProfile:{networkInterfaces:[]}
      }
    });
  });

  // Load Balancers
  albs.forEach(alb=>{
    const lbname=armName(alb,'lb');
    res.push({
      type:'Microsoft.Network/loadBalancers',
      apiVersion:'2023-04-01',
      name:alb.LoadBalancerName||alb.name||lbname,
      location:location,
      sku:{name:'Standard'},
      tags:armTags(alb),
      properties:{
        frontendIPConfigurations:[{
          name:'frontend',
          properties:{publicIPAddress:{id:'PLACEHOLDER /* set actual public IP resource ID */'}}
        }],
        backendAddressPools:[{name:'backend'}],
        loadBalancingRules:[],
        probes:[]
      }
    });
  });

  // SQL Servers (RDS)
  rdsInstances.forEach(rds=>{
    const srvname=armName({name:rds.DBInstanceIdentifier||rds.name},'sql');
    res.push({
      type:'Microsoft.Sql/servers',
      apiVersion:'2022-05-01-preview',
      name:rds.DBInstanceIdentifier||rds.name||srvname,
      location:location,
      tags:armTags(rds),
      properties:{
        administratorLogin:'sqladmin',
        administratorLoginPassword:'[parameters(\'adminPassword\')]',
        version:'12.0'
      }
    });
    res.push({
      type:'Microsoft.Sql/servers/databases',
      apiVersion:'2022-05-01-preview',
      name:(rds.DBInstanceIdentifier||srvname)+'/'+(rds.DBName||'maindb'),
      location:location,
      dependsOn:['[resourceId(\'Microsoft.Sql/servers\', \''+(rds.DBInstanceIdentifier||srvname)+'\')]'],
      sku:{name:'GP_S_Gen5',tier:'GeneralPurpose',family:'Gen5',capacity:2},
      properties:{collation:'SQL_Latin1_General_CP1_CI_AS'}
    });
  });

  // Outputs
  vpcs.forEach((vpc,i)=>{
    const vname=vpc.name||armName(vpc,'vnet');
    template.outputs['vnet'+i+'Id']={
      type:'string',
      value:'[resourceId(\'Microsoft.Network/virtualNetworks\', \''+vname+'\')]'
    };
  });

  // Serialize
  const format=opts.format||'json';
  const code=JSON.stringify(template,null,2);

  _iacOutput=code;
  return {code:code,warnings:warnings,stats:{resources:res.length}};
}

function _cfnTags(resource){
  // Kept for Checkov generator compatibility — returns flat Azure tag object
  if(resource.tags&&typeof resource.tags==='object'&&!Array.isArray(resource.tags))return resource.tags;
  const t={};
  (resource.Tags||[]).filter(tag=>tag.Key&&!tag.Key.startsWith('aws:')&&!tag.Key.startsWith('microsoft:')).forEach(tag=>{t[tag.Key]=tag.Value||'';});
  return t;
}

function _cfnSGRule(rule){
  // Kept for Checkov generator compatibility
  const r={IpProtocol:rule.IpProtocol||'-1'};
  if(rule.FromPort!=null)r.FromPort=rule.FromPort;
  if(rule.ToPort!=null)r.ToPort=rule.ToPort;
  const cidrs=(rule.IpRanges||[]).map(c=>c.CidrIp).filter(Boolean);
  if(cidrs.length)r.CidrIp=cidrs[0];
  const sgRefs=(rule.UserIdGroupPairs||[]).map(p=>p.GroupId).filter(Boolean);
  if(sgRefs.length)r.SourceSecurityGroupId=sgRefs[0];
  return r;
}

function _cfnSGRuleProps(rule){
  // Kept for Checkov generator compatibility
  const r={};
  if(rule.FromPort!=null)r.FromPort=rule.FromPort;
  if(rule.ToPort!=null)r.ToPort=rule.ToPort;
  const cidrs=(rule.IpRanges||[]).map(c=>c.CidrIp).filter(Boolean);
  if(cidrs.length)r.CidrIp=cidrs[0];
  const sgRefs=(rule.UserIdGroupPairs||[]).map(p=>p.GroupId).filter(Boolean);
  if(sgRefs.length)r.SourceSecurityGroupId=sgRefs[0];
  return r;
}

// === CHECKOV ARM GENERATOR ===
// Generates a security-property-rich ARM template for Checkov scanning (--framework arm)
function _ckId(name,prefix,seen){
  var base=(name||prefix||'Res').replace(/[^a-zA-Z0-9-]/g,'-').toLowerCase();
  if(!base||/^\d/.test(base)) base=(prefix||'r')+'-'+base;
  var id=base,i=2;
  while(seen.has(id)){id=base+'-'+i;i++;}
  seen.add(id);
  return id;
}
function _ckVnets(vpcs,resources,seen){
  vpcs.forEach(function(v){
    var id=_ckId(v.name||gn(v,v.VpcId),'vnet',seen);
    var cidr=v.CidrBlock||(v.properties&&v.properties.addressSpace&&v.properties.addressSpace.addressPrefixes&&v.properties.addressSpace.addressPrefixes[0])||'10.0.0.0/16';
    resources.push({type:'Microsoft.Network/virtualNetworks',apiVersion:'2023-04-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(v),
      properties:{addressSpace:{addressPrefixes:[cidr]},enableDdosProtection:false}});
  });
}
function _ckSubnets(subnets,resources,seen){
  subnets.forEach(function(s){
    var id=_ckId(s.name||gn(s,s.SubnetId),'subnet',seen);
    var prefix=s.CidrBlock||s.properties&&s.properties.addressPrefix||'10.0.0.0/24';
    resources.push({type:'Microsoft.Network/virtualNetworks/subnets',apiVersion:'2023-04-01',
      name:'placeholder-vnet/'+id,location:'[parameters(\'location\')]',
      properties:{addressPrefix:prefix,privateEndpointNetworkPolicies:'Enabled'}});
  });
}
function _ckNsgs(sgs,resources,seen){
  sgs.forEach(function(sg){
    var id=_ckId(sg.GroupName||sg.name||sg.GroupId,'nsg',seen);
    var ruleIdx=100;
    var rules=(sg.IpPermissions||sg.properties&&sg.properties.securityRules||[]).map(function(rule){
      var proto=rule.IpProtocol||rule.properties&&rule.properties.protocol||'*';
      var fromPort=rule.FromPort!=null?String(rule.FromPort):(rule.properties&&rule.properties.destinationPortRange||'*');
      var toPort=rule.ToPort!=null?String(rule.ToPort):fromPort;
      var cidrs=(rule.IpRanges||[]).map(function(r){return r.CidrIp;}).filter(Boolean);
      var r={name:'rule-'+(ruleIdx),properties:{
        priority:ruleIdx,protocol:proto==='-1'?'*':proto,access:'Allow',direction:'Inbound',
        sourceAddressPrefix:cidrs.length?cidrs[0]:'*',sourcePortRange:'*',
        destinationAddressPrefix:'*',
        destinationPortRange:fromPort===toPort?fromPort:fromPort+'-'+toPort
      }};
      ruleIdx+=10;
      return r;
    });
    resources.push({type:'Microsoft.Network/networkSecurityGroups',apiVersion:'2023-04-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(sg),
      properties:{securityRules:rules}});
  });
}
function _ckNacls(nacls,resources,seen){
  // NACLs do not exist in Azure — omit silently
}
function _ckRts(rts,resources,seen){
  rts.forEach(function(rt){
    var id=_ckId(rt.name||gn(rt,rt.RouteTableId),'udr',seen);
    var routes=(rt.Routes||rt.properties&&rt.properties.routes||[])
      .filter(function(r){return r.GatewayId!=='local';})
      .map(function(r,i){return {name:'route-'+i,properties:{
        addressPrefix:r.DestinationCidrBlock||r.properties&&r.properties.addressPrefix||'',
        nextHopType:r.NatGatewayId?'VirtualAppliance':(r.GatewayId?'Internet':'None')
      }};});
    resources.push({type:'Microsoft.Network/routeTables',apiVersion:'2023-04-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(rt),
      properties:{routes:routes,disableBgpRoutePropagation:false}});
  });
}
function _ckVms(instances,ctx,resources,seen){
  instances.forEach(function(inst){
    var id=_ckId(inst.name||gn(inst,inst.InstanceId),'vm',seen);
    var vmSize=inst.InstanceType||inst.properties&&inst.properties.hardwareProfile&&inst.properties.hardwareProfile.vmSize||'Standard_D2s_v3';
    resources.push({type:'Microsoft.Compute/virtualMachines',apiVersion:'2023-03-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(inst),
      properties:{
        hardwareProfile:{vmSize:vmSize},
        storageProfile:{
          imageReference:{publisher:'Canonical',offer:'UbuntuServer',sku:'18.04-LTS',version:'latest'},
          osDisk:{createOption:'FromImage',managedDisk:{storageAccountType:'Premium_LRS'},encryptionSettings:{enabled:true}}
        },
        osProfile:{computerName:id,adminUsername:'azureuser',linuxConfiguration:{disablePasswordAuthentication:true,ssh:{publicKeys:[]}}},
        networkProfile:{networkInterfaces:[]},
        diagnosticsProfile:{bootDiagnostics:{enabled:true}}
      }});
  });
}
function _ckRds(rdsInstances,resources,seen){
  rdsInstances.forEach(function(db){
    var id=_ckId(db.DBInstanceIdentifier||db.name,'sql',seen);
    resources.push({type:'Microsoft.Sql/servers',apiVersion:'2022-05-01-preview',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(db),
      properties:{administratorLogin:'sqladmin',
        administratorLoginPassword:'[parameters(\'adminPassword\')]',version:'12.0',
        minimalTlsVersion:'1.2',publicNetworkAccess:'Disabled'}});
    resources.push({type:'Microsoft.Sql/servers/databases',apiVersion:'2022-05-01-preview',
      name:id+'/'+(db.DBName||'maindb'),location:'[parameters(\'location\')]',
      dependsOn:['[resourceId(\'Microsoft.Sql/servers\', \''+id+'\')]'],
      sku:{name:'GP_S_Gen5',tier:'GeneralPurpose',family:'Gen5',capacity:2},
      properties:{collation:'SQL_Latin1_General_CP1_CI_AS',zoneRedundant:db.MultiAZ===true}});
  });
}
function _ckS3(buckets,resources,seen){
  buckets.forEach(function(bk){
    var id=_ckId(bk.name||bk.Name,'storage',seen).replace(/[^a-z0-9]/g,'').slice(0,24);
    resources.push({type:'Microsoft.Storage/storageAccounts',apiVersion:'2023-01-01',
      name:id||'storageaccount',location:'[parameters(\'location\')]',tags:_cfnTags(bk),
      sku:{name:'Standard_LRS'},kind:'StorageV2',
      properties:{
        supportsHttpsTrafficOnly:true,minimumTlsVersion:'TLS1_2',
        allowBlobPublicAccess:false,networkAcls:{defaultAction:'Deny'}
      }});
  });
}
function _ckAlbs(albs,resources,seen){
  albs.forEach(function(alb){
    var id=_ckId(alb.LoadBalancerName||alb.name,'lb',seen);
    resources.push({type:'Microsoft.Network/loadBalancers',apiVersion:'2023-04-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(alb),
      sku:{name:'Standard'},
      properties:{frontendIPConfigurations:[{name:'frontend',properties:{publicIPAddress:{id:'PLACEHOLDER'}}}],
        backendAddressPools:[{name:'backend'}],loadBalancingRules:[],probes:[]}});
  });
}
function _ckFuncApps(fns,resources,seen){
  fns.forEach(function(fn){
    var id=_ckId(fn.name||fn.FunctionName,'func',seen);
    resources.push({type:'Microsoft.Web/sites',apiVersion:'2022-09-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(fn),
      kind:'functionapp,linux',
      properties:{
        httpsOnly:true,
        siteConfig:{
          minTlsVersion:'1.2',
          linuxFxVersion:fn.Runtime||fn.properties&&fn.properties.siteConfig&&fn.properties.siteConfig.linuxFxVersion||'PYTHON|3.11',
          ftpsState:'Disabled'
        }
      }});
  });
}
function _ckRbac(roles,resources,seen){
  roles.forEach(function(role){
    var id=_ckId(role.RoleName||role.name,'role',seen);
    resources.push({type:'Microsoft.Authorization/roleDefinitions',apiVersion:'2022-04-01',
      name:'[guid(subscription().id, \''+id+'\')]',
      properties:{roleName:role.RoleName||role.name||id,
        description:'Custom role — review permissions',type:'CustomRole',
        permissions:[{actions:[],notActions:[],dataActions:[],notDataActions:[]}],
        assignableScopes:['[subscription().id]']}});
  });
}
function _ckRedis(clusters,resources,seen){
  clusters.forEach(function(c){
    var id=_ckId(c.name||c.CacheClusterId,'redis',seen);
    resources.push({type:'Microsoft.Cache/Redis',apiVersion:'2023-04-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(c),
      properties:{sku:{name:'Standard',family:'C',capacity:c.NumCacheNodes||1},
        enableNonSslPort:false,minimumTlsVersion:'1.2',
        redisConfiguration:{}}});
  });
}
function _ckAks(clusters,resources,seen){
  clusters.forEach(function(c){
    var id=_ckId(c.name||c.ClusterIdentifier,'aks',seen);
    resources.push({type:'Microsoft.ContainerService/managedClusters',apiVersion:'2023-05-01',
      name:id,location:'[parameters(\'location\')]',tags:_cfnTags(c),
      identity:{type:'SystemAssigned'},
      properties:{dnsPrefix:id,
        agentPoolProfiles:[{name:'nodepool1',count:c.NumberOfNodes||2,vmSize:'Standard_D2_v2',
          osType:'Linux',mode:'System'}],
        networkProfile:{networkPlugin:'azure'},
        addonProfiles:{},
        enableRBAC:true,
        disableLocalAccounts:false}});
  });
}
function generateCheckovCfn(ctx,iamData){
  if(!ctx||!ctx.vpcs) return null;
  var template={
    '$schema':'https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#',
    contentVersion:'1.0.0.0',
    description:'Generated by Azure Mapper for Checkov scanning (--framework arm) — '+new Date().toISOString().split('T')[0],
    parameters:{
      location:{type:'string',defaultValue:'eastus'},
      adminPassword:{type:'securestring',defaultValue:''}
    },
    resources:[]
  };
  var resources=template.resources,seen=new Set();
  _ckVnets(ctx.vpcs||[],resources,seen);
  _ckSubnets(ctx.subnets||[],resources,seen);
  _ckNsgs(ctx.sgs||[],resources,seen);
  _ckNacls(ctx.nacls||[],resources,seen);
  _ckRts(ctx.rts||[],resources,seen);
  _ckVms(ctx.instances||[],ctx,resources,seen);
  _ckRds(ctx.rdsInstances||[],resources,seen);
  _ckS3(ctx.s3bk||[],resources,seen);
  _ckAlbs(ctx.albs||[],resources,seen);
  _ckFuncApps(ctx.lambdaFns||[],resources,seen);
  _ckRedis(ctx.ecacheClusters||[],resources,seen);
  _ckAks(ctx.redshiftClusters||[],resources,seen);
  if(iamData){
    _ckRbac(iamData.roles||[],resources,seen);
  }
  return JSON.stringify(template,null,2);
}

// --- Simple YAML serializer for CFN ---
function _serializeCfnYaml(obj,indent){
  indent=indent||0;
  const pad='  '.repeat(indent);
  const lines=[];
  if(obj===null||obj===undefined)return 'null';
  if(typeof obj==='boolean')return obj?'true':'false';
  if(typeof obj==='number')return String(obj);
  if(typeof obj==='string'){
    if(obj.includes('\n'))return '|\n'+obj.split('\n').map(l=>pad+'  '+l).join('\n');
    if(obj.match(/[:{}\[\],&*?|>!%@`#'"]/)||obj===''||obj==='true'||obj==='false'||!isNaN(obj))return "'"+obj.replace(/'/g,"''")+"'";
    return obj;
  }
  if(Array.isArray(obj)){
    if(obj.length===0)return '[]';
    // Check if array of simple values
    if(obj.every(v=>typeof v==='string'||typeof v==='number'||typeof v==='boolean')){
      return '['+obj.map(v=>{
        if(typeof v==='string')return "'"+v.replace(/'/g,"''")+"'";
        return String(v);
      }).join(', ')+']';
    }
    obj.forEach(item=>{
      if(typeof item==='object'&&item!==null&&!Array.isArray(item)){
        const keys=Object.keys(item);
        if(keys.length){
          lines.push(pad+'- '+keys[0]+': '+_serializeCfnYaml(item[keys[0]],indent+2));
          keys.slice(1).forEach(k=>{
            lines.push(pad+'  '+k+': '+_serializeCfnYaml(item[k],indent+2));
          });
        }else{
          lines.push(pad+'- {}');
        }
      }else{
        lines.push(pad+'- '+_serializeCfnYaml(item,indent+1));
      }
    });
    return '\n'+lines.join('\n');
  }
  if(typeof obj==='object'){
    // Handle CFN intrinsic functions
    const keys=Object.keys(obj);
    if(keys.length===1&&keys[0]==='Ref')return '!Ref '+obj.Ref;
    if(keys.length===1&&keys[0]==='Fn::GetAtt')return '!GetAtt '+obj['Fn::GetAtt'].join('.');
    if(keys.length===1&&keys[0]==='Fn::Sub')return '!Sub '+_serializeCfnYaml(obj['Fn::Sub'],indent);

    if(keys.length===0)return '{}';
    keys.forEach(k=>{
      const val=obj[k];
      if(val===null||val===undefined)return;
      if(typeof val==='object'&&!Array.isArray(val)&&Object.keys(val).length>0){
        // Check for intrinsic
        const vkeys=Object.keys(val);
        if(vkeys.length===1&&vkeys[0]==='Ref'){
          lines.push(pad+k+': !Ref '+val.Ref);
        }else if(vkeys.length===1&&vkeys[0]==='Fn::GetAtt'){
          lines.push(pad+k+': !GetAtt '+val['Fn::GetAtt'].join('.'));
        }else{
          lines.push(pad+k+':');
          lines.push(_serializeCfnYaml(val,indent+1));
        }
      }else if(Array.isArray(val)){
        const ser=_serializeCfnYaml(val,indent+1);
        if(ser.startsWith('\n')){
          lines.push(pad+k+':'+ser);
        }else{
          lines.push(pad+k+': '+ser);
        }
      }else{
        lines.push(pad+k+': '+_serializeCfnYaml(val,indent+1));
      }
    });
    return lines.join('\n');
  }
  return String(obj);
}

// --- Syntax Highlighting (basic HCL) ---
function _highlightHCL(code){
  // Escape HTML first
  code=code.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  // Process line-by-line to avoid cross-match issues
  return code.split('\n').map(line=>{
    // Comments take precedence
    if(line.match(/^\s*#/))return '<span class="hcl-cmt">'+line+'</span>';
    // Strings: replace "..." with colored spans
    line=line.replace(/"([^"]*)"/g,function(_,s){return '"<span class="hcl-str">'+s+'</span>"'});
    // Keywords
    line=line.replace(/\b(resource|variable|data|module|provider|output|terraform|required_providers|import|locals|dynamic)\b/g,'<span class="hcl-kw">$1</span>');
    // Types
    line=line.replace(/\b(string|number|bool|list|map|set|object|any)\b/g,'<span class="hcl-type">$1</span>');
    // Numbers (standalone, not inside strings)
    line=line.replace(/= (\d+)$/g,'= <span class="hcl-num">$1</span>');
    // Booleans
    line=line.replace(/\b(true|false|null)\b/g,'<span class="hcl-num">$1</span>');
    // Resource refs
    line=line.replace(/(azurerm_[a-z_]+\.[a-z_0-9]+\.[a-z_]+)/g,'<span class="hcl-ref">$1</span>');
    return line;
  }).join('\n');
}

function _highlightYAML(code){
  code=code.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  return code.split('\n').map(line=>{
    if(line.match(/^\s*#/))return '<span class="hcl-cmt">'+line+'</span>';
    line=line.replace(/(\[parameters|concat|resourceId|reference|variables|subscription|resourceGroup)\b/g,'<span class="hcl-kw">$1</span>');
    line=line.replace(/(Microsoft\.[A-Za-z0-9./]+)/g,'<span class="hcl-type">$1</span>');
    line=line.replace(/'([^']*)'/g,"'<span class=\"hcl-str\">$1</span>'");
    line=line.replace(/\b(true|false|null)\b/g,'<span class="hcl-num">$1</span>');
    return line;
  }).join('\n');
}

// --- IaC Modal UI ---
function openIacModal(type){
  _iacType=type;
  const modal=document.getElementById('iacModal');
  const title=document.getElementById('iacTitle');
  title.textContent=type==='terraform'?'Export as Terraform HCL':type==='bicep'?'Export as Bicep':'Export as ARM Template';

  // Populate VNet scope dropdown
  const scopeSel=document.getElementById('iacScope');
  scopeSel.innerHTML='<option value="all">All Resources</option>';
  if(_rlCtx&&_rlCtx.vnets){
    _rlCtx.vnets.forEach(vpc=>{
      const n=(vpc.tags&&(vpc.tags.Name||vpc.tags.name))||vpc.name||vpc.id;
      const label=n||vpc.id||'VNet';
      scopeSel.innerHTML+='<option value="'+esc(vpc.id||vpc.VpcId)+'">'+esc(label)+'</option>';
    });
  }

  // Toggle TF-only options
  const modularLabel=document.getElementById('iacModular').parentElement;
  const formatSel=document.getElementById('iacFormat');
  if(type==='arm'){
    modularLabel.style.display='none';
    formatSel.innerHTML='<option value="json">JSON</option>';
  }else if(type==='bicep'){
    modularLabel.style.display='none';
    formatSel.innerHTML='<option value="bicep">Bicep</option>';
  }else{
    modularLabel.style.display='';
    formatSel.innerHTML='<option value="hcl">HCL</option><option value="json">JSON</option>';
  }

  // Reset preview
  document.getElementById('iacPreview').innerHTML='<div class="iac-empty">Click Generate to preview code</div>';

  modal.classList.add('open');
}

function closeIacModal(){
  document.getElementById('iacModal').classList.remove('open');
  _iacOutput='';
}

function generateIacPreview(){
  const ctx=_rlCtx;
  if(!ctx||!ctx.vpcs||!ctx.vpcs.length){
    document.getElementById('iacPreview').innerHTML='<div class="iac-empty">No data loaded. Render a map first.</div>';
    return;
  }
  const opts={
    mode:document.getElementById('iacMode').value,
    scopeVpcId:document.getElementById('iacScope').value==='all'?null:document.getElementById('iacScope').value,
    includeVars:document.getElementById('iacVars').checked,
    modular:document.getElementById('iacModular').checked,
    format:document.getElementById('iacFormat').value
  };

  let result;
  if(_iacType==='terraform'){
    if(opts.format==='json'){
      // Generate HCL first then wrap as note
      result=generateTerraform(ctx,opts);
      // For JSON format, produce a structured version
      result.code='// Terraform JSON format\n// Use HCL format for the best experience\n\n'+result.code;
    }else{
      result=generateTerraform(ctx,opts);
    }
  }else if(_iacType==='bicep'&&window.AppModules&&window.AppModules.IacGenerator){
    result=window.AppModules.IacGenerator.generateBicep(_rlCtx,opts);
  }else{
    result=generateArmTemplate(ctx,opts);
  }

  const preview=document.getElementById('iacPreview');
  let html='';

  // Warnings
  if(result.warnings&&result.warnings.length){
    html+='<div class="iac-warn">'+result.warnings.map(w=>'&#9888; '+w).join('<br>')+'</div>';
  }

  // Stats
  if(result.stats){
    const s=result.stats;
    const parts=[];
    if(s.vpcs)parts.push(s.vpcs+' VNets');
    if(s.subnets)parts.push(s.subnets+' Subnets');
    if(s.sgs)parts.push(s.sgs+' NSGs');
    if(s.instances)parts.push(s.instances+' VMs');
    if(s.total)parts.push(s.total+' total resources');
    if(s.resources)parts.push(s.resources+' ARM resources');
    if(parts.length)html+='<div style="padding:6px 20px;font-family:Segoe UI,system-ui,sans-serif;font-size:10px;color:var(--text-muted);border-bottom:1px solid var(--border)">'+parts.join(' | ')+'</div>';
  }

  // Highlighted code
  const highlighted=(_iacType==='terraform'||_iacType==='bicep')?_highlightHCL(result.code):
    (opts.format==='json'?_highlightHCL(result.code):_highlightYAML(result.code));
  html+='<pre>'+highlighted+'</pre>';

  preview.innerHTML=html;
}

